import React, { useState, useEffect } from 'react'
import { useParams, useNavigate, Link } from 'react-router-dom'
import { documentsApi } from '../services/api'
import { formatDate, formatTime } from '../utils/dateUtils'
import PDFViewer from '../components/PDFViewer'
import DocumentViewer from '../components/DocumentViewer'
import {
  ArrowLeft,
  FileText,
  FileSpreadsheet,
  File,
  Calendar,
  RefreshCw,
  AlertCircle,
  Eye,
  Edit3,
  Download,
  Printer,
  Loader2
} from 'lucide-react'

function DocumentDetail() {
  const { id } = useParams()
  const navigate = useNavigate()
  const [document, setDocument] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [requests, setRequests] = useState([])
  const [requestsLoading, setRequestsLoading] = useState(false)
  const [downloading, setDownloading] = useState(false)
  const [printing, setPrinting] = useState(false)

  const fetchDocument = async () => {
    try {
      setLoading(true)
      const res = await documentsApi.get(id)
      setDocument(res.data)
      setError(null)
    } catch (err) {
      console.error('Error fetching document:', err)
      setError('Failed to load document')
    } finally {
      setLoading(false)
    }
  }

  const fetchRequests = async () => {
    try {
      setRequestsLoading(true)
      const res = await documentsApi.getRequests(id)
      setRequests(res.data.requests || [])
    } catch (err) {
      console.error('Error fetching requests for document:', err)
    } finally {
      setRequestsLoading(false)
    }
  }

  useEffect(() => {
    fetchDocument()
    fetchRequests()
  }, [id])

  const handleDownload = async () => {
    try {
      setDownloading(true)
      const res = await documentsApi.download(id)
      const url = window.URL.createObjectURL(new Blob([res.data]))
      const link = window.document.createElement('a')
      link.href = url
      link.setAttribute('download', document?.filename || 'document')
      window.document.body.appendChild(link)
      link.click()
      link.remove()
      window.URL.revokeObjectURL(url)
    } catch (err) {
      console.error('Error downloading document:', err)
    } finally {
      setDownloading(false)
    }
  }

  const handlePrint = async () => {
    try {
      setPrinting(true)
      
      // Try SAS URL first (direct from storage), fallback to backend proxy
      let url
      try {
        const sasRes = await documentsApi.getSasUrl(id, 1)
        if (sasRes.data?.url) {
          url = sasRes.data.url
        }
      } catch {
        // SAS URL failed, fall back to backend proxy
      }
      
      if (!url) {
        const res = await documentsApi.getPdfBlob(id)
        const blob = new Blob([res.data], { type: 'application/pdf' })
        url = window.URL.createObjectURL(blob)
      }
      
      const printWindow = window.open(url)
      if (printWindow) {
        printWindow.addEventListener('load', () => {
          printWindow.print()
        })
      }
    } catch (err) {
      console.error('Error printing document:', err)
    } finally {
      setPrinting(false)
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64 dark:bg-gray-950">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="space-y-4">
        <button onClick={() => navigate(-1)} className="btn btn-secondary">
          <ArrowLeft className="h-4 w-4 mr-1" />
          Back
        </button>
        <div className="bg-red-50 dark:bg-red-900/30 border border-red-200 dark:border-red-800 rounded-lg p-4 flex items-center">
          <AlertCircle className="h-5 w-5 text-red-500 dark:text-red-400 mr-2" />
          <span className="text-red-700 dark:text-red-300">{error}</span>
        </div>
      </div>
    )
  }

  if (!document) {
    return null
  }

  const isPdf = document.content_type?.includes('pdf') || document.filename?.toLowerCase().endsWith('.pdf')

  const getDocIcon = (filename) => {
    if (!filename) return File
    const ext = filename.split('.').pop()?.toLowerCase()
    if (filename.endsWith('.pdf')) return FileText
    if (['xlsx', 'xls', 'csv'].includes(ext)) return FileSpreadsheet
    if (['doc', 'docx', 'txt', 'eml', 'msg'].includes(ext)) return FileText
    return File
  }

  const getFileTypeLabel = (filename) => {
    if (!filename) return 'Document'
    const ext = filename.split('.').pop()?.toLowerCase()
    const labels = {
      xlsx: 'Excel Spreadsheet', xls: 'Excel Spreadsheet',
      csv: 'CSV File', doc: 'Word Document', docx: 'Word Document',
      ppt: 'PowerPoint', pptx: 'PowerPoint',
      txt: 'Text File', eml: 'Email File', msg: 'Email File',
      json: 'JSON File', xml: 'XML File',
      png: 'Image', jpg: 'Image', jpeg: 'Image', gif: 'Image',
      pdf: 'PDF Document'
    }
    return labels[ext] || 'Document'
  }

  const DocIcon = getDocIcon(document.filename)
  const ext = document.filename?.split('.').pop()?.toLowerCase()

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center">
        <button onClick={() => navigate(-1)} className="mr-4">
          <ArrowLeft className="h-6 w-6 text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300" />
        </button>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <DocIcon className="h-5 w-5 text-gray-500 dark:text-gray-400 flex-shrink-0" />
            <h1 className="text-2xl font-bold text-gray-900 dark:text-gray-100 truncate">{document.filename}</h1>
            <span className="text-xs text-gray-400 dark:text-gray-500 flex-shrink-0">{getFileTypeLabel(document.filename)}</span>
          </div>
          <p className="text-gray-500 dark:text-gray-400">Document #{document.id}</p>
        </div>
        <div className="flex items-center gap-2 flex-shrink-0">
          {isPdf && (
            <button onClick={handlePrint} disabled={printing || downloading} className="btn btn-secondary btn-sm disabled:opacity-50 disabled:cursor-not-allowed">
              {printing ? <Loader2 className="h-4 w-4 mr-1 animate-spin" /> : <Printer className="h-4 w-4 mr-1" />}
              {printing ? 'Printing...' : 'Print'}
            </button>
          )}
          <button onClick={handleDownload} disabled={downloading || printing} className="btn btn-secondary btn-sm disabled:opacity-50 disabled:cursor-not-allowed">
            {downloading ? <Loader2 className="h-4 w-4 mr-1 animate-spin" /> : <Download className="h-4 w-4 mr-1" />}
            {downloading ? 'Downloading...' : 'Download'}
          </button>
        </div>
      </div>

      {/* Document Info Card */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <InfoCard icon={<DocIcon className="h-5 w-5 text-blue-500" />} label="Type" value={getFileTypeLabel(document.filename)} />
        <InfoCard icon={<Calendar className="h-5 w-5 text-purple-500" />} label="Uploaded" value={formatDate(document.created_at)} />
        {document.file_size_bytes && (
          <InfoCard icon={<File className="h-5 w-5 text-gray-500" />} label="Size" value={formatFileSize(document.file_size_bytes)} />
        )}
      </div>

      {/* Document Viewer */}
      <div className="card overflow-hidden">
        <div className="card-header">
          <h2 className="text-base font-semibold text-gray-900 dark:text-gray-100">
            Document Preview
          </h2>
        </div>
        <div className="h-[700px]">
          {isPdf ? (
            <PDFViewer documentId={id} highlightedField={null} onClose={null} />
          ) : (
            <DocumentViewer
              documentId={parseInt(id)}
              document={{
                id: parseInt(id),
                filename: document.filename,
                content_type: document.content_type,
                file_size_bytes: document.file_size_bytes
              }}
            />
          )}
        </div>
      </div>

      {/* Requests Table - Full Width, same as EmailDetail */}
      <div className="card overflow-hidden">
        <div className="card-header flex items-center justify-between">
          <h2 className="text-base font-semibold text-gray-900 dark:text-gray-100">
            Related Requests ({requests.length})
          </h2>
          <button onClick={fetchRequests} disabled={requestsLoading} className="btn btn-secondary btn-sm disabled:opacity-50 disabled:cursor-not-allowed">
            <RefreshCw className={`h-4 w-4 ${requestsLoading ? 'animate-spin' : ''}`} />
          </button>
        </div>
        {requestsLoading ? (
          <div className="flex items-center justify-center h-32">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
          </div>
        ) : requests.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12">
            <FileText className="h-12 w-12 text-gray-300 dark:text-gray-600 mb-3" />
            <p className="text-gray-500 dark:text-gray-400 font-medium">No requests found</p>
            <p className="text-sm text-gray-400 dark:text-gray-500 mt-1">No requests have been created from this document</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="table w-full">
              <thead>
                <tr className="border-b border-gray-100 dark:border-gray-800">
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">Instrument</th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">Issuer</th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">Processed Date</th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">Status</th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">AI Confidence</th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">Created By</th>
                  <th className="px-4 py-3"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
                {requests.map((req, index) => (
                  <InstrumentRow key={req.id} request={req} index={index} />
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  )
}

function InfoCard({ icon, label, value }) {
  return (
    <div className="card">
      <div className="card-body flex items-center gap-3">
        {icon}
        <div>
          <p className="text-xs text-gray-500 dark:text-gray-400">{label}</p>
          <p className="text-sm font-medium text-gray-900 dark:text-gray-100 truncate">{value}</p>
        </div>
      </div>
    </div>
  )
}

function InstrumentRow({ request, index }) {
  const confidence = request.ai_confidence != null ? Math.min(100, Math.max(0, request.ai_confidence)) : 0
  const createdByName = request.created_by_name || 'Unknown'
  const createdByInitials = createdByName.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || 'UN'
  const issuer = request.issuer || request.email?.sender || request.email_sender || 'Unknown Issuer'
  const documents = request.documents || []
  const documentCount = documents.length || request.document_count || 0
  const documentNames = documents.length > 0
    ? documents.map(d => d.filename || d.name || 'Unknown').join('\n')
    : (request.document_names || []).join('\n')
  const description = request.description || ''
  const maxDescLength = 50
  const truncatedDesc = description.length > maxDescLength
    ? description.substring(0, maxDescLength) + '...'
    : description

  const getStatusConfig = (status) => {
    const config = {
      pending: { bg: 'bg-yellow-50 dark:bg-yellow-900/20', text: 'text-yellow-700 dark:text-yellow-300', dot: 'bg-yellow-500', label: 'Pending' },
      processing: { bg: 'bg-blue-50 dark:bg-blue-900/20', text: 'text-blue-600 dark:text-blue-300', dot: 'bg-blue-500', label: 'Processing' },
      extracted: { bg: 'bg-indigo-50 dark:bg-indigo-900/20', text: 'text-indigo-600 dark:text-indigo-300', dot: 'bg-indigo-500', label: 'Extracted' },
      reviewing: { bg: 'bg-orange-50 dark:bg-orange-900/20', text: 'text-orange-600 dark:text-orange-300', dot: 'bg-orange-500', label: 'Reviewing' },
      rejected: { bg: 'bg-red-50 dark:bg-red-900/20', text: 'text-red-600 dark:text-red-300', dot: 'bg-red-500', label: 'Rejected' },
      failed: { bg: 'bg-red-50 dark:bg-red-900/20', text: 'text-red-600 dark:text-red-300', dot: 'bg-red-500', label: 'Failed' },
      completed: { bg: 'bg-green-50 dark:bg-green-900/20', text: 'text-green-600 dark:text-green-300', dot: 'bg-green-500', label: 'Completed' },
      cancelled: { bg: 'bg-gray-50 dark:bg-gray-700', text: 'text-gray-600 dark:text-gray-300', dot: 'bg-gray-500', label: 'Cancelled' },
    }
    return config[status] || config.pending
  }

  const statusConfig = getStatusConfig(request.status)
  const confidenceColor = confidence >= 90 ? 'bg-green-500' : confidence >= 70 ? 'bg-yellow-500' : 'bg-red-500'

  const getIconColor = (status) => {
    const colors = {
      pending: 'text-yellow-600 bg-yellow-50 dark:text-yellow-400 dark:bg-yellow-900/20',
      processing: 'text-blue-600 bg-blue-50 dark:text-blue-400 dark:bg-blue-900/20',
      extracted: 'text-indigo-600 bg-indigo-50 dark:text-indigo-400 dark:bg-indigo-900/20',
      reviewing: 'text-orange-600 bg-orange-50 dark:text-orange-400 dark:bg-orange-900/20',
      rejected: 'text-red-600 bg-red-50 dark:text-red-400 dark:bg-red-900/20',
      failed: 'text-red-600 bg-red-50 dark:text-red-400 dark:bg-red-900/20',
      completed: 'text-green-600 bg-green-50 dark:text-green-400 dark:bg-green-900/20',
      cancelled: 'text-gray-600 bg-gray-50 dark:text-gray-400 dark:bg-gray-700',
    }
    return colors[status] || 'text-gray-600 bg-gray-50 dark:text-gray-400 dark:bg-gray-700'
  }

  return (
    <tr className="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors">
      <td className="px-4 py-3">
        <div className="flex items-center gap-3">
          <div
            className={`w-10 h-10 rounded-lg flex items-center justify-center relative cursor-default ${getIconColor(request.status)}`}
            title={documentCount > 0 ? documentNames : 'No documents'}
          >
            <FileText className="h-5 w-5" />
            <span className="absolute -top-1 -right-1 bg-navy-600 text-white text-[10px] font-medium rounded-full min-w-[18px] h-[18px] flex items-center justify-center px-1">
              {documentCount}
            </span>
          </div>
          <div className="max-w-xs">
            <Link to={`/requests/${request.id}`} className="font-medium text-gray-900 dark:text-gray-100 hover:text-navy-600 dark:hover:text-navy-400">
              {request.title || request.email_subject || `Request #${String(request.id).substring(0, 8)}`}
            </Link>
            {description && (
              <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5" title={description.length > maxDescLength ? description : undefined}>
                {truncatedDesc || 'No description'}
              </p>
            )}
          </div>
        </div>
      </td>
      <td className="px-4 py-3">
        <span className="text-sm text-gray-600 dark:text-gray-400">{issuer}</span>
      </td>
      <td className="px-4 py-3">
        <div>
          <p className="text-sm text-gray-900 dark:text-gray-100">{formatDate(request.created_at)}</p>
          <p className="text-xs text-gray-500 dark:text-gray-400">{formatTime(request.created_at)}</p>
        </div>
      </td>
      <td className="px-4 py-3">
        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${statusConfig.bg} ${statusConfig.text}`}>
          <span className={`w-1.5 h-1.5 rounded-full ${statusConfig.dot}`}></span>
          {statusConfig.label}
        </span>
      </td>
      <td className="px-4 py-3">
        <div className="flex items-center gap-2">
          <div className="w-16 h-1.5 bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden">
            <div className={`h-full rounded-full ${confidenceColor}`} style={{ width: `${confidence}%` }} />
          </div>
          <span className="text-sm text-gray-600 dark:text-gray-400">{confidence}%</span>
        </div>
      </td>
      <td className="px-4 py-3">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-gray-200 dark:bg-gray-700 flex items-center justify-center text-xs font-medium text-gray-600 dark:text-gray-300">
            {createdByInitials}
          </div>
          <span className="text-sm text-gray-600 dark:text-gray-400">{createdByName}</span>
        </div>
      </td>
      <td className="px-4 py-3">
        <div className="flex items-center gap-1">
          {request.status === 'completed' || request.status === 'cancelled' ? (
            <Link
              to={`/requests/${request.id}?mode=view`}
              className="p-1.5 rounded-lg text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
              title="View request"
            >
              <Eye className="h-4 w-4" />
            </Link>
          ) : (
            <Link
              to={`/requests/${request.id}?mode=edit`}
              className="p-1.5 rounded-lg text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
              title="Edit request"
            >
              <Edit3 className="h-4 w-4" />
            </Link>
          )}
        </div>
      </td>
    </tr>
  )
}

function StatusBadge({ status, displayName }) {
  return (
    <span className={`status-badge status-${status}`}>
      {displayName || status?.replace(/_/g, ' ')}
    </span>
  )
}

function formatFileSize(bytes) {
  if (!bytes) return '0 B'
  const k = 1024
  const sizes = ['B', 'KB', 'MB', 'GB']
  const i = Math.floor(Math.log(bytes) / Math.log(k))
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i]
}

export default DocumentDetail
