import React, { useState, useEffect, useCallback } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { dashboardApi } from '../services/api'
import { formatDate } from '../utils/dateUtils'
import {
  Search,
  ChevronLeft,
  ChevronRight,
  Building2,
  ArrowLeft,
  RefreshCw,
} from 'lucide-react'

// formatDate imported from ../utils/dateUtils

const rankColors = {
  1: 'bg-navy-800 text-white',
  2: 'bg-gray-200 text-gray-700 dark:bg-gray-600 dark:text-gray-200',
  3: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300',
}

export default function Issuers() {
  const navigate = useNavigate()
  const [items, setItems] = useState([])
  const [loading, setLoading] = useState(true)
  const [page, setPage] = useState(1)
  const [totalPages, setTotalPages] = useState(1)
  const [total, setTotal] = useState(0)
  const [search, setSearch] = useState('')
  const [searchInput, setSearchInput] = useState('')
  const [perPage, setPerPage] = useState(10)

  const fetchIssuers = useCallback(async () => {
    setLoading(true)
    try {
      const params = { page, page_size: perPage }
      if (search) params.search = search
      const res = await dashboardApi.getIssuersPaginated(params)
      const data = res.data
      setItems(data.items || [])
      setTotal(data.total || 0)
      setTotalPages(data.total_pages || 1)
    } catch (err) {
      console.error('Failed to load issuers:', err)
      setItems([])
    } finally {
      setLoading(false)
    }
  }, [page, search, perPage])

  useEffect(() => {
    fetchIssuers()
  }, [fetchIssuers])

  const handleSearch = (e) => {
    e.preventDefault()
    setPage(1)
    setSearch(searchInput)
  }

  const handleClearSearch = () => {
    setSearchInput('')
    setSearch('')
    setPage(1)
  }

  const getPageNumbers = () => {
    const pages = []
    const maxVisible = 7
    if (totalPages <= maxVisible) {
      for (let i = 1; i <= totalPages; i++) pages.push(i)
    } else {
      pages.push(1)
      if (page > 3) pages.push('...')
      const start = Math.max(2, page - 1)
      const end = Math.min(totalPages - 1, page + 1)
      for (let i = start; i <= end; i++) pages.push(i)
      if (page < totalPages - 2) pages.push('...')
      pages.push(totalPages)
    }
    return pages
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Link to="/" className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg text-gray-500 hover:text-gray-700 dark:hover:text-gray-300 transition-colors">
            <ArrowLeft className="h-5 w-5" />
          </Link>
          <div>
            <h1 className="text-2xl font-bold text-gray-900 dark:text-gray-100">Issuers</h1>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">{total} total issuers</p>
          </div>
        </div>
        <button
          onClick={fetchIssuers}
          disabled={loading}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
          Refresh
        </button>
      </div>

      {/* Search Bar */}
      <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 p-4">
        <form onSubmit={handleSearch} className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
          <input
            type="text"
            placeholder="Search issuers..."
            value={searchInput}
            onChange={(e) => setSearchInput(e.target.value)}
            className="w-full pl-10 pr-4 py-2 text-sm border border-gray-300 dark:border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-navy-500 focus:border-navy-500 dark:bg-gray-800 dark:text-gray-200"
          />
          {search && (
            <button
              type="button"
              onClick={handleClearSearch}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
            >
              ×
            </button>
          )}
        </form>

        {search && (
          <div className="flex items-center gap-2 mt-3 pt-3 border-t border-gray-100 dark:border-gray-800">
            <span className="text-xs text-gray-500 dark:text-gray-400">Filters:</span>
            <span className="inline-flex items-center gap-1 px-2 py-0.5 text-xs font-medium bg-navy-50 text-navy-700 dark:bg-navy-900/30 dark:text-navy-300 rounded-full">
              Search: "{search}"
              <button onClick={handleClearSearch} className="hover:text-navy-900 dark:hover:text-navy-200">×</button>
            </span>
          </div>
        )}
      </div>

      {/* Issuers List */}
      <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden">
        {loading ? (
          <div className="divide-y divide-gray-100 dark:divide-gray-800">
            {[...Array(6)].map((_, i) => (
              <div key={i} className="px-5 py-4 flex items-center gap-4 animate-pulse">
                <div className="w-9 h-9 bg-gray-200 dark:bg-gray-700 rounded-lg"></div>
                <div className="flex-1 min-w-0">
                  <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-40 mb-1"></div>
                  <div className="h-3 bg-gray-100 dark:bg-gray-800 rounded w-20"></div>
                </div>
                <div className="hidden sm:block w-20">
                  <div className="h-3 bg-gray-100 dark:bg-gray-800 rounded w-16 mb-1"></div>
                  <div className="h-3 bg-gray-200 dark:bg-gray-700 rounded w-20"></div>
                </div>
                <div className="hidden sm:block w-20">
                  <div className="h-3 bg-gray-100 dark:bg-gray-800 rounded w-16 mb-1"></div>
                  <div className="h-3 bg-gray-200 dark:bg-gray-700 rounded w-20"></div>
                </div>
                <div className="flex items-center gap-2 w-24">
                  <div className="flex-1 h-2 bg-gray-200 dark:bg-gray-700 rounded-full"></div>
                  <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-8"></div>
                </div>
              </div>
            ))}
          </div>
        ) : items.length === 0 ? (
          <div className="py-16 text-center">
            <Building2 className="h-10 w-10 text-gray-300 dark:text-gray-600 mx-auto mb-3" />
            <p className="text-sm text-gray-500 dark:text-gray-400">No issuers found</p>
            {search && (
              <p className="text-xs text-gray-400 dark:text-gray-500 mt-1">Try adjusting your search</p>
            )}
          </div>
        ) : (
          <div className="divide-y divide-gray-100 dark:divide-gray-800">
            {items.map((item, idx) => {
              const globalRank = (page - 1) * pageSize + idx + 1
              const badgeClass = rankColors[globalRank] || 'bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-300'

              return (
                <div
                  key={item.name}
                  onClick={() => navigate(`/requests?search=${encodeURIComponent(item.name)}`)}
                  className="px-5 py-4 flex items-center gap-4 hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors cursor-pointer clickable-row"
                  title={`View requests from ${item.name}`}
                >
                  {/* Rank */}
                  <div className={`w-9 h-9 rounded-lg flex items-center justify-center text-sm font-semibold flex-shrink-0 ${badgeClass}`}>
                    {globalRank}
                  </div>

                  {/* Name + requests */}
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-900 dark:text-gray-100 truncate">{item.name}</p>
                    <p className="text-xs text-gray-500 dark:text-gray-400">{item.request_count} request{item.request_count !== 1 ? 's' : ''}</p>
                  </div>

                  {/* Date range */}
                  <div className="hidden sm:block text-right flex-shrink-0">
                    <p className="text-xs text-gray-400 dark:text-gray-500">First seen</p>
                    <p className="text-xs text-gray-600 dark:text-gray-400">{formatDate(item.first_seen)}</p>
                  </div>
                  <div className="hidden sm:block text-right flex-shrink-0">
                    <p className="text-xs text-gray-400 dark:text-gray-500">Last seen</p>
                    <p className="text-xs text-gray-600 dark:text-gray-400">{formatDate(item.last_seen)}</p>
                  </div>

                  {/* Percentage */}
                  <div className="flex items-center gap-2 flex-shrink-0 w-24">
                    <div className="flex-1 h-2 bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden">
                      <div
                        className="h-full bg-navy-500 rounded-full transition-all"
                        style={{ width: `${Math.min(item.percentage, 100)}%` }}
                      />
                    </div>
                    <span className="text-sm font-medium text-gray-600 dark:text-gray-400 w-10 text-right">{item.percentage}%</span>
                  </div>
                </div>
              )
            })}
          </div>
        )}

        {/* Pagination */}
        <div className="px-5 py-4 border-t border-gray-100 dark:border-gray-800 flex items-center justify-between">
          <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400">
            <span>
              {total === 0
                ? 'No results'
                : `Showing ${(page - 1) * perPage + 1}\u2013${Math.min(page * perPage, total)} of ${total} result${total !== 1 ? 's' : ''}`}
            </span>
            <span className="border-l border-gray-200 dark:border-gray-700 h-4" />
            <span className="flex items-center gap-1.5">
              Rows per page
              <select
                value={perPage}
                onChange={(e) => {
                  setPerPage(Number(e.target.value))
                  setPage(1)
                }}
                className="px-2 py-1 border border-gray-200 dark:border-gray-700 rounded text-sm dark:bg-gray-800 dark:text-gray-200"
              >
                <option value={10}>10</option>
                <option value={25}>25</option>
                <option value={50}>50</option>
              </select>
            </span>
          </div>
          {totalPages > 1 && (
            <div className="flex items-center gap-1">
              <button
                onClick={() => setPage(p => Math.max(1, p - 1))}
                disabled={page === 1}
                className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <ChevronLeft className="h-4 w-4" />
                Previous
              </button>
              {getPageNumbers().map((p, i) => (
                <React.Fragment key={i}>
                  {p === '...' ? (
                    <span className="px-2 text-gray-400 dark:text-gray-500">...</span>
                  ) : (
                    <button
                      onClick={() => setPage(p)}
                      className={`w-8 h-8 rounded text-sm font-medium ${
                        p === page
                          ? 'bg-navy-800 text-white'
                          : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800'
                      }`}
                    >
                      {p}
                    </button>
                  )}
                </React.Fragment>
              ))}
              <button
                onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                disabled={page === totalPages}
                className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Next
                <ChevronRight className="h-4 w-4" />
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}
