import React, { useState, useEffect, useRef } from 'react'
import { Outlet, Link, useLocation, useParams } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import { useTheme } from '../context/ThemeContext'
import { useBranding } from '../context/BrandingContext'
import defaultLogoImage from '../assets/CompanyLogoSynapx.png'
import {
  LayoutDashboard,
  FileText,
  Mail,
  Files,
  Clock,
  LogOut,
  Menu,
  X,
  User,
  ChevronDown,
  ChevronRight,
  Sun,
  Moon,
  Activity,
  Building2,
  FileStack,
  Crown,
  Sparkles,
  AlertTriangle,
  ExternalLink,
  FlaskConical,
  Settings
} from 'lucide-react'

const navigation = [
  { name: 'Dashboard', href: '/', icon: LayoutDashboard },
  { name: 'Email Queue', href: '/emails', icon: Mail },
  { name: 'Requests', href: '/requests', icon: FileText },
  { name: 'Issuers', href: '/issuers', icon: Building2 },
  { name: 'Templates', href: '/templates', icon: FileStack },
  { name: 'Documents', href: '/documents', icon: Files },
  { name: 'Jobs', href: '/jobs', icon: Clock },
  { name: 'Analyze & Test', href: '/test-analysis', icon: FlaskConical },
  { name: 'Settings', href: '/settings', icon: Settings },
]

// Helper: format plan name for display
function getPlanDisplay(plan) {
  const plans = {
    free_trial: { label: 'Free Trial', color: 'bg-amber-500/20 text-amber-300', icon: Sparkles },
    enterprise: { label: 'Enterprise', color: 'bg-emerald-500/20 text-emerald-300', icon: Crown },
  }
  return plans[plan] || plans.free_trial
}

// Subscription badge for sidebar
function SubscriptionBadge({ subscription }) {
  const plan = getPlanDisplay(subscription?.plan)
  const Icon = plan.icon
  return (
    <div className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-xs font-medium ${plan.color}`}>
      <Icon className="h-3 w-3" />
      {plan.label}
    </div>
  )
}

// Helper: build breadcrumbs from pathname
function getBreadcrumbs(pathname) {
  if (pathname === '/') return [{ label: 'Dashboard', href: '/' }]
  const segments = pathname.split('/').filter(Boolean)
  const crumbs = [{ label: 'Dashboard', href: '/' }]
  const nameMap = {
    requests: 'Requests',
    emails: 'Email Queue',
    documents: 'Documents',
    jobs: 'Jobs',
    issuers: 'Issuers',
    templates: 'Templates',
    activity: 'Activity',
    'test-analysis': 'Analyze & Test',
    settings: 'Settings',
  }
  if (segments[0]) {
    crumbs.push({ label: nameMap[segments[0]] || segments[0], href: `/${segments[0]}` })
  }
  // Detail page: show ID shortened
  if (segments[1]) {
    const id = segments[1]
    const shortId = id.length > 8 ? `#${id.substring(0, 8)}…` : `#${id}`
    crumbs.push({ label: shortId, href: pathname })
  }
  return crumbs
}

function Layout() {
  const { user, logout, subscription, organizationName } = useAuth()
  const { isDark, toggleTheme } = useTheme()
  const { branding } = useBranding()
  const location = useLocation()
  const logoImage = branding.logo_url || defaultLogoImage
  const appName = branding.app_name || 'Xtract'
  const appSubtitle = branding.subtitle || 'Synapx AI'
  const [sidebarOpen, setSidebarOpen] = useState(false)
  const [userMenuOpen, setUserMenuOpen] = useState(false)
  const userMenuRef = useRef(null)

  // Close user dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (userMenuRef.current && !userMenuRef.current.contains(e.target)) {
        setUserMenuOpen(false)
      }
    }
    if (userMenuOpen) {
      document.addEventListener('mousedown', handleClickOutside)
    }
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [userMenuOpen])

  const breadcrumbs = getBreadcrumbs(location.pathname)
  const isDetailPage = location.pathname.split('/').filter(Boolean).length > 1
  
  const isActive = (path) => {
    if (path === '/') {
      return location.pathname === '/'
    }
    return location.pathname.startsWith(path)
  }
  
  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-950">
      {/* Mobile sidebar overlay */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 z-40 bg-gray-900/50 dark:bg-black/60 lg:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}
      
      {/* Mobile sidebar */}
      <div
        className={`fixed inset-y-0 left-0 z-50 w-64 transform transition-transform lg:hidden ${
          sidebarOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
        style={{ backgroundColor: 'var(--brand-primary)' }}
      >
        <div className="flex items-center justify-between h-16 px-4 border-b border-white/10">
          <div className="flex items-center gap-2">
            <img src={logoImage} alt={appName} className="w-8 h-8 rounded-lg object-contain" />
            <span className="text-lg font-semibold text-white">{appName}</span>
          </div>
          <button
            onClick={() => setSidebarOpen(false)}
            className="p-2 rounded-md text-white/60 hover:text-white"
          >
            <X className="h-5 w-5" />
          </button>
        </div>
        <nav className="mt-4 px-3">
          {navigation.map((item) => (
            <Link
              key={item.name}
              to={item.href}
              onClick={() => setSidebarOpen(false)}
              className={`relative flex items-center px-3 py-2.5 mb-1 rounded-lg text-sm font-medium transition-colors ${
                isActive(item.href)
                  ? 'bg-white/10 text-white'
                  : 'text-white/60 hover:bg-white/5 hover:text-white'
              }`}
            >
              {isActive(item.href) && <span className="nav-active-indicator" />}
              <item.icon className="h-5 w-5 mr-3" />
              {item.name}
            </Link>
          ))}
        </nav>
      </div>
      
      {/* Desktop sidebar */}
      <div className="hidden lg:fixed lg:inset-y-0 lg:flex lg:w-64 lg:flex-col">
        <div className="flex flex-col flex-grow" style={{ backgroundColor: 'var(--brand-primary)' }}>
          {/* Logo */}
          <div className="flex items-center h-16 px-4 border-b border-white/10">
            <div className="flex items-center gap-2">
              <img src={logoImage} alt={appName} className="w-8 h-8 rounded-lg object-contain" />
              <div>
                <span className="text-lg font-semibold text-white">{appName}</span>
                <p className="text-xs text-white/50">{appSubtitle}</p>
              </div>
            </div>
          </div>
          
          {/* Navigation */}
          <nav className="flex-1 mt-4 px-3">
            {navigation.map((item) => (
              <Link
                key={item.name}
                to={item.href}
                className={`relative flex items-center px-3 py-2.5 mb-1 rounded-lg text-sm font-medium transition-colors ${
                  isActive(item.href)
                    ? 'bg-white/10 text-white'
                    : 'text-white/60 hover:bg-white/5 hover:text-white'
                }`}
              >
                {isActive(item.href) && <span className="nav-active-indicator" />}
                <item.icon className="h-5 w-5 mr-3" />
                {item.name}
              </Link>
            ))}
          </nav>
          
          {/* Sidebar footer */}
          <div className="p-4 border-t border-white/10">
            <SubscriptionBadge subscription={subscription} />
            <div className="flex items-center gap-3 mt-3">
              <div className="w-8 h-8 bg-white/10 rounded-full flex items-center justify-center">
                <User className="h-4 w-4 text-white/80" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-white truncate">
                  {user?.name || 'User'}
                </p>
                <p className="text-xs text-white/50 truncate">
                  {organizationName || user?.email}
                </p>
              </div>
            </div>
            <a
              href="/privacy"
              target="_blank"
              rel="noopener noreferrer"
              className="block mt-3 text-xs text-white/30 hover:text-white/50 transition-colors"
            >
              Privacy Policy
            </a>
          </div>
        </div>
      </div>
      
      {/* Main content */}
      <div className="lg:pl-64">
        {/* Top header */}
        <header className="sticky top-0 z-30 flex items-center justify-between h-16 px-6 bg-white dark:bg-gray-900 border-b border-gray-100 dark:border-gray-800">
          <div className="flex items-center gap-3">
            <button
              onClick={() => setSidebarOpen(true)}
              className="p-2 rounded-lg text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 lg:hidden"
              aria-label="Open sidebar menu"
            >
              <Menu className="h-5 w-5" />
            </button>

            {/* Breadcrumbs */}
            {isDetailPage && (
              <nav className="hidden lg:flex items-center text-sm" aria-label="Breadcrumb">
                {breadcrumbs.map((crumb, i) => (
                  <React.Fragment key={crumb.href}>
                    {i > 0 && <ChevronRight className="h-3.5 w-3.5 breadcrumb-separator" />}
                    {i === breadcrumbs.length - 1 ? (
                      <span className="text-gray-500 dark:text-gray-400 font-medium">{crumb.label}</span>
                    ) : (
                      <Link to={crumb.href} className="text-gray-400 dark:text-gray-500 hover:text-gray-700 dark:hover:text-gray-300 transition-colors">
                        {crumb.label}
                      </Link>
                    )}
                  </React.Fragment>
                ))}
              </nav>
            )}
          </div>
          
          <div className="flex items-center gap-4">
            {/* Subscription badge */}
            {(() => {
              const plan = getPlanDisplay(subscription?.plan)
              const Icon = plan.icon
              return (
                <div className={`hidden md:flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg text-xs font-medium ${
                  subscription?.plan === 'enterprise'
                    ? 'bg-emerald-50 text-emerald-700 dark:bg-emerald-500/10 dark:text-emerald-400'
                    : 'bg-amber-50 text-amber-700 dark:bg-amber-500/10 dark:text-amber-400'
                }`}>
                  <Icon className="h-3.5 w-3.5" />
                  {plan.label}
                </div>
              )
            })()}

            {/* Theme toggle */}
            <button
              onClick={toggleTheme}
              className="p-2 rounded-lg text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
              title={isDark ? 'Switch to light mode' : 'Switch to dark mode'}
              aria-label={isDark ? 'Switch to light mode' : 'Switch to dark mode'}
            >
              {isDark ? <Sun className="h-5 w-5" /> : <Moon className="h-5 w-5" />}
            </button>
            
            {/* User menu */}
            <div className="relative" ref={userMenuRef}>
              <button
                onClick={() => setUserMenuOpen(!userMenuOpen)}
                className="flex items-center gap-2 text-sm font-medium text-gray-700 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white p-1.5 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                aria-label="User menu"
                aria-expanded={userMenuOpen}
              >
                <div className="flex items-center justify-center w-8 h-8 rounded-full bg-navy-100 dark:bg-navy-700">
                  <User className="h-4 w-4 text-navy-600 dark:text-navy-200" />
                </div>
                <span className="hidden md:block max-w-32 truncate">{user?.name || user?.email}</span>
                <ChevronDown className="h-4 w-4 text-gray-400 dark:text-gray-500" />
              </button>
              
              {userMenuOpen && (
                <div className="absolute right-0 mt-2 w-56 bg-white dark:bg-gray-800 rounded-xl shadow-lg border border-gray-100 dark:border-gray-700 py-1 z-50">
                  <div className="px-4 py-3 border-b border-gray-100 dark:border-gray-700">
                    <p className="text-sm font-medium text-gray-900 dark:text-gray-100">{user?.name}</p>
                    <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{user?.email}</p>
                  </div>
                  <button
                    onClick={() => {
                      setUserMenuOpen(false)
                      logout()
                    }}
                    className="flex items-center w-full px-4 py-2.5 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                  >
                    <LogOut className="h-4 w-4 mr-2 text-gray-400 dark:text-gray-500" />
                    Sign out
                  </button>
                </div>
              )}
            </div>
          </div>
        </header>
        
        {/* Free trial banner */}
        {subscription?.plan === 'free_trial' && (
          <div className="bg-amber-50 dark:bg-amber-900/20 border-b border-amber-200 dark:border-amber-800 px-6 py-2.5 flex items-center justify-between">
            <div className="flex items-center gap-2 text-sm text-amber-800 dark:text-amber-200">
              <AlertTriangle className="h-4 w-4 flex-shrink-0" />
              <span>You're on the <strong>Free Trial</strong> plan. Upgrade to Enterprise for unlimited access.</span>
            </div>
            <a
              href="https://azuremarketplace.microsoft.com"
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1 text-xs font-medium text-amber-700 dark:text-amber-300 hover:text-amber-900 dark:hover:text-amber-100 whitespace-nowrap"
            >
              Upgrade <ExternalLink className="h-3 w-3" />
            </a>
          </div>
        )}

        {/* Page content */}
        <main className="p-6">
          <Outlet />
        </main>
      </div>
      
    </div>
  )
}

export default Layout
