import React, { useState, useEffect, useMemo } from 'react'
import { emailsApi, templatesApi } from '../services/api'
import { X, Upload, Mail, AlertCircle, RefreshCw, Plus, Trash2, ChevronDown, ChevronRight, FileText } from 'lucide-react'

const HIDE_TEMPLATE_SELECTOR = import.meta.env.VITE_HIDE_TEMPLATE_SELECTOR === 'true'

function IngestEmailModal({ onClose, onSuccess }) {
  const [formData, setFormData] = useState({
    subject: '',
    sender: '',
    recipients: '',
    body: '',
    received_at: '',
    message_id: '',
    template_id: '', // Changed from request_type to template_id
    auto_analyze: true,
  })
  const [attachments, setAttachments] = useState([])
  const [templates, setTemplates] = useState([]) // Templates with analyzers
  const [loadingTemplates, setLoadingTemplates] = useState(true)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)
  const [showTemplateFields, setShowTemplateFields] = useState(false)
  const [isDragOver, setIsDragOver] = useState(false)
  
  // Get the selected template with full field information
  const selectedTemplate = useMemo(() => {
    return templates.find(t => t.id === formData.template_id) || null
  }, [templates, formData.template_id])
  
  // Fetch templates with analyzers on mount
  useEffect(() => {
    const fetchTemplates = async () => {
      try {
        setLoadingTemplates(true)
        const response = await templatesApi.list({ has_analyzer: true, include_fields: true })
        const data = response.data || response
        setTemplates(data.templates || [])
        // Set first template as default if available
        if (data.templates && data.templates.length > 0) {
          setFormData(prev => ({ ...prev, template_id: data.templates[0].id }))
        }
      } catch (err) {
        console.error('Error fetching templates:', err)
      } finally {
        setLoadingTemplates(false)
      }
    }
    fetchTemplates()
  }, [])
  
  // Close on Escape key
  useEffect(() => {
    const handleEsc = (e) => {
      if (e.key === 'Escape' && !loading) onClose()
    }
    window.addEventListener('keydown', handleEsc)
    return () => window.removeEventListener('keydown', handleEsc)
  }, [onClose, loading])
  
  const handleChange = (e) => {
    const { name, value, type, checked } = e.target
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }))
  }
  
  const handleFileChange = async (e) => {
    const files = Array.from(e.target.files || [])
    const rejected = []
    
    for (const file of files) {
      if (!file.name.toLowerCase().endsWith('.pdf')) {
        rejected.push(file.name)
        continue
      }
      const reader = new FileReader()
      reader.onload = () => {
        const base64 = reader.result?.split(',')[1] || ''
        setAttachments(prev => [...prev, {
          filename: file.name,
          content_type: file.type,
          content_base64: base64,
          size: file.size
        }])
      }
      reader.readAsDataURL(file)
    }
    
    if (rejected.length > 0) {
      setError(`Only PDF files are allowed. Rejected: ${rejected.join(', ')}`)
    }
    
    e.target.value = ''
  }
  
  const removeAttachment = (index) => {
    setAttachments(prev => prev.filter((_, i) => i !== index))
  }
  
  const handleDrop = (e) => {
    e.preventDefault()
    setIsDragOver(false)
    const files = Array.from(e.dataTransfer.files || [])
    processFiles(files)
  }
  
  const processFiles = (files) => {
    for (const file of files) {
      if (!file.name.toLowerCase().endsWith('.pdf')) continue
      const reader = new FileReader()
      reader.onload = () => {
        const base64 = reader.result?.split(',')[1] || ''
        setAttachments(prev => [...prev, {
          filename: file.name,
          content_type: file.type,
          content_base64: base64,
          size: file.size
        }])
      }
      reader.readAsDataURL(file)
    }
  }
  
  const handleSubmit = async (e) => {
    e.preventDefault()
    setError(null)
    
    if (!formData.subject || !formData.sender) {
      setError('Subject and sender are required')
      return
    }
    
    try {
      setLoading(true)
      
      const payload = {
        ...formData,
        recipients: formData.recipients || '',
        attachments,
      }
      
      await emailsApi.ingest(payload)
      onSuccess()
    } catch (err) {
      console.error('Error ingesting email:', err)
      setError(err.response?.data?.error || 'Failed to ingest email')
    } finally {
      setLoading(false)
    }
  }
  
  return (
    <div className="fixed inset-0 z-50 overflow-y-auto">
      <div className="flex items-center justify-center min-h-screen px-4">
        {/* Backdrop */}
        <div
          className="fixed inset-0 bg-gray-600 bg-opacity-75"
          onClick={() => { if (!loading) onClose(); }}
        />
        
        {/* Modal */}
        <div className="relative bg-white dark:bg-gray-900 rounded-lg shadow-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
          {/* Header */}
          <div className="flex items-center justify-between px-6 py-4 border-b dark:border-gray-700">
            <div className="flex items-center">
              <Mail className="h-5 w-5 text-primary-600 mr-2" />
              <h2 className="text-lg font-semibold text-gray-900 dark:text-gray-100">Ingest Email</h2>
            </div>
            <button
              onClick={onClose}
              disabled={loading}
              className={`text-gray-400 hover:text-gray-500 dark:hover:text-gray-300 ${loading ? 'opacity-50 cursor-not-allowed' : ''}`}
              aria-label="Close modal"
            >
              <X className="h-6 w-6" />
            </button>
          </div>
          
          {/* Body */}
          <form onSubmit={handleSubmit}>
            <div className="px-6 py-4 space-y-4">
              {error && (
                <div className="bg-red-50 dark:bg-red-900/30 border border-red-200 dark:border-red-800 rounded-lg p-3 flex items-center">
                  <AlertCircle className="h-5 w-5 text-red-500 dark:text-red-400 mr-2 flex-shrink-0" />
                  <span className="text-red-700 dark:text-red-300 text-sm">{error}</span>
                </div>
              )}
              
              {/* Subject */}
              <div>
                <label className="form-label">Subject *</label>
                <input
                  type="text"
                  name="subject"
                  value={formData.subject}
                  onChange={handleChange}
                  className="form-input"
                  placeholder="Email subject"
                  required
                />
              </div>
              
              {/* Sender */}
              <div>
                <label className="form-label">Sender *</label>
                <input
                  type="email"
                  name="sender"
                  value={formData.sender}
                  onChange={handleChange}
                  className="form-input"
                  placeholder="sender@example.com"
                  required
                />
              </div>
              
              {/* Recipients */}
              <div>
                <label className="form-label">Recipients</label>
                <input
                  type="text"
                  name="recipients"
                  value={formData.recipients}
                  onChange={handleChange}
                  className="form-input"
                  placeholder="recipient1@example.com, recipient2@example.com"
                />
                <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">Comma-separated email addresses</p>
              </div>
              
              {/* Body */}
              <div>
                <label className="form-label">Body</label>
                <textarea
                  name="body"
                  value={formData.body}
                  onChange={handleChange}
                  className="form-input"
                  rows={4}
                  placeholder="Email body content..."
                />
              </div>
              
              <div className={`grid ${HIDE_TEMPLATE_SELECTOR ? 'grid-cols-1' : 'grid-cols-2'} gap-4`}>
                {/* Template Selection - hidden when VITE_HIDE_TEMPLATE_SELECTOR=true */}
                {!HIDE_TEMPLATE_SELECTOR && (
                <div>
                  <label className="form-label">Template</label>
                  <select
                    name="template_id"
                    value={formData.template_id}
                    onChange={handleChange}
                    className="form-select"
                    disabled={loadingTemplates}
                  >
                    {loadingTemplates ? (
                      <option value="">Loading templates...</option>
                    ) : templates.length === 0 ? (
                      <option value="">No templates available</option>
                    ) : (
                      templates.map(template => (
                        <option key={template.id} value={template.id}>
                          {template.name}
                        </option>
                      ))
                    )}
                  </select>
                  {selectedTemplate && (
                    <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
                      {selectedTemplate.description}
                    </p>
                  )}
                </div>
                )}
                
                {/* Received At */}
                <div>
                  <label className="form-label">Received At</label>
                  <input
                    type="datetime-local"
                    name="received_at"
                    value={formData.received_at}
                    onChange={handleChange}
                    className="form-input"
                  />
                </div>
              </div>
              
              {/* Template Fields Preview - hidden when template selector is hidden */}
              {!HIDE_TEMPLATE_SELECTOR && selectedTemplate && selectedTemplate.fields && selectedTemplate.fields.length > 0 && (
                <div className="border border-gray-200 dark:border-gray-700 rounded-lg overflow-hidden">
                  <button
                    type="button"
                    onClick={() => setShowTemplateFields(!showTemplateFields)}
                    className="w-full flex items-center justify-between px-4 py-3 bg-gray-50 dark:bg-gray-800 hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                  >
                    <div className="flex items-center">
                      <FileText className="h-4 w-4 text-primary-600 mr-2" />
                      <span className="text-sm font-medium text-gray-700 dark:text-gray-300">
                        Fields to Extract ({selectedTemplate.field_count || selectedTemplate.fields.length})
                      </span>
                    </div>
                    {showTemplateFields ? (
                      <ChevronDown className="h-4 w-4 text-gray-500" />
                    ) : (
                      <ChevronRight className="h-4 w-4 text-gray-500" />
                    )}
                  </button>
                  
                  {showTemplateFields && (
                    <div className="px-4 py-3 max-h-48 overflow-y-auto">
                      {selectedTemplate.fields_by_category ? (
                        // Show fields grouped by category
                        Object.entries(selectedTemplate.fields_by_category).map(([category, fields]) => (
                          <div key={category} className="mb-3 last:mb-0">
                            <h4 className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">
                              {selectedTemplate.category_display_names?.[category] || category}
                            </h4>
                            <div className="flex flex-wrap gap-1">
                              {fields.map(field => (
                                <span
                                  key={field.id}
                                  className="inline-flex items-center px-2 py-0.5 rounded text-xs bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-300"
                                  title={field.display_name || field.field_name}
                                >
                                  {field.display_name || field.field_name}
                                </span>
                              ))}
                            </div>
                          </div>
                        ))
                      ) : (
                        // Show flat list of fields
                        <div className="flex flex-wrap gap-1">
                          {selectedTemplate.fields.map(field => (
                            <span
                              key={field.id}
                              className="inline-flex items-center px-2 py-0.5 rounded text-xs bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-300"
                              title={field.display_name || field.field_name}
                            >
                              {field.display_name || field.field_name}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              )}
              
              {/* Attachments */}
              <div>
                <label className="form-label">Attachments</label>
                <div 
                  className={`border-2 border-dashed rounded-lg p-4 transition-colors ${
                    isDragOver 
                      ? 'border-navy-500 bg-navy-50 dark:bg-navy-900/20 drop-zone-active' 
                      : 'border-gray-300 dark:border-gray-600'
                  }`}
                  onDragOver={(e) => { e.preventDefault(); setIsDragOver(true) }}
                  onDragLeave={(e) => { e.preventDefault(); setIsDragOver(false) }}
                  onDrop={handleDrop}
                >
                  {attachments.length === 0 ? (
                    <label className="flex flex-col items-center cursor-pointer">
                      <Upload className={`h-8 w-8 mb-2 ${isDragOver ? 'text-navy-600 dark:text-navy-400' : 'text-gray-400 dark:text-gray-500'}`} />
                      <span className="text-sm text-gray-500 dark:text-gray-400">
                        Click to upload or drag and drop
                      </span>
                      <span className="text-xs text-gray-400 dark:text-gray-500 mt-1">
                        PDF
                      </span>
                      <input
                        type="file"
                        className="hidden"
                        onChange={handleFileChange}
                        multiple
                        accept=".pdf"
                      />
                    </label>
                  ) : (
                    <div className="space-y-2">
                      {attachments.map((att, index) => (
                        <div
                          key={index}
                          className="flex items-center justify-between bg-gray-50 dark:bg-gray-800 rounded p-2"
                        >
                          <div className="flex items-center">
                            <Mail className="h-4 w-4 text-gray-400 mr-2" />
                            <span className="text-sm text-gray-700 dark:text-gray-300">{att.filename}</span>
                            <span className="text-xs text-gray-400 dark:text-gray-500 ml-2">
                              ({formatFileSize(att.size)})
                            </span>
                          </div>
                          <button
                            type="button"
                            onClick={() => removeAttachment(index)}
                            className="text-red-500 hover:text-red-700"
                          >
                            <Trash2 className="h-4 w-4" />
                          </button>
                        </div>
                      ))}
                      <label className="flex items-center justify-center py-2 text-sm text-primary-600 cursor-pointer hover:text-primary-700">
                        <Plus className="h-4 w-4 mr-1" />
                        Add more files
                        <input
                          type="file"
                          className="hidden"
                          onChange={handleFileChange}
                          multiple
                          accept=".pdf"
                        />
                      </label>
                    </div>
                  )}
                </div>
              </div>
            </div>
            
            {/* Footer */}
            <div className="px-6 py-4 border-t dark:border-gray-700 flex justify-end gap-3">
              <button
                type="button"
                onClick={onClose}
                disabled={loading}
                className={`btn btn-secondary ${loading ? 'opacity-50 cursor-not-allowed' : ''}`}
              >
                Cancel
              </button>
              <button
                type="submit"
                disabled={loading}
                className="btn btn-primary"
              >
                {loading ? (
                  <>
                    <RefreshCw className="h-4 w-4 mr-1 animate-spin" />
                    Ingesting...
                  </>
                ) : (
                  <>
                    <Mail className="h-4 w-4 mr-1" />
                    Ingest Email
                  </>
                )}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  )
}

function formatFileSize(bytes) {
  if (!bytes) return '0 B'
  const k = 1024
  const sizes = ['B', 'KB', 'MB', 'GB']
  const i = Math.floor(Math.log(bytes) / Math.log(k))
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i]
}

export default IngestEmailModal
