function BrandColorPicker({ value, onChange }) {
  const [showQuick, setShowQuick] = useState(false)

  return (
    <div className="space-y-3">
      <div className="flex items-end gap-3">
        {/* Native OS colour picker */}
        <div>
          <label className="text-xs text-gray-500 dark:text-gray-400 block mb-1">Colour</label>
          <label className="relative cursor-pointer group block">
            <input
              type="color"
              value={value.length === 7 ? value : '#1e2a3b'}
              onChange={(e) => onChange(e.target.value)}
              className="absolute inset-0 opacity-0 w-full h-full cursor-pointer"
            />
            <div
              className="w-10 h-10 rounded-lg border-2 border-gray-300 dark:border-gray-600 group-hover:border-blue-500 transition-colors shadow-sm"
              style={{ backgroundColor: value }}
            />
          </label>
        </div>

        {/* Hex input */}
        <div>
          <label className="text-xs text-gray-500 dark:text-gray-400 block mb-1">Hex Code</label>
          <input
            type="text"
            value={value}
            onChange={(e) => {
              const v = e.target.value
              if (/^#[0-9a-fA-F]{0,6}$/.test(v)) onChange(v)
            }}
            maxLength={7}
            className="form-input w-28 font-mono text-sm h-10"
            placeholder="#1e2a3b"
          />
        </div>

        {/* Quick-pick toggle */}
        <button
          type="button"
          onClick={() => setShowQuick(!showQuick)}
          className="h-10 text-sm font-medium flex items-center gap-1.5 px-3 rounded-lg border border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
        >
          <Palette className="h-4 w-4" />
          {showQuick ? 'Hide' : 'Quick Pick'}
        </button>
      </div>

      {/* Dropdown-style compact palette */}
      {showQuick && (
        <div className="inline-block p-2 rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 shadow-lg max-h-48 overflow-y-auto">
          <div className="grid grid-cols-10 gap-1">
            {QUICK_COLORS.map((color) => (
              <button
                key={color}
                type="button"
                onClick={() => { onChange(color); setShowQuick(false) }}
                className={`w-7 h-7 rounded-md transition-transform hover:scale-110 hover:z-10 ${
                  value === color
                    ? 'ring-2 ring-blue-500 ring-offset-1 scale-110 z-10'
                    : 'ring-1 ring-black/10 dark:ring-white/10'
                }`}
                style={{ backgroundColor: color }}
                title={color}
              />
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Image upload with preview
// ---------------------------------------------------------------------------
function ImageUploader({ label, currentUrl, onUpload, type, accept = 'image/png,image/jpeg,image/svg+xml,image/webp' }) {
  const inputRef = useRef(null)
  const [uploading, setUploading] = useState(false)
  const [dragOver, setDragOver] = useState(false)

  const handleFile = async (file) => {
    if (!file) return
    setUploading(true)
    try {
      await onUpload(file, type)
    } finally {
      setUploading(false)
    }
  }

  const onDrop = (e) => {
    e.preventDefault()
    setDragOver(false)
    const file = e.dataTransfer.files?.[0]
    if (file) handleFile(file)
  }

  return (
    <div>
      <label className="form-label">{label}</label>
      <div
        className={`mt-1.5 border-2 border-dashed rounded-xl p-6 text-center transition-colors cursor-pointer
          ${dragOver ? 'border-[var(--brand-accent)] bg-[var(--brand-accent)]/5' : 'border-gray-200 dark:border-gray-700 hover:border-gray-300 dark:hover:border-gray-600'}
        `}
        onClick={() => inputRef.current?.click()}
        onDragOver={(e) => { e.preventDefault(); setDragOver(true) }}
        onDragLeave={() => setDragOver(false)}
        onDrop={onDrop}
      >
        {uploading ? (
          <div className="flex flex-col items-center gap-2 text-gray-500 dark:text-gray-400">
            <Loader2 className="h-8 w-8 animate-spin" />
            <span className="text-sm">Uploading…</span>
          </div>
        ) : currentUrl ? (
          <div className="flex flex-col items-center gap-3">
            <img src={currentUrl} alt={label} className="max-h-20 max-w-48 object-contain rounded-lg" />
            <span className="text-xs text-gray-500 dark:text-gray-400">Click or drag to replace</span>
          </div>
        ) : (
          <div className="flex flex-col items-center gap-2 text-gray-400 dark:text-gray-500">
            <Upload className="h-8 w-8" />
            <span className="text-sm">Click or drag an image</span>
            <span className="text-xs">PNG, JPG, SVG, or WebP</span>
          </div>
        )}
        <input
          ref={inputRef}
          type="file"
          accept={accept}
          className="hidden"
          onChange={(e) => handleFile(e.target.files?.[0])}
        />
      </div>
    </div>
  )
}

