import React, { createContext, useContext, useState, useEffect, useMemo, useCallback } from 'react'
import { useMsal, useAccount } from '@azure/msal-react'
import { InteractionRequiredAuthError } from '@azure/msal-browser'
import { isMsalConfigured, apiTokenRequest, loginRequest } from '../config/msalConfig'
import { authApi, setAccessToken as setApiToken, setTokenRefreshCallback } from '../services/api'

const AuthContext = createContext(null)

// Development mode mock user
const devUser = {
  sub: 'dev|local-user',
  email: 'dev@localhost',
  name: 'Development User',
  picture: 'https://via.placeholder.com/150'
}

const devSubscription = {
  plan: 'enterprise',
  status: 'active',
  started_at: null,
  expires_at: null,
}

// Dev mode provider - doesn't use MSAL at all
export function DevAuthProvider({ children }) {
  const login = useCallback(() => {}, [])
  const logout = useCallback(() => {}, [])
  const getAccessToken = useCallback(async () => 'dev-token', [])
  
  const value = useMemo(() => ({
    isAuthenticated: true,
    isLoading: false,
    user: devUser,
    accessToken: 'dev-token',
    subscription: devSubscription,
    organizationName: 'Development Org',
    login,
    logout,
    getAccessToken,
  }), [login, logout, getAccessToken])

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  )
}

// Production provider - uses Microsoft Entra ID via MSAL
export function MsalAuthProvider({ children }) {
  const { instance, accounts, inProgress } = useMsal()
  const account = useAccount(accounts[0] || {})
  const [accessToken, setAccessToken] = useState(null)
  const [subscription, setSubscription] = useState(null)
  const [organizationName, setOrganizationName] = useState(null)
  const [userRole, setUserRole] = useState(null) 
  const [sessionExpired, setSessionExpired] = useState(false)
  const [redirectHandled, setRedirectHandled] = useState(false)
  const [authReady, setAuthReady] = useState(false)

  const isAuthenticated = accounts.length > 0
  // Keep showing the loading spinner while:
  //  - MSAL is processing a redirect/interaction
  //  - The redirect promise hasn't been handled yet
  //  - Cached accounts exist but the initial token + profile fetch hasn't completed
  //    (prevents a flash of the login page for returning users)
  const isLoading = inProgress !== 'none' || !redirectHandled || (accounts.length > 0 && !authReady)

  // Listen for session-expired events from API interceptor (401 responses)
  useEffect(() => {
    const handleSessionExpired = () => {
      console.warn('Session expired — clearing auth state')
      setAccessToken(null)
      setSessionExpired(true)
    }
    window.addEventListener('session-expired', handleSessionExpired)
    return () => window.removeEventListener('session-expired', handleSessionExpired)
  }, [])

  const clearSessionExpired = useCallback(() => setSessionExpired(false), [])

  // Transform MSAL account to our user format
  const user = useMemo(() => {
    if (!account) return null
    return {
      sub: account.localAccountId || account.homeAccountId,
      email: account.username,
      name: account.name || account.username,
      picture: null, // Microsoft doesn't provide picture in token by default
    }
  }, [account])

  // Get access token
  const getAccessToken = useCallback(async () => {
    if (!account) return null
    
    try {
      const response = await instance.acquireTokenSilent({
        ...apiTokenRequest,
        account: account,
      })
      return response.accessToken
    } catch (error) {
      if (error instanceof InteractionRequiredAuthError) {
        // Fallback to interactive method
        try {
          const response = await instance.acquireTokenPopup(apiTokenRequest)
          return response.accessToken
        } catch (popupError) {
          console.error('Error getting access token via popup:', popupError)
          return null
        }
      }
      console.error('Error getting access token:', error)
      return null
    }
  }, [instance, account])

  // Fetch token on mount and when account changes, then load user profile.
  // Gated on redirectHandled so we don't start before MSAL is ready.
  useEffect(() => {
    if (!redirectHandled) return

    const fetchTokenAndProfile = async () => {
      if (isAuthenticated && account) {
        const token = await getAccessToken()
        setAccessToken(token)

        // Register the token refresh callback so the API request interceptor
        // can proactively acquire a fresh token before expiry, and the
        // response interceptor can retry on 401.
        setTokenRefreshCallback(getAccessToken)

        // Once we have a token, fetch user profile from backend (includes subscription)
        if (token) {
          setApiToken(token)
          try {
            const res = await authApi.getCurrentUser()
            if (res.data?.subscription) {
              setSubscription(res.data.subscription)
            }
            if (res.data?.organization_name) {
              setOrganizationName(res.data.organization_name)
            }
            if (res.data?.role) {
              setUserRole(res.data.role)                                 // ← NEW
            }
          } catch (err) {
            console.error('Error fetching user profile:', err)
          }
        }
      }
      // Mark auth initialisation complete so isLoading becomes false
      setAuthReady(true)
    }
    fetchTokenAndProfile()
  }, [isAuthenticated, account, getAccessToken, redirectHandled])

  const handleLogin = useCallback(async () => {
    try {
      const returnUrl = localStorage.getItem('xtract_return_url') || '/'
      await instance.loginRedirect({
        ...loginRequest,
        prompt: 'select_account', // Always show the Microsoft account picker
        state: returnUrl,
      })
    } catch (error) {
      console.error('Login error:', error)
    }
  }, [instance])

  // Handle redirect promise first before attempting auto-login
  useEffect(() => {
    const handleRedirect = async () => {
      try {
        const response = await instance.handleRedirectPromise()
        if (response) {
          instance.setActiveAccount(response.account)
          // Restore the return URL from MSAL state (set during loginRedirect)
          if (response.state && response.state !== '/' && response.state !== '/login') {
            localStorage.setItem('xtract_return_url', response.state)
          }
        }
      } catch (error) {
        console.error('Error handling redirect:', error)
      } finally {
        setRedirectHandled(true)
      }
    }
    handleRedirect()
  }, [instance])

  const handleLogout = useCallback(async () => {
    try {
      // Clear local app state
      setAccessToken(null)
      setSubscription(null)
      setOrganizationName(null)
      setAuthReady(false)
      setApiToken(null)
      setTokenRefreshCallback(null)
      localStorage.removeItem('xtract_return_url')

      // Use logoutRedirect with onRedirectNavigate returning false.
      // This tells MSAL to:
      //  1. Clear the entire MSAL token cache (accounts, tokens, etc.)
      //  2. NOT navigate to Microsoft's logout page (which shows the
      //     account picker and adds an unnecessary round-trip)
      // We then redirect to /login ourselves.
      // On next sign-in, prompt:'select_account' ensures the user can
      // pick a different account if needed.
      await instance.logoutRedirect({
        onRedirectNavigate: () => false,  // prevent navigation to Microsoft
      })
    } catch (error) {
      console.error('Logout error:', error)
      // Fallback: clear MSAL cache programmatically
      try { await instance.clearCache() } catch {}
      sessionStorage.clear()
      localStorage.removeItem('xtract_return_url')
    }
    // Navigate to login (runs after logoutRedirect clears cache,
    // or after the fallback above)
    window.location.href = '/login'
  }, [instance])

  const value = useMemo(() => ({
    isAuthenticated,
    isLoading,
    user,
    accessToken,
    subscription,
    organizationName,
    userRole,                                 // ← NEW
    sessionExpired,
    login: handleLogin,
    logout: handleLogout,
    getAccessToken,
    clearSessionExpired,
  }), [isAuthenticated, isLoading, user, accessToken, subscription, organizationName, sessionExpired, handleLogin, handleLogout, getAccessToken, clearSessionExpired])

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  )
}

// Main AuthProvider that chooses between dev and production
export function AuthProvider({ children }) {
  if (!isMsalConfigured()) {
    return <DevAuthProvider>{children}</DevAuthProvider>
  }
  return <MsalAuthProvider>{children}</MsalAuthProvider>
}

export function useAuth() {
  const context = useContext(AuthContext)
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return context
}
