import React, { useEffect, useMemo, useState, useRef } from 'react'
import { Link, useNavigate, useParams, useLocation } from 'react-router-dom'
import { templatesApi } from '../services/api'
import { formatDate } from '../utils/dateUtils'
import { useToast } from '../context/ToastContext'
import {
  ArrowLeft,
  Plus,
  Loader2,
  AlertCircle,
  Bot,
  Pencil,
  Trash2,
  Save,
  CheckCircle2,
  Upload,
  Sparkles,
  FileText,
  X,
  Check,
  ChevronDown,
  ChevronRight,
  MessageSquare,
  Info,
  User,
  Calendar,
  Clock,
} from 'lucide-react'

const DATA_TYPES = [
  { value: 'text', label: 'Text' },
  { value: 'number', label: 'Number' },
  { value: 'currency', label: 'Currency' },
  { value: 'percentage', label: 'Percentage' },
  { value: 'date', label: 'Date' },
  { value: 'boolean', label: 'Boolean' },
  { value: 'dropdown', label: 'Dropdown' },
]

function slugify(value = '') {
  return value
    .trim()
    .replace(/[^a-zA-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')
}

function FieldModal({ open, onClose, onSave, categories, initialField, saving }) {
  const [form, setForm] = useState({
    display_name: '',
    field_name: '',
    field_type: 'text',
    category_id: '',
    description: '',
  })

  useEffect(() => {
    if (!open) return

    if (initialField) {
      setForm({
        display_name: initialField.display_name || '',
        field_name: initialField.field_name || '',
        field_type: initialField.field_type || 'text',
        category_id: initialField.category_id || '',
        description: initialField.description || '',
      })
    } else {
      const defaultCategory = categories?.[0]?.id || ''
      setForm({
        display_name: '',
        field_name: '',
        field_type: 'text',
        category_id: defaultCategory,
        description: '',
      })
    }
  }, [open, initialField, categories])

  if (!open) return null

  const isEdit = !!initialField

  const autoGenerateFieldName = () => {
    if (!form.display_name) return
    setForm(prev => ({ ...prev, field_name: slugify(prev.display_name) }))
  }

  const save = () => {
    if (!form.display_name.trim() || !form.field_name.trim()) return
    onSave({
      display_name: form.display_name.trim(),
      field_name: form.field_name.trim(),
      field_type: form.field_type,
      category_id: form.category_id || null,
      description: form.description.trim() || null,
    })
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/40" onClick={onClose} />
      <div className="relative w-full max-w-2xl bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 shadow-xl p-6">
        <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-100">{isEdit ? 'Edit Field' : 'Add Field'}</h3>
        <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
          Keep descriptions clear and specific — they guide the analyzer to extract accurately.
        </p>

        <div className="mt-5 grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Display name</label>
            <input
              value={form.display_name}
              onChange={e => setForm(prev => ({ ...prev, display_name: e.target.value }))}
              className="w-full px-3 py-2.5 rounded-lg border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm"
              placeholder="Coupon Rate"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Field name (internal)</label>
            <div className="flex gap-2">
              <input
                value={form.field_name}
                onChange={e => setForm(prev => ({ ...prev, field_name: slugify(e.target.value) }))}
                className="w-full px-3 py-2.5 rounded-lg border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm font-mono"
                placeholder="coupon_rate"
              />
              <button
                onClick={autoGenerateFieldName}
                type="button"
                className="px-3 py-2 rounded-lg border border-gray-300 dark:border-gray-700 text-sm"
              >
                Auto
              </button>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Data type</label>
            <select
              value={form.field_type}
              onChange={e => setForm(prev => ({ ...prev, field_type: e.target.value }))}
              className="w-full px-3 py-2.5 rounded-lg border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm"
            >
              {DATA_TYPES.map(dt => (
                <option key={dt.value} value={dt.value}>{dt.label}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Category</label>
            <select
              value={form.category_id}
              onChange={e => setForm(prev => ({ ...prev, category_id: e.target.value }))}
              className="w-full px-3 py-2.5 rounded-lg border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm"
            >
              <option value="">Uncategorized</option>
              {categories.map(c => (
                <option key={c.id} value={c.id}>{c.display_name || c.name}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="mt-4">
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Description</label>
          <textarea
            rows={4}
            value={form.description}
            onChange={e => setForm(prev => ({ ...prev, description: e.target.value }))}
            className="w-full px-3 py-2.5 rounded-lg border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm"
            placeholder="Example: Annual coupon rate shown in percentage near financial terms section"
          />
        </div>



        <div className="mt-6 flex items-center justify-end gap-2.5">
          <button onClick={onClose} className="px-4 py-2 rounded-lg border border-gray-300 dark:border-gray-700 text-sm">
            Cancel
          </button>
          <button
            onClick={save}
            disabled={!form.display_name.trim() || !form.field_name.trim() || saving}
            className="inline-flex items-center gap-2 px-4 py-2 rounded-lg bg-navy-800 text-white text-sm font-medium disabled:opacity-50"
          >
            {saving && <Loader2 className="h-4 w-4 animate-spin" />}
            {isEdit ? 'Save Changes' : 'Add Field'}
          </button>
        </div>
      </div>
    </div>
  )
}

export default function TemplateDetail() {
  const { id } = useParams()
  const navigate = useNavigate()
  const toast = useToast()

  const [template, setTemplate] = useState(null)
  const [categories, setCategories] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  const [fieldModalOpen, setFieldModalOpen] = useState(false)
  const [editingField, setEditingField] = useState(null)
  const [savingField, setSavingField] = useState(false)
  const [buildingAnalyzer, setBuildingAnalyzer] = useState(false)

  // AI Suggest state
  const [showAiSuggest, setShowAiSuggest] = useState(false)
  const [aiFiles, setAiFiles] = useState([])
  const [aiPrompt, setAiPrompt] = useState('')
  const [aiSuggesting, setAiSuggesting] = useState(false)
  const [aiResult, setAiResult] = useState(null) // { fields, document_type, ... }
  const [aiSelected, setAiSelected] = useState({}) // field_name -> true/false
  const [aiSaving, setAiSaving] = useState(false)
  const fileInputRef = useRef(null)
  const importInputRef = useRef(null)
  const [importing, setImporting] = useState(false)

  // Track whether fields have changed since last analyzer build
  const [fieldsDirty, setFieldsDirty] = useState(false)

  // Custom navigation guard (useBlocker only works with createBrowserRouter, not BrowserRouter)
  const [navBlocked, setNavBlocked] = useState(false)
  const [pendingNavPath, setPendingNavPath] = useState(null)
  const location = useLocation()

  // Intercept all <a> clicks when fields are dirty (sidebar, back link, etc.)
  useEffect(() => {
    if (!fieldsDirty) return

    const handleClick = (e) => {
      const anchor = e.target.closest('a[href]')
      if (!anchor) return
      const href = anchor.getAttribute('href')
      if (href && href.startsWith('/') && href !== location.pathname) {
        e.preventDefault()
        e.stopPropagation()
        setPendingNavPath(href)
        setNavBlocked(true)
      }
    }

    document.addEventListener('click', handleClick, true) // capture phase
    return () => document.removeEventListener('click', handleClick, true)
  }, [fieldsDirty, location.pathname])

  const groupedFields = useMemo(() => {
    const fields = template?.fields || []
    const map = {}
    fields.forEach(f => {
      const key = f.category || 'other'
      const displayName = f.category_display_name || 'Other'
      if (!map[key]) {
        map[key] = { displayName, fields: [] }
      }
      map[key].fields.push(f)
    })
    return map
  }, [template])

  // Point 5: Filter categories to only those used by this template's fields
  const templateCategories = useMemo(() => {
    const usedCategoryIds = new Set(
      (template?.fields || []).map(f => f.category_id).filter(Boolean)
    )
    // If no fields have categories yet, show all global categories
    if (usedCategoryIds.size === 0) return categories
    return categories.filter(c => usedCategoryIds.has(c.id))
  }, [template, categories])

  const loadTemplate = async () => {
    try {
      setLoading(true)
      const [templateRes, categoriesRes] = await Promise.all([
        templatesApi.get(id),
        templatesApi.getCategories(),
      ])
      setTemplate(templateRes.data)
      setCategories(categoriesRes.data?.categories || [])
      setError('')
    } catch (e) {
      console.error(e)
      setError('Failed to load template details')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    loadTemplate()
  }, [id])

  // Browser close/refresh guard when fields changed but analyzer not rebuilt
  useEffect(() => {
    const handler = (e) => {
      if (fieldsDirty) {
        e.preventDefault()
        e.returnValue = ''
      }
    }
    window.addEventListener('beforeunload', handler)
    return () => window.removeEventListener('beforeunload', handler)
  }, [fieldsDirty])

  const handleSaveField = async (payload) => {
    try {
      setSavingField(true)
      if (editingField) {
        await templatesApi.updateField(id, editingField.id, payload)
        toast.success('Field updated', 'Template field updated successfully.')
      } else {
        await templatesApi.addField(id, payload)
        toast.success('Field added', 'Template field added successfully.')
      }
      setFieldModalOpen(false)
      setEditingField(null)
      setFieldsDirty(true)
      await loadTemplate()
    } catch (e) {
      console.error(e)
      toast.error('Save failed', e?.response?.data?.error || 'Unable to save field')
    } finally {
      setSavingField(false)
    }
  }

  const handleDeleteField = async (fieldId) => {
    try {
      await templatesApi.deleteField(id, fieldId)
      toast.success('Field removed', 'Field removed from template.')
      setFieldsDirty(true)
      await loadTemplate()
    } catch (e) {
      console.error(e)
      toast.error('Delete failed', e?.response?.data?.error || 'Unable to delete field')
    }
  }

  const handleDeleteAllFields = async () => {
    if (!window.confirm(`Delete ALL ${template?.fields?.length || 0} fields from this template? This cannot be undone.`)) return
    try {
      const res = await templatesApi.deleteAllFields(id)
      toast.success('All fields deleted', res.data?.message || 'All fields removed.')
      setFieldsDirty(true)
      await loadTemplate()
    } catch (e) {
      console.error(e)
      toast.error('Delete failed', e?.response?.data?.error || 'Unable to delete fields')
    }
  }

  const handleImportFields = async (e) => {
    const file = e.target.files?.[0]
    e.target.value = ''
    if (!file) return

    try {
      setImporting(true)
      const text = await file.text()
      const json = JSON.parse(text)

      // Support multiple JSON formats:
      // 1. Azure CU format: { fieldSchema: { fields: { FieldName: { type, description } } } }
      // 2. Flat dict: { fields: { FieldName: { type, description } } }
      // 3. Direct dict: { FieldName: { type, description } }
      let fieldsDict = null
      if (json.fieldSchema?.fields && typeof json.fieldSchema.fields === 'object') {
        fieldsDict = json.fieldSchema.fields
      } else if (json.fields && typeof json.fields === 'object' && !Array.isArray(json.fields)) {
        fieldsDict = json.fields
      } else if (typeof json === 'object' && !Array.isArray(json) && !json.fieldSchema) {
        // Check if top-level keys look like field definitions (have type/description)
        const firstVal = Object.values(json)[0]
        if (firstVal && typeof firstVal === 'object' && ('type' in firstVal || 'description' in firstVal)) {
          fieldsDict = json
        }
      }

      if (!fieldsDict || Object.keys(fieldsDict).length === 0) {
        toast.error('Invalid format', 'JSON must contain field definitions. Supported formats: Azure CU analyzer JSON, or a { fields: { ... } } dictionary.')
        return
      }

      // Ask whether to clear existing fields
      const fieldCount = Object.keys(fieldsDict).length
      const existingCount = template?.fields?.length || 0
      const clearExisting = existingCount > 0 && window.confirm(
        `This will import ${fieldCount} fields from "${file.name}".\n\n` +
        `You currently have ${existingCount} fields.\n` +
        `Click OK to REPLACE all existing fields, or Cancel to ADD alongside them.`
      )

      const res = await templatesApi.importFields(id, {
        fields: fieldsDict,
        clear_existing: clearExisting,
      })

      const data = res.data
      toast.success(
        'Fields imported',
        `${data.added} added, ${data.reactivated} reactivated, ${data.skipped} skipped`
      )

      // Save the import source as template metadata
      try {
        const existingDocs = template.source_documents
          ? (() => { try { return JSON.parse(template.source_documents) } catch { return [] } })()
          : []
        await templatesApi.update(id, {
          name: template.name,
          description: template.description,
          source_documents: JSON.stringify([...existingDocs, file.name]),
          creation_method: template.creation_method || 'json_import',
        })
      } catch (metaErr) {
        console.warn('Failed to save import metadata:', metaErr)
      }

      setFieldsDirty(true)
      await loadTemplate()
    } catch (err) {
      console.error('Import error:', err)
      if (err instanceof SyntaxError) {
        toast.error('Invalid JSON', 'The file could not be parsed as JSON.')
      } else {
        toast.error('Import failed', err?.response?.data?.error || 'Unable to import fields')
      }
    } finally {
      setImporting(false)
    }
  }

  const handleBuildAnalyzer = async () => {
    try {
      setBuildingAnalyzer(true)
      const res = await templatesApi.buildAnalyzer(id, {
        name: `${template.name} Analyzer`,
        description: `Custom analyzer for template ${template.name}`,
        default_method: 'extract',
      })
      setTemplate(res.data.template)
      setFieldsDirty(false)
      toast.success('Analyzer ready', 'Custom analyzer built and linked to this template.')
    } catch (e) {
      console.error(e)
      toast.error('Build failed', e?.response?.data?.error || 'Unable to build analyzer')
    } finally {
      setBuildingAnalyzer(false)
    }
  }

  // ===== AI Suggest Handlers =====
  const handleAiFileSelect = (e) => {
    const incoming = Array.from(e.target.files || [])
    const pdfs = incoming.filter(f => f.type === 'application/pdf')
    if (pdfs.length === 0) {
      toast.error('Invalid file', 'Please select PDF files only')
      return
    }
    const merged = [...aiFiles, ...pdfs].slice(0, 5)
    if (incoming.length + aiFiles.length > 5) {
      toast.info('Limit reached', 'Maximum 5 documents allowed. Only the first 5 were kept.')
    }
    setAiFiles(merged)
    setAiResult(null)
    setAiSelected({})
    e.target.value = '' // reset so same file can be re-selected
  }

  const handleAiFileDrop = (e) => {
    e.preventDefault()
    const incoming = Array.from(e.dataTransfer.files || [])
    const pdfs = incoming.filter(f => f.type === 'application/pdf')
    if (pdfs.length === 0) {
      toast.error('Invalid file', 'Please drop PDF files only')
      return
    }
    const merged = [...aiFiles, ...pdfs].slice(0, 5)
    if (incoming.length + aiFiles.length > 5) {
      toast.info('Limit reached', 'Maximum 5 documents allowed. Only the first 5 were kept.')
    }
    setAiFiles(merged)
    setAiResult(null)
    setAiSelected({})
  }

  const handleAiSuggest = async () => {
    if (aiFiles.length === 0) return
    try {
      setAiSuggesting(true)
      setAiResult(null)
      const res = await templatesApi.suggestFields(aiFiles, aiPrompt)
      const data = res.data
      setAiResult(data)
      // Pre-select all suggested fields
      const selected = {}
      ;(data.fields || []).forEach(f => { selected[f.field_name] = true })
      setAiSelected(selected)
      toast.success(
        'Fields suggested',
        `AI identified ${data.total_fields} fields from "${data.source_file}". Review and accept the ones you want.`
      )
    } catch (e) {
      console.error(e)
      toast.error('AI suggestion failed', e?.response?.data?.error || e?.response?.data?.details || 'Unable to analyze document')
    } finally {
      setAiSuggesting(false)
    }
  }

  const handleAcceptSuggested = async () => {
    if (!aiResult?.fields) return
    const fieldsToAdd = aiResult.fields.filter(f => aiSelected[f.field_name])
    if (fieldsToAdd.length === 0) {
      toast.error('No fields selected', 'Select at least one field to add')
      return
    }

    // Map category names to category IDs from the database
    const categoryMap = {}
    categories.forEach(c => {
      const name = (c.display_name || c.name || '').toLowerCase()
      categoryMap[name] = c.id
      // Also map the short name (e.g., "instrument" → cat_instrument)
      if (c.name) categoryMap[c.name.toLowerCase()] = c.id
    })
    // Common AI-suggested categories that don't have exact DB matches
    if (!categoryMap['risk metrics']) categoryMap['risk metrics'] = categoryMap['other fields'] || ''
    if (!categoryMap['risk']) categoryMap['risk'] = categoryMap['other fields'] || ''

    setAiSaving(true)
    let added = 0
    let failed = 0
    const existingNames = new Set((template?.fields || []).map(f => f.field_name))

    for (const field of fieldsToAdd) {
      if (existingNames.has(field.field_name)) {
        // Skip duplicates
        continue
      }
      try {
        // Try to match category by name
        const catName = (field.category || '').toLowerCase()
        const categoryId = categoryMap[catName] || ''

        await templatesApi.addField(id, {
          display_name: field.display_name || field.field_name,
          field_name: field.field_name,
          field_type: field.field_type === 'currency' ? 'number' : field.field_type || 'text',
          category_id: categoryId,
          description: field.description || '',
        })
        added++
        existingNames.add(field.field_name)
      } catch (e) {
        // 409 = duplicate field name — skip silently
        if (e?.response?.status === 409) {
          existingNames.add(field.field_name)
          continue
        }
        console.error(`Failed to add field ${field.field_name}:`, e)
        failed++
      }
    }

    setAiSaving(false)
    
    if (added > 0) {
      setFieldsDirty(true)
      toast.success('Fields added', `Added ${added} fields to template.${failed > 0 ? ` ${failed} failed.` : ''}`)
    }
    if (added === 0 && failed > 0) {
      toast.error('Failed', `All ${failed} fields failed to save.`)
    }
    
    // Save template metadata (source documents, prompt, method) BEFORE
    // reloading the template so the refreshed state includes this data.
    try {
      await templatesApi.update(id, {
        name: template.name,
        description: template.description,
        source_documents: JSON.stringify(aiFiles.map(f => f.name)),
        creation_prompt: aiPrompt || null,
        creation_method: 'ai_suggest',
      })
    } catch (metaErr) {
      console.warn('Failed to save template metadata:', metaErr)
    }

    // Reload template (now includes saved source_documents + creation_method)
    await loadTemplate()

    // Clear suggestion state
    setAiResult(null)
    setAiFiles([])
    setAiPrompt('')
    setShowAiSuggest(false)
  }

  const toggleSelectAll = () => {
    if (!aiResult?.fields) return
    const allSelected = aiResult.fields.every(f => aiSelected[f.field_name])
    const next = {}
    aiResult.fields.forEach(f => { next[f.field_name] = !allSelected })
    setAiSelected(next)
  }
  // ===== End AI Suggest Handlers =====

  if (loading) {
    return (
      <div className="space-y-6">
        <div className="rounded-xl border border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900 p-10 text-center">
          <Loader2 className="h-6 w-6 animate-spin text-gray-500 mx-auto mb-3" />
          <p className="text-sm text-gray-500 dark:text-gray-400">Loading template...</p>
        </div>
      </div>
    )
  }

  if (error || !template) {
    return (
      <div className="space-y-6">
        <div className="rounded-xl border border-red-200 dark:border-red-900/40 bg-red-50 dark:bg-red-900/20 p-4 text-sm text-red-700 dark:text-red-300 flex items-center gap-2">
          <AlertCircle className="h-4 w-4" />
          {error || 'Template not found'}
        </div>
        <div className="mt-4">
          <button
            onClick={() => navigate('/templates')}
            className="inline-flex items-center gap-2 px-3 py-2 rounded-lg border border-gray-300 dark:border-gray-700 text-sm"
          >
            <ArrowLeft className="h-4 w-4" />
            Back to Templates
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between gap-4">
        <div>
          <Link to="/templates" className="inline-flex items-center gap-1.5 text-sm text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 mb-2">
            <ArrowLeft className="h-4 w-4" />
            Back to Templates
          </Link>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-gray-100">{template.name}</h1>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">{template.description || 'No description'}</p>
          <div className="flex items-center gap-2 mt-2">
            <span className="text-xs font-medium text-gray-500 dark:text-gray-400">Allow Reprocessing</span>
            <button
              type="button"
              onClick={async () => {
                const newValue = !template.allow_reprocessing
                setTemplate(prev => ({ ...prev, allow_reprocessing: newValue }))
                try {
                  await templatesApi.update(template.id, {
                    allow_reprocessing: newValue
                  })
                } catch (err) {
                  setTemplate(prev => ({ ...prev, allow_reprocessing: !newValue }))
                  console.error('Failed to update reprocessing setting:', err)
                }
              }}
              className={`relative inline-flex h-5 w-9 flex-shrink-0 rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out cursor-pointer focus:outline-none focus:ring-2 focus:ring-primary-500 focus:ring-offset-2 ${
                template.allow_reprocessing !== false
                  ? 'bg-green-500'
                  : 'bg-gray-300 dark:bg-gray-600'
              }`}
              title={template.allow_reprocessing !== false ? 'Reprocessing allowed — click to block' : 'Reprocessing blocked — click to allow'}
            >
              <span
                className={`pointer-events-none inline-block h-4 w-4 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${
                  template.allow_reprocessing !== false ? 'translate-x-4' : 'translate-x-0'
                }`}
              />
            </button>
            <span className={`text-xs ${template.allow_reprocessing !== false ? 'text-green-600 dark:text-green-400' : 'text-gray-400 dark:text-gray-500'}`}>
              {template.allow_reprocessing !== false ? 'Allowed' : 'Blocked'}
            </span>
          </div>
        </div>

        <div className="flex flex-wrap gap-2">
          <button
            onClick={() => setShowAiSuggest(!showAiSuggest)}
            className={`inline-flex items-center gap-2 px-3.5 py-2 rounded-lg text-sm font-medium transition-colors ${
              showAiSuggest
                ? 'bg-purple-100 text-purple-700 border border-purple-300 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-700'
                : 'bg-gradient-to-r from-purple-600 to-indigo-600 text-white hover:from-purple-700 hover:to-indigo-700'
            }`}
          >
            <Sparkles className="h-4 w-4" />
            {showAiSuggest ? 'Close Upload' : 'Upload Documents'}
          </button>
          <button
            onClick={() => {
              setEditingField(null)
              setFieldModalOpen(true)
            }}
            className="inline-flex items-center gap-2 px-3.5 py-2 rounded-lg border border-gray-300 dark:border-gray-700 text-sm"
          >
            <Plus className="h-4 w-4" />
            Add Field
          </button>
          <input
            type="file"
            accept=".json"
            ref={importInputRef}
            onChange={handleImportFields}
            className="hidden"
          />
          <button
            onClick={() => importInputRef.current?.click()}
            disabled={importing}
            className="inline-flex items-center gap-2 px-3.5 py-2 rounded-lg border border-blue-300 dark:border-blue-700 text-blue-600 dark:text-blue-400 text-sm hover:bg-blue-50 dark:hover:bg-blue-900/20 disabled:opacity-50"
          >
            {importing ? <Loader2 className="h-4 w-4 animate-spin" /> : <Upload className="h-4 w-4" />}
            Import Fields
          </button>
          {(template?.fields || []).length > 0 && (
            <button
              onClick={handleDeleteAllFields}
              className="inline-flex items-center gap-2 px-3.5 py-2 rounded-lg border border-red-300 dark:border-red-700 text-red-600 dark:text-red-400 text-sm hover:bg-red-50 dark:hover:bg-red-900/20"
            >
              <Trash2 className="h-4 w-4" />
              Delete All Fields
            </button>
          )}
          <button
            onClick={handleBuildAnalyzer}
            disabled={buildingAnalyzer || (template?.fields || []).length === 0}
            className="inline-flex items-center gap-2 px-3.5 py-2 rounded-lg bg-navy-800 text-white text-sm font-medium disabled:opacity-50"
          >
            {buildingAnalyzer ? <Loader2 className="h-4 w-4 animate-spin" /> : <Bot className="h-4 w-4" />}
            Build Analyzer
          </button>
        </div>
      </div>

      {/* ── Template Info Panel ── */}
      <div className="rounded-xl border border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900 p-4">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {/* Created by */}
          <div className="flex items-start gap-2.5">
            <div className="p-1.5 rounded-md bg-blue-50 dark:bg-blue-900/30">
              <User className="h-3.5 w-3.5 text-blue-600 dark:text-blue-400" />
            </div>
            <div>
              <p className="text-xs text-gray-500 dark:text-gray-400">Created by</p>
              <p className="text-sm font-medium text-gray-900 dark:text-gray-100 mt-0.5">
                {template.created_by_name || 'Unknown'}
              </p>
            </div>
          </div>

          {/* Created date */}
          <div className="flex items-start gap-2.5">
            <div className="p-1.5 rounded-md bg-green-50 dark:bg-green-900/30">
              <Calendar className="h-3.5 w-3.5 text-green-600 dark:text-green-400" />
            </div>
            <div>
              <p className="text-xs text-gray-500 dark:text-gray-400">Created</p>
              <p className="text-sm font-medium text-gray-900 dark:text-gray-100 mt-0.5">
                {template.created_at
                  ? formatDate(template.created_at)
                  : '—'}
              </p>
            </div>
          </div>

          {/* Last updated */}
          <div className="flex items-start gap-2.5">
            <div className="p-1.5 rounded-md bg-amber-50 dark:bg-amber-900/30">
              <Clock className="h-3.5 w-3.5 text-amber-600 dark:text-amber-400" />
            </div>
            <div>
              <p className="text-xs text-gray-500 dark:text-gray-400">Last updated</p>
              <p className="text-sm font-medium text-gray-900 dark:text-gray-100 mt-0.5">
                {template.updated_at
                  ? formatDate(template.updated_at)
                  : '—'}
                {template.modified_by_name && (
                  <span className="text-xs text-gray-400 dark:text-gray-500 ml-1">by {template.modified_by_name}</span>
                )}
              </p>
            </div>
          </div>

          {/* Creation method */}
          <div className="flex items-start gap-2.5">
            <div className="p-1.5 rounded-md bg-purple-50 dark:bg-purple-900/30">
              <Sparkles className="h-3.5 w-3.5 text-purple-600 dark:text-purple-400" />
            </div>
            <div>
              <p className="text-xs text-gray-500 dark:text-gray-400">Method</p>
              <p className="text-sm font-medium text-gray-900 dark:text-gray-100 mt-0.5">
                {{
                  ai_suggest:  'AI Suggested',
                  plugin_auto: 'Plugin (Auto-created)',
                  json_import: 'Imported from JSON',
                  manual:      'Created Manually',
                }[template.creation_method] || template.creation_method || 'Created Manually'}
              </p>
            </div>
          </div>
        </div>

        {/* Source documents — prominent display */}
        {(() => {
          let docs = []
          try {
            if (template.source_documents) {
              const parsed = JSON.parse(template.source_documents)
              if (Array.isArray(parsed)) docs = parsed
            }
          } catch { /* ignore */ }

          return (
            <div className="mt-3 pt-3 border-t border-gray-100 dark:border-gray-800">
              <div className="flex items-center gap-2 mb-2">
                <FileText className="h-3.5 w-3.5 text-blue-500 dark:text-blue-400" />
                <p className="text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wide">
                  Source Documents
                </p>
              </div>
              {docs.length > 0 ? (
                <div className="flex flex-wrap gap-1.5">
                  {docs.map((doc, i) => (
                    <span
                      key={i}
                      className="inline-flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg bg-blue-50 dark:bg-blue-900/25 text-sm font-medium text-blue-700 dark:text-blue-300 border border-blue-200 dark:border-blue-800/50"
                    >
                      <FileText className="h-3.5 w-3.5 shrink-0" />
                      {doc}
                    </span>
                  ))}
                </div>
              ) : (
                <p className="text-sm text-gray-400 dark:text-gray-500 italic">No source documents — template was created manually</p>
              )}
            </div>
          )
        })()}

        {/* Prompt used */}
        {template.creation_prompt && (
          <div className="mt-3 pt-3 border-t border-gray-100 dark:border-gray-800">
            <div className="flex items-center gap-2 mb-1.5">
              <MessageSquare className="h-3.5 w-3.5 text-gray-400 dark:text-gray-500" />
              <p className="text-xs font-medium text-gray-500 dark:text-gray-400">AI Prompt Used</p>
            </div>
            <p className="text-sm text-gray-600 dark:text-gray-400 italic">"{template.creation_prompt}"</p>
          </div>
        )}
      </div>

      {/* Rebuild reminder banner */}
      {fieldsDirty && (
        <div className="rounded-lg border border-amber-200 dark:border-amber-800/40 bg-amber-50 dark:bg-amber-900/20 px-4 py-3 flex items-center justify-between gap-3">
          <div className="flex items-center gap-2.5">
            <AlertCircle className="h-4 w-4 text-amber-600 dark:text-amber-400 flex-shrink-0" />
            <p className="text-sm text-amber-800 dark:text-amber-200">
              Fields have changed — <span className="font-semibold">rebuild the analyzer</span> for changes to take effect in extractions.
            </p>
          </div>
          <button
            onClick={handleBuildAnalyzer}
            disabled={buildingAnalyzer || (template?.fields || []).length === 0}
            className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-amber-600 hover:bg-amber-700 text-white text-xs font-medium whitespace-nowrap disabled:opacity-50"
          >
            {buildingAnalyzer ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Bot className="h-3.5 w-3.5" />}
            Rebuild Now
          </button>
        </div>
      )}

      {/* ===== AI SUGGEST PANEL ===== */}
      {showAiSuggest && (
        <div className="rounded-xl border-2 border-purple-200 dark:border-purple-800/50 bg-gradient-to-b from-purple-50 to-white dark:from-purple-900/10 dark:to-gray-900 p-5 space-y-4">
          <div className="flex items-center gap-2">
            <Sparkles className="h-5 w-5 text-purple-600 dark:text-purple-400" />
            <h3 className="text-base font-semibold text-gray-900 dark:text-gray-100">AI Field Suggestion</h3>
            <span className="text-xs text-gray-400 dark:text-gray-500 ml-2">Upload sample PDFs → AI generates template fields</span>
          </div>

          {/* Point 3: Disclaimer about uploading same-type documents */}
          <div className="flex items-start gap-2.5 rounded-lg border border-blue-200 dark:border-blue-800/40 bg-blue-50 dark:bg-blue-900/20 px-4 py-3">
            <Info className="h-4 w-4 text-blue-500 dark:text-blue-400 flex-shrink-0 mt-0.5" />
            <p className="text-xs text-blue-700 dark:text-blue-300">
              Upload up to <strong>5 documents of the same type</strong> (e.g., all insurance policies, all prospectuses).
              The AI will analyze them together to discover the most comprehensive set of extractable fields.
              Mixing different document types may produce inaccurate results.
            </p>
          </div>

          {!aiResult ? (
            /* STEP 1: Upload + Prompt */
            <div className="space-y-3">
              {/* Dropzone */}
              <div
                onDragOver={e => e.preventDefault()}
                onDrop={handleAiFileDrop}
                onClick={() => fileInputRef.current?.click()}
                className={`border-2 border-dashed rounded-lg p-6 text-center cursor-pointer transition-colors ${
                  aiFiles.length > 0
                    ? 'border-purple-400 bg-purple-50 dark:bg-purple-900/20 dark:border-purple-600'
                    : 'border-gray-300 dark:border-gray-700 hover:border-purple-400 dark:hover:border-purple-600 hover:bg-purple-50/50 dark:hover:bg-purple-900/10'
                }`}
              >
                <input
                  ref={fileInputRef}
                  type="file"
                  accept=".pdf"
                  multiple
                  onChange={handleAiFileSelect}
                  className="hidden"
                />
                {aiFiles.length > 0 ? (
                  <div className="space-y-2">
                    {aiFiles.map((file, idx) => (
                      <div key={`${file.name}-${idx}`} className="flex items-center justify-center gap-3">
                        <FileText className="h-5 w-5 text-purple-500 flex-shrink-0" />
                        <div className="text-left flex-1 min-w-0">
                          <p className="text-sm font-medium text-gray-900 dark:text-gray-100 truncate">{file.name}</p>
                          <p className="text-xs text-gray-500">{(file.size / 1024 / 1024).toFixed(2)} MB</p>
                        </div>
                        <button
                          onClick={e => { e.stopPropagation(); setAiFiles(prev => prev.filter((_, i) => i !== idx)); setAiResult(null) }}
                          className="p-1 rounded hover:bg-gray-200 dark:hover:bg-gray-700 flex-shrink-0"
                        >
                          <X className="h-4 w-4 text-gray-400" />
                        </button>
                      </div>
                    ))}
                    {aiFiles.length < 5 && (
                      <p className="text-xs text-purple-500 dark:text-purple-400 mt-2">
                        + Drop or click to add more ({5 - aiFiles.length} remaining)
                      </p>
                    )}
                  </div>
                ) : (
                  <>
                    <Upload className="h-8 w-8 text-gray-400 mx-auto mb-2" />
                    <p className="text-sm text-gray-600 dark:text-gray-400">
                      Drop sample PDFs here or <span className="text-purple-600 dark:text-purple-400 font-medium">browse</span>
                    </p>
                    <p className="text-xs text-gray-400 mt-1">Upload up to 5 PDFs — the AI will analyze them and suggest extractable fields</p>
                  </>
                )}
              </div>

              {/* Optional prompt */}
              <div>
                <label className="flex items-center gap-1.5 text-xs font-medium text-gray-500 dark:text-gray-400 mb-1.5">
                  <MessageSquare className="h-3 w-3" />
                  Optional: Tell the AI what fields you're looking for
                </label>
                <textarea
                  rows={2}
                  value={aiPrompt}
                  onChange={e => setAiPrompt(e.target.value)}
                  className="w-full px-3 py-2 rounded-lg border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm"
                  placeholder="e.g., I need all financial fields like coupon rate, issue size, ISIN, maturity dates, and risk metrics..."
                />
              </div>

              {/* Suggest button */}
              <button
                onClick={handleAiSuggest}
                disabled={aiFiles.length === 0 || aiSuggesting}
                className="w-full inline-flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg bg-gradient-to-r from-purple-600 to-indigo-600 text-white text-sm font-medium disabled:opacity-50 hover:from-purple-700 hover:to-indigo-700 transition-all"
              >
                {aiSuggesting ? (
                  <>
                    <Loader2 className="h-4 w-4 animate-spin" />
                    Analyzing document... (this may take 30-60 seconds)
                  </>
                ) : (
                  <>
                    <Sparkles className="h-4 w-4" />
                    Suggest Fields
                  </>
                )}
              </button>
            </div>
          ) : (
            /* STEP 2: Review suggested fields */
            <div className="space-y-3">
              {/* Document info header */}
              <div className="flex items-start justify-between gap-4 bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-3">
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-gray-900 dark:text-gray-100">{aiResult.document_type}</p>
                  <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5 truncate">{aiResult.document_summary}</p>
                  <p className="text-xs text-gray-400 dark:text-gray-500 mt-1">
                    {aiResult.source_files?.join(', ') || aiResult.source_file} • {aiResult.pages_analyzed}/{aiResult.total_pages} pages analyzed • {aiResult.total_fields} fields suggested
                  </p>
                </div>
                <button
                  onClick={() => { setAiResult(null); setAiFiles([]) }}
                  className="text-xs text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 whitespace-nowrap"
                >
                  ← Try another
                </button>
              </div>

              {/* Select all / none */}
              <div className="flex items-center justify-between">
                <button
                  onClick={toggleSelectAll}
                  className="text-xs text-purple-600 dark:text-purple-400 hover:underline font-medium"
                >
                  {aiResult.fields?.every(f => aiSelected[f.field_name]) ? 'Deselect all' : 'Select all'}
                </button>
                <span className="text-xs text-gray-400">
                  {Object.values(aiSelected).filter(Boolean).length} of {aiResult.fields?.length} selected
                </span>
              </div>

              {/* Suggested fields table */}
              <div className="overflow-x-auto rounded-lg border border-gray-200 dark:border-gray-700 max-h-[28rem] overflow-y-auto">
                <table className="min-w-full text-sm">
                  <thead className="bg-gray-50 dark:bg-gray-800/60 sticky top-0">
                    <tr>
                      <th className="px-3 py-2 text-left w-8"></th>
                      <th className="px-3 py-2 text-left font-medium text-gray-500 dark:text-gray-400">Field</th>
                      <th className="px-3 py-2 text-left font-medium text-gray-500 dark:text-gray-400">Type</th>
                      <th className="px-3 py-2 text-left font-medium text-gray-500 dark:text-gray-400">Category</th>
                      <th className="px-3 py-2 text-left font-medium text-gray-500 dark:text-gray-400">Sample Value</th>
                      <th className="px-3 py-2 text-left font-medium text-gray-500 dark:text-gray-400 w-8">Conf</th>
                    </tr>
                  </thead>
                  <tbody>
                    {(aiResult.fields || []).map((field, idx) => {
                      const selected = !!aiSelected[field.field_name]
                      const existingNames = new Set((template?.fields || []).map(f => f.field_name))
                      const isDuplicate = existingNames.has(field.field_name)
                      return (
                        <tr
                          key={field.field_name}
                          onClick={() => !isDuplicate && setAiSelected(prev => ({ ...prev, [field.field_name]: !prev[field.field_name] }))}
                          className={`border-t border-gray-100 dark:border-gray-800 cursor-pointer transition-colors ${
                            isDuplicate
                              ? 'opacity-40 cursor-not-allowed'
                              : selected
                              ? 'bg-purple-50 dark:bg-purple-900/10'
                              : 'hover:bg-gray-50 dark:hover:bg-gray-800/50'
                          }`}
                          title={isDuplicate ? 'Already exists in template' : field.description}
                        >
                          <td className="px-3 py-2">
                            <div className={`w-4 h-4 rounded border-2 flex items-center justify-center transition-colors ${
                              isDuplicate
                                ? 'border-gray-300 bg-gray-100 dark:border-gray-600 dark:bg-gray-700'
                                : selected
                                ? 'border-purple-500 bg-purple-500'
                                : 'border-gray-300 dark:border-gray-600'
                            }`}>
                              {(selected && !isDuplicate) && <Check className="h-3 w-3 text-white" />}
                              {isDuplicate && <span className="text-[9px] text-gray-400">✓</span>}
                            </div>
                          </td>
                          <td className="px-3 py-2">
                            <p className="font-medium text-gray-900 dark:text-gray-100 text-xs">{field.display_name}</p>
                            <p className="text-[10px] text-gray-400 font-mono">{field.field_name}</p>
                          </td>
                          <td className="px-3 py-2">
                            <span className={`inline-flex px-1.5 py-0.5 rounded text-[10px] font-medium ${
                              field.field_type === 'date' ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300' :
                              field.field_type === 'number' || field.field_type === 'currency' ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-300' :
                              field.field_type === 'percentage' ? 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300' :
                              'bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-300'
                            }`}>
                              {field.field_type}
                            </span>
                          </td>
                          <td className="px-3 py-2 text-xs text-gray-500 dark:text-gray-400">{field.category}</td>
                          <td className="px-3 py-2 text-xs text-gray-600 dark:text-gray-300 max-w-[200px] truncate font-mono">
                            {field.sample_value || <span className="text-gray-300 dark:text-gray-600 italic">—</span>}
                          </td>
                          <td className="px-3 py-2 text-xs text-gray-400">{field.confidence ? `${Math.round(field.confidence * 100)}%` : ''}</td>
                        </tr>
                      )
                    })}
                  </tbody>
                </table>
              </div>

              {/* Notes */}
              {aiResult.notes && (
                <p className="text-xs text-gray-400 dark:text-gray-500 italic">{aiResult.notes}</p>
              )}

              {/* Accept button */}
              <div className="flex items-center gap-3">
                <button
                  onClick={handleAcceptSuggested}
                  disabled={aiSaving || Object.values(aiSelected).filter(Boolean).length === 0}
                  className="flex-1 inline-flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg bg-gradient-to-r from-purple-600 to-indigo-600 text-white text-sm font-medium disabled:opacity-50 hover:from-purple-700 hover:to-indigo-700"
                >
                  {aiSaving ? (
                    <>
                      <Loader2 className="h-4 w-4 animate-spin" />
                      Adding {Object.values(aiSelected).filter(Boolean).length} fields...
                    </>
                  ) : (
                    <>
                      <Check className="h-4 w-4" />
                      Accept {Object.values(aiSelected).filter(Boolean).length} Selected Fields
                    </>
                  )}
                </button>
                <button
                  onClick={() => { setAiResult(null); setAiFiles([]) }}
                  className="px-4 py-2.5 rounded-lg border border-gray-300 dark:border-gray-700 text-sm"
                >
                  Discard
                </button>
              </div>
            </div>
          )}
        </div>
      )}
      {/* ===== END AI SUGGEST PANEL ===== */}

      {/* Analyzer status inline bar */}
      <div className="rounded-lg border border-gray-200 dark:border-gray-800 bg-gray-50 dark:bg-gray-900/50 px-4 py-3 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1.5 text-sm">
            <span className="text-gray-500 dark:text-gray-400">Analyzer:</span>
            {template?.analyzer?.is_active ? (
              <span className="inline-flex items-center gap-1 text-emerald-700 dark:text-emerald-300 font-medium">
                <CheckCircle2 className="h-3.5 w-3.5" />
                Ready
              </span>
            ) : (
              <span className="inline-flex items-center gap-1 text-amber-700 dark:text-amber-300 font-medium">
                <AlertCircle className="h-3.5 w-3.5" />
                Not built
              </span>
            )}
          </div>
          {template?.analyzer?.azure_analyzer_id && (
            <span className="text-xs font-mono text-gray-400 dark:text-gray-500 hidden sm:inline">
              {template.analyzer.azure_analyzer_id}
            </span>
          )}
        </div>
        <span className="text-xs text-gray-400 dark:text-gray-500">{(template?.fields || []).length} fields</span>
      </div>
      <div className="rounded-xl border border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900 p-5">
        <h2 className="text-base font-semibold text-gray-900 dark:text-gray-100 mb-4">Fields</h2>

        {(template?.fields || []).length === 0 ? (
          <div className="text-center py-10">
            <p className="text-sm text-gray-500 dark:text-gray-400">No fields yet. Add your first field to start building the analyzer.</p>
          </div>
        ) : (
          <div className="space-y-5">
            {Object.entries(groupedFields).map(([categoryKey, group]) => (
              <div key={categoryKey}>
                <p className="text-xs font-semibold uppercase tracking-wide text-gray-500 dark:text-gray-400 mb-2">
                  {group.displayName}
                </p>
                <div className="overflow-x-auto rounded-lg border border-gray-200 dark:border-gray-800">
                  <table className="min-w-full text-sm">
                    <thead className="bg-gray-50 dark:bg-gray-800/60">
                      <tr>
                        <th className="px-3 py-2 text-left font-medium text-gray-500 dark:text-gray-400">Display</th>
                        <th className="px-3 py-2 text-left font-medium text-gray-500 dark:text-gray-400">Field Name</th>
                        <th className="px-3 py-2 text-left font-medium text-gray-500 dark:text-gray-400">Type</th>
                        <th className="px-3 py-2 text-left font-medium text-gray-500 dark:text-gray-400">Description</th>
                        <th className="px-3 py-2 text-right font-medium text-gray-500 dark:text-gray-400">Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {group.fields.map(field => (
                        <tr key={field.id} className="border-t border-gray-100 dark:border-gray-800">
                          <td className="px-3 py-2 text-gray-900 dark:text-gray-100">{field.display_name}</td>
                          <td className="px-3 py-2 font-mono text-xs text-gray-700 dark:text-gray-300">{field.field_name}</td>
                          <td className="px-3 py-2 text-gray-700 dark:text-gray-300">{field.field_type}</td>
                          <td className="px-3 py-2 text-gray-600 dark:text-gray-400 max-w-xl">{field.description || '-'}</td>
                          <td className="px-3 py-2">
                            <div className="flex items-center justify-end gap-1">
                              <button
                                onClick={() => {
                                  setEditingField(field)
                                  setFieldModalOpen(true)
                                }}
                                className="p-1.5 rounded hover:bg-gray-100 dark:hover:bg-gray-800"
                                title="Edit"
                              >
                                <Pencil className="h-4 w-4 text-gray-500" />
                              </button>
                              <button
                                onClick={() => handleDeleteField(field.id)}
                                className="p-1.5 rounded hover:bg-red-50 dark:hover:bg-red-900/20"
                                title="Delete"
                              >
                                <Trash2 className="h-4 w-4 text-red-500" />
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <FieldModal
        open={fieldModalOpen}
        onClose={() => {
          setFieldModalOpen(false)
          setEditingField(null)
        }}
        onSave={handleSaveField}
        categories={templateCategories}
        initialField={editingField}
        saving={savingField}
      />

      {/* Build Analyzer Reminder Modal — triggered by ANY navigation when fields are dirty */}
      {navBlocked && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          <div className="absolute inset-0 bg-navy-900/60 backdrop-blur-sm" onClick={() => { setNavBlocked(false); setPendingNavPath(null) }} />
          <div className="relative bg-white dark:bg-gray-900 rounded-xl shadow-2xl border border-gray-200 dark:border-gray-700 p-6 max-w-md w-full mx-4">
            <div className="flex items-center gap-3 mb-3">
              <div className="w-10 h-10 bg-amber-100 dark:bg-amber-900/30 rounded-full flex items-center justify-center">
                <AlertCircle className="h-5 w-5 text-amber-600 dark:text-amber-400" />
              </div>
              <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-100">Analyzer Not Rebuilt</h3>
            </div>
            <p className="text-sm text-gray-600 dark:text-gray-400 mb-1">
              You've made changes to the template fields but haven't rebuilt the analyzer.
            </p>
            <p className="text-sm text-gray-600 dark:text-gray-400 mb-5">
              Without rebuilding, your changes <span className="font-semibold text-gray-900 dark:text-gray-100">won't take effect</span> during extraction.
            </p>
            <div className="flex items-center justify-end gap-2.5">
              <button
                onClick={() => {
                  setNavBlocked(false)
                  const path = pendingNavPath
                  setPendingNavPath(null)
                  if (path) navigate(path)
                }}
                className="px-4 py-2 rounded-lg border border-gray-300 dark:border-gray-700 text-sm text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-800"
              >
                Leave Anyway
              </button>
              <button
                onClick={async () => {
                  setNavBlocked(false)
                  setPendingNavPath(null)
                  await handleBuildAnalyzer()
                }}
                disabled={buildingAnalyzer || (template?.fields || []).length === 0}
                className="inline-flex items-center gap-2 px-4 py-2 rounded-lg bg-navy-800 text-white text-sm font-medium disabled:opacity-50"
              >
                <Bot className="h-4 w-4" />
                Build Analyzer Now
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}
