import React, { useState, useEffect } from 'react'
import { Link, useSearchParams } from 'react-router-dom'
import { documentsApi } from '../services/api'
import { formatDate } from '../utils/dateUtils'
import {
  Search,
  Filter,
  ChevronLeft,
  ChevronRight,
  FileText,
  RefreshCw,
  AlertCircle,
  File
} from 'lucide-react'

function Documents() {
  const [searchParams, setSearchParams] = useSearchParams()
  const [documents, setDocuments] = useState([])
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0 })
  const [perPage, setPerPage] = useState(10)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  
  const page = parseInt(searchParams.get('page') || '1')
  const source = searchParams.get('source') || ''
  const search = searchParams.get('search') || ''
  
  const fetchDocuments = async () => {
    try {
      setLoading(true)
      const res = await documentsApi.list({
        page,
        per_page: perPage,
        source: source || undefined,
        search: search || undefined,
      })
      setDocuments(res.data.documents || [])
      setPagination(res.data.pagination || { page: 1, pages: 1, total: 0 })
      setError(null)
    } catch (err) {
      console.error('Error fetching documents:', err)
      setError('Failed to load documents')
    } finally {
      setLoading(false)
    }
  }
  
  useEffect(() => {
    fetchDocuments()
  }, [page, source, search, perPage])
  
  const handleSearch = (e) => {
    e.preventDefault()
    const formData = new FormData(e.target)
    const searchValue = formData.get('search')
    setSearchParams({
      ...Object.fromEntries(searchParams),
      search: searchValue,
      page: '1',
    })
  }
  
  const handleSearchChange = (e) => {
    const value = e.target.value
    if (value === '') {
      setSearchParams(prev => {
        const params = Object.fromEntries(prev)
        delete params.search
        return { ...params, page: '1' }
      })
    }
  }
  
  const handleSourceFilter = (newSource) => {
    setSearchParams({
      ...Object.fromEntries(searchParams),
      source: newSource,
      page: '1',
    })
  }
  
  const handlePageChange = (newPage) => {
    setSearchParams({
      ...Object.fromEntries(searchParams),
      page: newPage.toString(),
    })
  }
  
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-gray-100">Documents</h1>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">Manage uploaded and processed documents</p>
        </div>
      </div>
      
      {/* Filters */}
      <div className="card">
        <div className="card-body flex flex-col md:flex-row md:items-center gap-4">
          <form onSubmit={handleSearch} className="flex-1">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400 pointer-events-none z-10" />
              <input
                type="text"
                name="search"
                placeholder="Search documents..."
                key={search}
                defaultValue={search}
                onChange={handleSearchChange}
                className="form-input w-full"
                style={{ paddingLeft: '2.5rem' }}
              />
            </div>
          </form>
          
          <div className="flex items-center gap-2">
            <Filter className="h-5 w-5 text-gray-400" />
            <select
              value={source}
              onChange={(e) => handleSourceFilter(e.target.value)}
              className="form-select"
            >
              <option value="">All Status</option>
              <option value="uploaded">Uploaded</option>
              <option value="analyzed">Analyzed</option>
              <option value="failed">Failed</option>
            </select>
          </div>
          
          <button onClick={fetchDocuments} disabled={loading} className="btn btn-secondary disabled:opacity-50 disabled:cursor-not-allowed" aria-label="Refresh documents">
            <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
          </button>
        </div>
      </div>
      
      {/* Error */}
      {error && (
        <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-4 flex items-center">
          <AlertCircle className="h-5 w-5 text-red-500 dark:text-red-400 mr-2" />
          <span className="text-red-700 dark:text-red-300">{error}</span>
        </div>
      )}
      
      {/* Table */}
      <div className="card overflow-hidden">
        {loading ? (
          <div className="overflow-x-auto">
            <table className="table">
              <thead>
                <tr className="sticky top-0 z-10">
                  <th>Filename</th>
                  <th>Type</th>
                  <th>Size</th>
                  <th>Uploaded</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {[...Array(5)].map((_, i) => (
                  <tr key={i} className="animate-pulse">
                    <td><div className="flex items-center gap-2"><div className="h-5 w-5 bg-gray-200 dark:bg-gray-700 rounded"></div><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-40"></div></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-28"></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-16"></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-24"></div></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : documents.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-gray-500">
            <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
              <File className="h-8 w-8 text-gray-400 dark:text-gray-500" />
            </div>
            <p className="font-medium text-gray-900 dark:text-gray-100">No documents found</p>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">No uploaded documents available yet</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="table">
              <thead>
                <tr className="sticky top-0 z-10">
                  <th>Filename</th>
                  <th>Type</th>
                  <th>Size</th>
                  <th>Uploaded</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {documents.map((doc) => (
                    <tr key={doc.id}>
                      <td>
                        <Link
                          to={`/documents/${doc.id}`}
                          className="flex items-center text-primary-600 hover:underline"
                        >
                          <FileIcon mimeType={doc.content_type} />
                          <span className="ml-2 font-medium">{doc.filename}</span>
                        </Link>
                      </td>
                      <td className="text-gray-600 dark:text-gray-400">{doc.content_type || '-'}</td>
                      <td className="text-gray-600 dark:text-gray-400">{formatFileSize(doc.file_size_bytes)}</td>
                      <td className="text-gray-500 text-sm">
                        {formatDate(doc.created_at)}
                      </td>
                    </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        
        {/* Pagination */}
        {(() => {
          const totalPages = Math.ceil(pagination.total / perPage)
          return (
            <div className="px-5 py-4 border-t border-gray-100 dark:border-gray-800 flex items-center justify-between">
              <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400">
                <span>
                  {pagination.total === 0
                    ? 'No results'
                    : `Showing ${(page - 1) * perPage + 1}\u2013${Math.min(page * perPage, pagination.total)} of ${pagination.total} result${pagination.total !== 1 ? 's' : ''}`}
                </span>
                <span className="border-l border-gray-200 dark:border-gray-700 h-4" />
                <span className="flex items-center gap-1.5">
                  Rows per page
                  <select
                    value={perPage}
                    onChange={(e) => {
                      setPerPage(Number(e.target.value))
                      handlePageChange(1)
                    }}
                    className="px-2 py-1 border border-gray-200 dark:border-gray-700 rounded text-sm dark:bg-gray-800 dark:text-gray-200"
                  >
                    <option value={10}>10</option>
                    <option value={25}>25</option>
                    <option value={50}>50</option>
                  </select>
                </span>
              </div>
              {totalPages > 1 && (
                <div className="flex items-center gap-1">
                  <button
                    onClick={() => handlePageChange(page - 1)}
                    disabled={page <= 1}
                    className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <ChevronLeft className="h-4 w-4" />
                    Previous
                  </button>
                  {generatePageNumbers(page, totalPages).map((pg, i) => (
                    <React.Fragment key={i}>
                      {pg === '...' ? (
                        <span className="px-2 text-gray-400 dark:text-gray-500">...</span>
                      ) : (
                        <button
                          onClick={() => handlePageChange(pg)}
                          className={`w-8 h-8 rounded text-sm font-medium ${
                            page === pg
                              ? 'bg-navy-800 text-white'
                              : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800'
                          }`}
                        >
                          {pg}
                        </button>
                      )}
                    </React.Fragment>
                  ))}
                  <button
                    onClick={() => handlePageChange(page + 1)}
                    disabled={page >= totalPages}
                    className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    Next
                    <ChevronRight className="h-4 w-4" />
                  </button>
                </div>
              )}
            </div>
          )
        })()}
      </div>
    </div>
  )
}

function FileIcon({ mimeType }) {
  const isPdf = mimeType?.includes('pdf')
  const isImage = mimeType?.includes('image')
  const isDoc = mimeType?.includes('word') || mimeType?.includes('document')
  const isSpreadsheet = mimeType?.includes('sheet') || mimeType?.includes('excel')
  
  let color = 'text-gray-400'
  if (isPdf) color = 'text-red-500'
  else if (isImage) color = 'text-green-500'
  else if (isDoc) color = 'text-blue-500'
  else if (isSpreadsheet) color = 'text-green-600'
  
  return <FileText className={`h-5 w-5 ${color}`} />
}

function StatusBadge({ status, displayName }) {
  return (
    <span className={`status-badge status-${status}`}>
      {displayName || status?.replace(/_/g, ' ')}
    </span>
  )
}

function formatFileSize(bytes) {
  if (!bytes) return '0 B'
  const k = 1024
  const sizes = ['B', 'KB', 'MB', 'GB']
  const i = Math.floor(Math.log(bytes) / Math.log(k))
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i]
}

function generatePageNumbers(current, total) {
  if (total <= 7) {
    return Array.from({ length: total }, (_, i) => i + 1)
  }
  if (current <= 3) {
    return [1, 2, 3, '...', total]
  }
  if (current >= total - 2) {
    return [1, '...', total - 2, total - 1, total]
  }
  return [1, '...', current - 1, current, current + 1, '...', total]
}

export default Documents
