import React, { useEffect } from 'react'
import { Routes, Route, Navigate, useNavigate, useLocation } from 'react-router-dom'
import { useAuth } from './context/AuthContext'
import { useToast } from './context/ToastContext'
import { setAccessToken } from './services/api'
import Layout from './components/Layout'
import Login from './pages/Login'
import MarketplaceLanding from './pages/MarketplaceLanding'
import PrivacyPolicy from './pages/PrivacyPolicy'
import Dashboard from './pages/Dashboard'
import Requests from './pages/Requests'
import RequestDetail from './pages/RequestDetail'
import Emails from './pages/Emails'
import EmailDetail from './pages/EmailDetail'
import Documents from './pages/Documents'
import DocumentDetail from './pages/DocumentDetail'
import Jobs from './pages/Jobs'
import Activity from './pages/Activity'
import Issuers from './pages/Issuers'
import Templates from './pages/Templates'
import TemplateDetail from './pages/TemplateDetail'
import TestAnalysis from './pages/TestAnalysis'
import Settings from './pages/Settings'

function PrivateRoute({ children }) {
  const { isAuthenticated, isLoading, accessToken } = useAuth()
  const location = useLocation()
  
  // While MSAL is processing a redirect, show a spinner
  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-gray-950">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600 mx-auto mb-4"></div>
          <p className="text-gray-600 dark:text-gray-400">Authenticating...</p>
        </div>
      </div>
    )
  }
  
  // Not authenticated — save intended destination, then redirect to login
  if (!isAuthenticated || !accessToken) {
    const intendedPath = location.pathname + location.search + location.hash
    // Persist in localStorage so it survives the MSAL redirect round-trip
    if (intendedPath && intendedPath !== '/' && intendedPath !== '/login') {
      localStorage.setItem('xtract_return_url', intendedPath)
    }
    return <Navigate to="/login" state={{ from: intendedPath }} replace />
  }
  
  return children
}

/**
 * LoginRedirector — after successful login, redirect to the intended page
 * (saved before the MSAL redirect round-trip) instead of always going to /.
 */
function LoginRedirector() {
  const location = useLocation()

  // Check route state first (if login happened without full page reload),
  // then fall back to localStorage (survives the MSAL redirect round-trip).
  const from = location.state?.from
  const savedUrl = localStorage.getItem('xtract_return_url')
  const returnTo = from || savedUrl || '/'

  // Clean up — don't want stale return URLs
  localStorage.removeItem('xtract_return_url')

  return <Navigate to={returnTo} replace />
}

function App() {
  const { accessToken, sessionExpired, clearSessionExpired, isAuthenticated } = useAuth()
  const toast = useToast()
  const navigate = useNavigate()
  
  // Sync access token from auth context → API layer (including clearing on logout)
  useEffect(() => {
    setAccessToken(accessToken || null)
  }, [accessToken])

  // When session expires (401 from backend), show a toast and redirect to login
  useEffect(() => {
    if (sessionExpired) {
      toast.warning('Session Expired', 'Your session has expired. Please sign in again.')
      clearSessionExpired()
      navigate('/login', { replace: true })
    }
  }, [sessionExpired, clearSessionExpired, navigate, toast])
  
  return (
    <Routes>
      {/* Public routes (no auth required) */}
      <Route path="/login" element={
        isAuthenticated && accessToken
          ? <LoginRedirector />
          : <Login />
      } />
      <Route path="/marketplace/landing" element={<MarketplaceLanding />} />
      <Route path="/privacy" element={<PrivacyPolicy />} />

      {/* Protected routes with Layout wrapper */}
      <Route path="/" element={
        <PrivateRoute>
          <Layout />
        </PrivateRoute>
      }>
        <Route index element={<Dashboard />} />
        <Route path="requests" element={<Requests />} />
        <Route path="requests/:id" element={<RequestDetail />} />
        <Route path="activity" element={<Activity />} />
        <Route path="issuers" element={<Issuers />} />
        <Route path="templates" element={<Templates />} />
        <Route path="templates/:id" element={<TemplateDetail />} />
        <Route path="emails" element={<Emails />} />
        <Route path="emails/:id" element={<EmailDetail />} />
        <Route path="documents" element={<Documents />} />
        <Route path="documents/:id" element={<DocumentDetail />} />
        <Route path="jobs" element={<Jobs />} />
        <Route path="test-analysis" element={<TestAnalysis />} />
        <Route path="settings" element={<Settings />} />
      </Route>
      
      <Route path="*" element={<Navigate to="/" />} />
    </Routes>
  )
}

export default App
