import React, { useState, useEffect, useCallback } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { dashboardApi } from '../services/api'
import { formatTimeAgo as formatTimeAgoUtil, formatDateTime, getDateGroupLabel as getDateGroupLabelUtil } from '../utils/dateUtils'
import {
  Search,
  Filter,
  ChevronLeft,
  ChevronRight,
  Check,
  AlertCircle,
  Upload,
  Cpu,
  Edit3,
  Plus,
  Activity as ActivityIcon,
  ArrowLeft,
  RefreshCw,
} from 'lucide-react'

const TYPE_OPTIONS = [
  { value: 'all', label: 'All Activity' },
  { value: 'publish', label: 'Published' },
  { value: 'cancel', label: 'Cancelled' },
  { value: 'upload', label: 'Uploads' },
  { value: 'extraction', label: 'Extractions' },
  { value: 'edit', label: 'Edits' },
  { value: 'new_request', label: 'New Requests' },
]

const getActivityMeta = (type) => {
  switch (type) {
    case 'publish':
      return { icon: <Check className="h-4 w-4 text-green-600 dark:text-green-400" />, iconBg: 'bg-green-100 dark:bg-green-900/30', label: 'Published', badgeColor: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300' }
    case 'cancel':
      return { icon: <AlertCircle className="h-4 w-4 text-red-600 dark:text-red-400" />, iconBg: 'bg-red-100 dark:bg-red-900/30', label: 'Cancelled', badgeColor: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300' }
    case 'upload':
      return { icon: <Upload className="h-4 w-4 text-blue-600 dark:text-blue-400" />, iconBg: 'bg-blue-100 dark:bg-blue-900/30', label: 'Upload', badgeColor: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300' }
    case 'extraction':
      return { icon: <Cpu className="h-4 w-4 text-purple-600 dark:text-purple-400" />, iconBg: 'bg-purple-100 dark:bg-purple-900/30', label: 'Extraction', badgeColor: 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300' }
    case 'edit':
      return { icon: <Edit3 className="h-4 w-4 text-orange-600 dark:text-orange-400" />, iconBg: 'bg-orange-100 dark:bg-orange-900/30', label: 'Edit', badgeColor: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-300' }
    case 'new_request':
      return { icon: <Plus className="h-4 w-4 text-navy-600 dark:text-navy-400" />, iconBg: 'bg-navy-100 dark:bg-navy-900/30', label: 'New Request', badgeColor: 'bg-navy-100 text-navy-700 dark:bg-navy-900/30 dark:text-navy-300' }
    default:
      return { icon: <ActivityIcon className="h-4 w-4 text-gray-600 dark:text-gray-400" />, iconBg: 'bg-gray-100 dark:bg-gray-700', label: 'Activity', badgeColor: 'bg-gray-100 text-gray-700 dark:bg-gray-700 dark:text-gray-300' }
  }
}

const formatTimeAgo = formatTimeAgoUtil

const formatDate = formatDateTime

const getDateGroupLabel = getDateGroupLabelUtil

export default function Activity() {
  const navigate = useNavigate()
  const [items, setItems] = useState([])
  const [loading, setLoading] = useState(true)
  const [page, setPage] = useState(1)
  const [totalPages, setTotalPages] = useState(1)
  const [total, setTotal] = useState(0)
  const [search, setSearch] = useState('')
  const [searchInput, setSearchInput] = useState('')
  const [typeFilter, setTypeFilter] = useState('all')
  const [perPage, setPerPage] = useState(10)

  const fetchActivity = useCallback(async () => {
    setLoading(true)
    try {
      const params = { page, page_size: perPage }
      if (search) params.search = search
      if (typeFilter !== 'all') params.type = typeFilter
      const res = await dashboardApi.getActivityPaginated(params)
      const data = res.data
      setItems(data.items || [])
      setTotal(data.total || 0)
      setTotalPages(data.total_pages || 1)
    } catch (err) {
      console.error('Failed to load activity:', err)
      setItems([])
    } finally {
      setLoading(false)
    }
  }, [page, search, typeFilter, perPage])

  useEffect(() => {
    fetchActivity()
  }, [fetchActivity])

  // Reset to page 1 on filter/search change
  const handleSearch = (e) => {
    e.preventDefault()
    setPage(1)
    setSearch(searchInput)
  }

  const handleTypeChange = (val) => {
    setTypeFilter(val)
    setPage(1)
  }

  const handleClearSearch = () => {
    setSearchInput('')
    setSearch('')
    setPage(1)
  }

  // Pagination helpers
  const getPageNumbers = () => {
    const pages = []
    const maxVisible = 7
    if (totalPages <= maxVisible) {
      for (let i = 1; i <= totalPages; i++) pages.push(i)
    } else {
      pages.push(1)
      if (page > 3) pages.push('...')
      const start = Math.max(2, page - 1)
      const end = Math.min(totalPages - 1, page + 1)
      for (let i = start; i <= end; i++) pages.push(i)
      if (page < totalPages - 2) pages.push('...')
      pages.push(totalPages)
    }
    return pages
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Link to="/" className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg text-gray-500 hover:text-gray-700 dark:hover:text-gray-300 transition-colors">
            <ArrowLeft className="h-5 w-5" />
          </Link>
          <div>
            <h1 className="text-2xl font-bold text-gray-900 dark:text-gray-100">Activity Log</h1>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">{total} total activities</p>
          </div>
        </div>
        <button
          onClick={fetchActivity}
          disabled={loading}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
          Refresh
        </button>
      </div>

      {/* Filters Bar */}
      <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 p-4">
        <div className="flex flex-col sm:flex-row gap-3">
          {/* Search */}
          <form onSubmit={handleSearch} className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
            <input
              type="text"
              placeholder="Search activities..."
              value={searchInput}
              onChange={(e) => setSearchInput(e.target.value)}
              className="w-full pl-10 pr-4 py-2 text-sm border border-gray-300 dark:border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-navy-500 focus:border-navy-500 dark:bg-gray-800 dark:text-gray-200"
            />
            {search && (
              <button
                type="button"
                onClick={handleClearSearch}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
              >
                ×
              </button>
            )}
          </form>

          {/* Type Filter */}
          <div className="flex items-center gap-2">
            <Filter className="h-4 w-4 text-gray-400" />
            <select
              value={typeFilter}
              onChange={(e) => handleTypeChange(e.target.value)}
              className="text-sm border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-navy-500 focus:border-navy-500 bg-white dark:bg-gray-800 dark:text-gray-200"
            >
              {TYPE_OPTIONS.map(opt => (
                <option key={opt.value} value={opt.value}>{opt.label}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Active filters summary */}
        {(search || typeFilter !== 'all') && (
          <div className="flex items-center gap-2 mt-3 pt-3 border-t border-gray-100 dark:border-gray-800">
            <span className="text-xs text-gray-500 dark:text-gray-400">Filters:</span>
            {search && (
              <span className="inline-flex items-center gap-1 px-2 py-0.5 text-xs font-medium bg-navy-50 text-navy-700 dark:bg-navy-900/30 dark:text-navy-300 rounded-full">
                Search: "{search}"
                <button onClick={handleClearSearch} className="hover:text-navy-900 dark:hover:text-navy-200">×</button>
              </span>
            )}
            {typeFilter !== 'all' && (
              <span className="inline-flex items-center gap-1 px-2 py-0.5 text-xs font-medium bg-navy-50 text-navy-700 dark:bg-navy-900/30 dark:text-navy-300 rounded-full">
                {TYPE_OPTIONS.find(o => o.value === typeFilter)?.label}
                <button onClick={() => handleTypeChange('all')} className="hover:text-navy-900 dark:hover:text-navy-200">×</button>
              </span>
            )}
          </div>
        )}
      </div>

      {/* Activity List */}
      <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden">
        {loading ? (
          <div className="divide-y divide-gray-100 dark:divide-gray-800">
            {[...Array(6)].map((_, i) => (
              <div key={i} className="px-5 py-4 flex items-start gap-4 animate-pulse">
                <div className="w-9 h-9 rounded-full bg-gray-200 dark:bg-gray-700 flex-shrink-0"></div>
                <div className="flex-1 min-w-0">
                  <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-64 mb-2"></div>
                  <div className="h-3 bg-gray-100 dark:bg-gray-800 rounded w-32"></div>
                </div>
                <div className="h-5 bg-gray-200 dark:bg-gray-700 rounded-full w-16"></div>
              </div>
            ))}
          </div>
        ) : items.length === 0 ? (
          <div className="py-16 text-center">
            <ActivityIcon className="h-10 w-10 text-gray-300 dark:text-gray-600 mx-auto mb-3" />
            <p className="text-sm text-gray-500 dark:text-gray-400">No activity found</p>
            {search && (
              <p className="text-xs text-gray-400 dark:text-gray-500 mt-1">Try adjusting your search or filters</p>
            )}
          </div>
        ) : (
          <div className="divide-y divide-gray-100 dark:divide-gray-800">
            {items.map((item, idx) => {
              const meta = getActivityMeta(item.type)
              // Date group header logic
              const dateLabel = getDateGroupLabel(item.time)
              const prevDateLabel = idx > 0 ? getDateGroupLabel(items[idx - 1].time) : null
              const showDateHeader = dateLabel !== prevDateLabel
              
              // Determine link target based on activity type
              const getLink = () => {
                if (item.entity_id) {
                  if (item.type === 'upload') return `/documents/${item.entity_id}`
                  return `/requests/${item.entity_id}`
                }
                return null
              }
              const link = getLink()
              
              return (
                <React.Fragment key={`${item.type}-${item.entity_id}-${idx}`}>
                  {showDateHeader && (
                    <div className="px-5 py-2 bg-gray-50 dark:bg-gray-800/50">
                      <span className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{dateLabel}</span>
                    </div>
                  )}
                  <div
                    className={`px-5 py-4 flex items-start gap-4 hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors ${link ? 'cursor-pointer clickable-row' : ''}`}
                    onClick={link ? () => navigate(link) : undefined}
                  >
                  {/* Icon */}
                  <div className={`w-9 h-9 rounded-full ${meta.iconBg} flex items-center justify-center flex-shrink-0 mt-0.5`}>
                    {meta.icon}
                  </div>

                  {/* Content */}
                  <div className="flex-1 min-w-0">
                    <p className="text-sm text-gray-900 dark:text-gray-100">{item.title}</p>
                    <div className="flex items-center gap-3 mt-1">
                      <span className="text-xs text-gray-400 dark:text-gray-500">{formatTimeAgo(item.time)}</span>
                      <span className="text-xs text-gray-300 dark:text-gray-600">•</span>
                      <span className="text-xs text-gray-400 dark:text-gray-500">{formatDate(item.time)}</span>
                    </div>
                  </div>

                  {/* Type Badge */}
                  <span className={`inline-flex items-center px-2 py-0.5 text-xs font-medium rounded-full flex-shrink-0 ${meta.badgeColor}`}>
                    {meta.label}
                  </span>
                </div>
                </React.Fragment>
              )
            })}
          </div>
        )}

        {/* Pagination */}
        <div className="px-5 py-4 border-t border-gray-100 dark:border-gray-800 flex items-center justify-between">
          <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400">
            <span>
              {total === 0
                ? 'No results'
                : `Showing ${(page - 1) * perPage + 1}\u2013${Math.min(page * perPage, total)} of ${total} result${total !== 1 ? 's' : ''}`}
            </span>
            <span className="border-l border-gray-200 dark:border-gray-700 h-4" />
            <span className="flex items-center gap-1.5">
              Rows per page
              <select
                value={perPage}
                onChange={(e) => {
                  setPerPage(Number(e.target.value))
                  setPage(1)
                }}
                className="px-2 py-1 border border-gray-200 dark:border-gray-700 rounded text-sm dark:bg-gray-800 dark:text-gray-200"
              >
                <option value={10}>10</option>
                <option value={25}>25</option>
                <option value={50}>50</option>
              </select>
            </span>
          </div>
          {totalPages > 1 && (
            <div className="flex items-center gap-1">
              <button
                onClick={() => setPage(p => Math.max(1, p - 1))}
                disabled={page === 1}
                className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <ChevronLeft className="h-4 w-4" />
                Previous
              </button>
              {getPageNumbers().map((p, i) => (
                <React.Fragment key={i}>
                  {p === '...' ? (
                    <span className="px-2 text-gray-400 dark:text-gray-500">...</span>
                  ) : (
                    <button
                      onClick={() => setPage(p)}
                      className={`w-8 h-8 rounded text-sm font-medium ${
                        p === page
                          ? 'bg-navy-800 text-white'
                          : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800'
                      }`}
                    >
                      {p}
                    </button>
                  )}
                </React.Fragment>
              ))}
              <button
                onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                disabled={page === totalPages}
                className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Next
                <ChevronRight className="h-4 w-4" />
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}
