import React, { useState, useEffect } from 'react'
import { Link, useSearchParams, useNavigate } from 'react-router-dom'
import { emailsApi } from '../services/api'
import { formatDate } from '../utils/dateUtils'
import IngestEmailModal from '../components/IngestEmailModal'
import {
  Plus,
  Search,
  Filter,
  ChevronLeft,
  ChevronRight,
  Mail,
  RefreshCw,
  AlertCircle,
  Paperclip,
  Clock,
  CheckCircle,
  XCircle,
  AlertTriangle,
  Eye
} from 'lucide-react'

const statusTabs = [
  { key: '', label: 'All', icon: Mail, color: 'gray' },
  { key: 'pending', label: 'Queued', icon: Clock, color: 'gray' },
  { key: 'processing', label: 'Processing', icon: RefreshCw, color: 'blue' },
  { key: 'processed', label: 'Processed', icon: CheckCircle, color: 'green' },
  { key: 'failed', label: 'Failed', icon: XCircle, color: 'red' },
]

function Emails() {
  const [searchParams, setSearchParams] = useSearchParams()
  const navigate = useNavigate()
  const [emails, setEmails] = useState([])
  const [stats, setStats] = useState({})
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0 })
  const [perPage, setPerPage] = useState(10)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [showIngestModal, setShowIngestModal] = useState(false)
  const [timeRange, setTimeRange] = useState('')
  
  const page = parseInt(searchParams.get('page') || '1')
  const status = searchParams.get('status') || ''
  const search = searchParams.get('search') || ''
  
  const fetchEmails = async () => {
    try {
      setLoading(true)
      const [res, statsRes] = await Promise.all([
        emailsApi.list({
          page,
          per_page: perPage,
          status: status || undefined,
          search: search || undefined,
          time_range: timeRange || undefined,
        }),
        emailsApi.stats({
          search: search || undefined,
          time_range: timeRange || undefined,
        }),
      ])
      setEmails(res.data.emails || [])
      setPagination(res.data.pagination || { page: 1, pages: 1, total: 0 })
      setStats(statsRes.data || {})
      setError(null)
    } catch (err) {
      console.error('Error fetching emails:', err)
      setError('Failed to load emails')
    } finally {
      setLoading(false)
    }
  }
  
  useEffect(() => {
    fetchEmails()
  }, [page, status, search, timeRange, perPage])
  
  const handleSearch = (e) => {
    e.preventDefault()
    const formData = new FormData(e.target)
    const searchValue = formData.get('search')
    setSearchParams({
      ...Object.fromEntries(searchParams),
      search: searchValue,
      page: '1',
    })
  }
  
  const handleSearchChange = (e) => {
    const value = e.target.value
    if (value === '') {
      setSearchParams(prev => {
        const params = Object.fromEntries(prev)
        delete params.search
        return { ...params, page: '1' }
      })
    }
  }
  
  const handleStatusFilter = (newStatus) => {
    setSearchParams({
      ...Object.fromEntries(searchParams),
      status: newStatus,
      page: '1',
    })
  }
  
  const handlePageChange = (newPage) => {
    setSearchParams({
      ...Object.fromEntries(searchParams),
      page: newPage.toString(),
    })
  }
  
  const handleIngestSuccess = () => {
    setShowIngestModal(false)
    fetchEmails()
  }
  
  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-gray-100">Email Queue</h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1">Monitor and manage incoming email submissions</p>
        </div>
        <div className="flex gap-3">
          <button onClick={fetchEmails} disabled={loading} className="btn btn-secondary disabled:opacity-50 disabled:cursor-not-allowed">
            <RefreshCw className={`h-4 w-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
            Refresh
          </button>
          <button
            onClick={() => setShowIngestModal(true)}
            className="btn btn-primary"
          >
            <Plus className="h-4 w-4 mr-2" />
            Ingest Email
          </button>
        </div>
      </div>
      
      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatCard value={pagination.total} label="Total Emails" color="navy" />
        <StatCard value={stats.pending || 0} label="Queued" color="gray" />
        <StatCard value={stats.processing || 0} label="Processing" color="blue" />
        <StatCard value={stats.processed || 0} label="Processed" color="green" />
      </div>
      
      {/* Status Tabs */}
      <div className="flex items-center gap-2 overflow-x-auto pb-2">
        {statusTabs.map((tab) => (
          <button
            key={tab.key}
            onClick={() => handleStatusFilter(tab.key)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-colors ${
              status === tab.key
                ? 'bg-navy-800 text-white'
                : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-700 border border-gray-200 dark:border-gray-700'
            }`}
          >
            <tab.icon className="h-4 w-4" />
            {tab.label}
          </button>
        ))}
      </div>
      
      {/* Search & Filters */}
      <div className="card">
        <div className="card-body flex flex-col md:flex-row md:items-center gap-4">
          <form onSubmit={handleSearch} className="flex-1">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400 pointer-events-none z-10" />
              <input
                type="text"
                name="search"
                placeholder="Search by subject, sender..."
                key={search}
                defaultValue={search}
                onChange={handleSearchChange}
                className="form-input w-full"
                style={{ paddingLeft: '2.5rem' }}
              />
            </div>
          </form>
          
          <div className="flex items-center gap-3">
            <select
              className="form-select text-sm"
              value={timeRange}
              onChange={(e) => {
                setTimeRange(e.target.value)
                setSearchParams(prev => ({ ...Object.fromEntries(prev), page: '1' }))
              }}
            >
              <option value="">All Time</option>
              <option value="today">Today</option>
              <option value="week">This Week</option>
              <option value="month">This Month</option>
            </select>
          </div>
        </div>
      </div>
      
      {/* Error */}
      {error && (
        <div className="bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-800 rounded-xl p-4 flex items-center gap-3">
          <AlertCircle className="h-5 w-5 text-red-500 dark:text-red-400" />
          <span className="text-red-700 dark:text-red-300">{error}</span>
        </div>
      )}
      
      {/* Table */}
      <div className="card overflow-hidden">
        {loading ? (
          <div className="overflow-x-auto">
            <table className="table">
              <thead>
                <tr className="sticky top-0 z-10">
                  <th>Subject</th>
                  <th>Sender</th>
                  <th>Documents</th>
                  <th>Status</th>
                  <th>Received</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50 dark:divide-gray-800">
                {[...Array(5)].map((_, i) => (
                  <tr key={i} className="animate-pulse">
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-48"></div><div className="h-3 bg-gray-100 dark:bg-gray-800 rounded w-24 mt-1"></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-32"></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-8"></div></td>
                    <td><div className="h-6 bg-gray-200 dark:bg-gray-700 rounded-full w-20"></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-24"></div></td>
                    <td><div className="h-7 bg-gray-200 dark:bg-gray-700 rounded w-16"></div></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : emails.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-gray-500">
            <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
              <Mail className="h-8 w-8 text-gray-400 dark:text-gray-500" />
            </div>
            <p className="font-medium text-gray-900 dark:text-gray-100">No emails found</p>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">Ingest an email to get started</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="table">
              <thead>
                <tr className="sticky top-0 z-10">
                  <th>Subject</th>
                  <th>Sender</th>
                  <th>Documents</th>
                  <th>Status</th>
                  <th>Received</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50 dark:divide-gray-800">
                {emails.map((email) => (
                  <tr key={email.id} className="clickable-row cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors" onClick={(e) => { if (!e.target.closest('a') && !e.target.closest('button')) navigate(`/emails/${email.id}`) }}>
                    <td>
                      <Link
                        to={`/emails/${email.id}`}
                        className="font-medium text-gray-900 dark:text-gray-100 hover:text-navy-700 dark:hover:text-navy-400"
                      >
                        {email.subject || 'No subject'}
                      </Link>
                      {email.request_id && (
                        <Link 
                          to={`/requests/${email.request_id}`}
                          className="block text-xs text-gray-400 dark:text-gray-500 hover:text-navy-600 dark:hover:text-navy-400 mt-0.5"
                        >
                          View Request →
                        </Link>
                      )}
                    </td>
                    <td className="text-gray-600 dark:text-gray-400">
                      {email.sender}
                      {email.is_shared_mailbox && email.mailbox_email && (
                        <span className="block text-xs text-indigo-500 dark:text-indigo-400 mt-0.5" title={`Shared mailbox: ${email.mailbox_email}`}>
                          📬 {email.mailbox_email}
                        </span>
                      )}
                    </td>
                    <td>
                      <div className="flex items-center gap-1.5 text-gray-500">
                        <Paperclip className="h-4 w-4" />
                        <span>{email.document_count || 0}</span>
                      </div>
                    </td>
                    <td>
                      <StatusBadge status={email.status} />
                    </td>
                    <td className="text-gray-500 text-sm">
                      {formatDate(email.received_at || email.created_at)}
                    </td>
                    <td>
                      <Link
                        to={`/emails/${email.id}`}
                        className="btn btn-secondary btn-xs"
                      >
                        <Eye className="h-3.5 w-3.5 mr-1" />
                        View
                      </Link>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        
        {/* Pagination */}
        {(() => {
          const totalPages = Math.ceil(pagination.total / perPage)
          return (
            <div className="px-5 py-4 border-t border-gray-100 dark:border-gray-800 flex items-center justify-between">
              <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400">
                <span>
                  {pagination.total === 0
                    ? 'No results'
                    : `Showing ${(page - 1) * perPage + 1}\u2013${Math.min(page * perPage, pagination.total)} of ${pagination.total} result${pagination.total !== 1 ? 's' : ''}`}
                </span>
                <span className="border-l border-gray-200 dark:border-gray-700 h-4" />
                <span className="flex items-center gap-1.5">
                  Rows per page
                  <select
                    value={perPage}
                    onChange={(e) => {
                      setPerPage(Number(e.target.value))
                      handlePageChange(1)
                    }}
                    className="px-2 py-1 border border-gray-200 dark:border-gray-700 rounded text-sm dark:bg-gray-800 dark:text-gray-200"
                  >
                    <option value={10}>10</option>
                    <option value={25}>25</option>
                    <option value={50}>50</option>
                  </select>
                </span>
              </div>
              {totalPages > 1 && (
                <div className="flex items-center gap-1">
                  <button
                    onClick={() => handlePageChange(page - 1)}
                    disabled={page <= 1}
                    className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <ChevronLeft className="h-4 w-4" />
                    Previous
                  </button>
                  {generatePageNumbers(page, totalPages).map((pg, i) => (
                    <React.Fragment key={i}>
                      {pg === '...' ? (
                        <span className="px-2 text-gray-400 dark:text-gray-500">...</span>
                      ) : (
                        <button
                          onClick={() => handlePageChange(pg)}
                          className={`w-8 h-8 rounded text-sm font-medium ${
                            page === pg
                              ? 'bg-navy-800 text-white'
                              : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800'
                          }`}
                        >
                          {pg}
                        </button>
                      )}
                    </React.Fragment>
                  ))}
                  <button
                    onClick={() => handlePageChange(page + 1)}
                    disabled={page >= totalPages}
                    className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    Next
                    <ChevronRight className="h-4 w-4" />
                  </button>
                </div>
              )}
            </div>
          )
        })()}
      </div>
      
      {/* Ingest Modal */}
      {showIngestModal && (
        <IngestEmailModal
          onClose={() => setShowIngestModal(false)}
          onSuccess={handleIngestSuccess}
        />
      )}
    </div>
  )
}

function StatCard({ value, label, color }) {
  const colorClasses = {
    navy: 'bg-navy-800 text-white',
    gray: 'bg-gray-100 text-gray-800',
    blue: 'bg-blue-100 text-blue-800',
    orange: 'bg-orange-100 text-orange-800',
    green: 'bg-green-100 text-green-800',
  }
  
  return (
    <div className={`rounded-xl p-4 ${color === 'navy' ? colorClasses.navy : 'bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800'}`}>
      <p className={`text-2xl font-bold ${color === 'navy' ? 'text-white' : 'text-gray-900 dark:text-gray-100'}`}>{value}</p>
      <p className={`text-sm mt-1 ${color === 'navy' ? 'text-white/70' : 'text-gray-500 dark:text-gray-400'}`}>{label}</p>
    </div>
  )
}

function StatusBadge({ status }) {
  return (
    <span className={`status-badge status-${status}`}>
      {status?.replace(/_/g, ' ')}
    </span>
  )
}

function generatePageNumbers(current, total) {
  if (total <= 7) {
    return Array.from({ length: total }, (_, i) => i + 1)
  }
  if (current <= 3) {
    return [1, 2, 3, '...', total]
  }
  if (current >= total - 2) {
    return [1, '...', total - 2, total - 1, total]
  }
  return [1, '...', current - 1, current, current + 1, '...', total]
}

export default Emails
