import React, { useEffect, useState } from 'react'
import { useSearchParams, useNavigate, Link } from 'react-router-dom'
import { parseUTC } from '../utils/dateUtils'
import {
  CheckCircle,
  AlertCircle,
  Loader2,
  Building2,
  CreditCard,
  Key,
  Package,
  Mail,
  Globe,
  Calendar,
  ArrowRight,
  RefreshCw,
  LifeBuoy,
  Copy,
  Check,
  Shield,
  Clock,
  FileText,
  Cpu,
  BarChart3,
  ExternalLink,
  Users,
  Info,
} from 'lucide-react'
import logoImage from '../assets/CompanyLogoSynapx.png'

const planLabels = {
  free_trial: 'Free Trial',
  starter: 'Starter',
  professional: 'Professional',
  enterprise: 'Enterprise',
}

const planDescriptions = {
  free_trial: 'Explore Xtract with limited processing capabilities',
  enterprise: 'Full access with metered billing for pages processed and fields normalised',
}

const errorMessages = {
  missing_token: 'No purchase token was provided. Please try purchasing from Azure Marketplace again.',
  invalid_token: 'The purchase token could not be verified. It may have expired. Please try purchasing again.',
  no_tenant: 'We could not identify your organization. Please ensure you are signed in with a work or school account.',
  processing_failed: 'Something went wrong while setting up your subscription. Please try again or contact support.',
  duplicate_subscription: 'Your organization already has an active Xtract subscription.',
}

function CopyButton({ text }) {
  const [copied, setCopied] = useState(false)
  if (!text) return null
  return (
    <button
      onClick={() => {
        navigator.clipboard.writeText(text)
        setCopied(true)
        setTimeout(() => setCopied(false), 2000)
      }}
      className="ml-1.5 p-1 rounded hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
      title="Copy to clipboard"
    >
      {copied ? (
        <Check className="h-3.5 w-3.5 text-green-500" />
      ) : (
        <Copy className="h-3.5 w-3.5 text-gray-400" />
      )}
    </button>
  )
}

function DetailRow({ icon: Icon, label, value, mono, copyable }) {
  if (!value) return null
  return (
    <div className="flex items-start justify-between py-3 gap-4">
      <div className="flex items-center gap-2.5 shrink-0">
        {Icon && <Icon className="h-4 w-4 text-gray-400 dark:text-gray-500" />}
        <span className="text-sm text-gray-500 dark:text-gray-400">{label}</span>
      </div>
      <div className="flex items-center gap-1 min-w-0 text-right">
        {mono ? (
          <>
            <code className="text-sm font-mono text-gray-700 dark:text-gray-300 break-all">{value}</code>
            {copyable && <CopyButton text={value} />}
          </>
        ) : (
          <span className="text-sm font-medium text-gray-900 dark:text-white break-all">{value}</span>
        )}
      </div>
    </div>
  )
}

/**
 * Marketplace Landing Page
 *
 * Azure Marketplace redirects here after a purchase.
 * The backend resolves the token, provisions the subscription, then redirects to:
 *   {FRONTEND_URL}/marketplace/landing?marketplace=activated&plan={plan_id}&...details
 *   {FRONTEND_URL}/marketplace/landing?error={error_code}
 */
function MarketplaceLanding() {
  const [searchParams] = useSearchParams()
  const navigate = useNavigate()
  const [countdown, setCountdown] = useState(15)

  // Parse all URL parameters
  const marketplaceStatus = searchParams.get('marketplace')
  const error = searchParams.get('error')
  const isSuccess = marketplaceStatus === 'activated'
  const isDuplicate = error === 'duplicate_subscription'
  const isError = !!error && !isDuplicate

  // Duplicate-specific params (also available for success state)
  const dupOrgName = searchParams.get('org_name') || ''
  const dupOrgId = searchParams.get('org_id') || ''
  const dupEmail = searchParams.get('purchaser_email') || ''

  const plan = searchParams.get('plan') || ''
  const offerId = searchParams.get('offer') || ''
  const subscriptionName = searchParams.get('subscription_name') || ''
  const marketplaceSubscriptionId = searchParams.get('marketplace_subscription_id') || ''
  const orgName = searchParams.get('org_name') || ''
  const orgId = searchParams.get('org_id') || ''
  const tenantId = searchParams.get('tenant_id') || ''
  const purchaserEmail = searchParams.get('purchaser_email') || ''
  const subscriptionId = searchParams.get('subscription_id') || ''
  const activatedAt = searchParams.get('activated_at') || ''

  // Format the activation date
  const formattedDate = activatedAt
    ? (parseUTC(activatedAt) || new Date()).toLocaleDateString('en-GB', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        timeZone: 'Europe/London',
      })
    : new Date().toLocaleDateString('en-GB', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        timeZone: 'Europe/London',
      })

  // Auto-redirect countdown (success only)
  useEffect(() => {
    if (!isSuccess) return
    const timer = setInterval(() => {
      setCountdown(prev => {
        if (prev <= 1) {
          clearInterval(timer)
          navigate('/', { replace: true })
          return 0
        }
        return prev - 1
      })
    }, 1000)
    return () => clearInterval(timer)
  }, [isSuccess, navigate])

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-gray-950">
      {/* ─── Top Navigation Bar ─── */}
      <header className="sticky top-0 z-10 border-b border-gray-200 dark:border-gray-800 bg-white/80 dark:bg-gray-900/80 backdrop-blur-sm">
        <div className="px-8 lg:px-16 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img src={logoImage} alt="Xtract" className="w-9 h-9 rounded-lg" />
            <div>
              <h1 className="text-lg font-semibold text-gray-900 dark:text-gray-100 leading-tight">Xtract</h1>
              <p className="text-xs text-gray-500 dark:text-gray-400">Synapx AI</p>
            </div>
          </div>
          <span className="hidden sm:inline-flex items-center gap-1.5 text-xs font-medium text-gray-400 dark:text-gray-500">
            <Globe className="h-3.5 w-3.5" />
            Azure Marketplace
          </span>
        </div>
      </header>

      {/* ─── Main Content ─── */}
      <main className="flex-1">
        <div className="px-8 lg:px-16 py-10 sm:py-14">

          {/* ══════════ LOADING STATE ══════════ */}
          {!isSuccess && !isError && (
            <div className="flex flex-col items-center justify-center py-32">
              <div className="w-16 h-16 bg-blue-50 dark:bg-blue-900/30 rounded-2xl flex items-center justify-center mb-6">
                <Loader2 className="w-8 h-8 text-blue-600 dark:text-blue-400 animate-spin" />
              </div>
              <h2 className="text-2xl font-bold text-gray-900 dark:text-gray-100 mb-2">
                Setting Up Your Subscription
              </h2>
              <p className="text-gray-500 dark:text-gray-400 text-center max-w-md">
                We're provisioning your account and activating your subscription. This usually takes just a few seconds.
              </p>
            </div>
          )}

          {/* ══════════ SUCCESS STATE ══════════ */}
          {isSuccess && (
            <div className="space-y-8">
              {/* Status Banner */}
              <div className="rounded-xl bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 p-6">
                <div className="flex items-start gap-4">
                  <div className="w-12 h-12 bg-green-100 dark:bg-green-900/40 rounded-xl flex items-center justify-center shrink-0">
                    <CheckCircle className="w-6 h-6 text-green-600 dark:text-green-400" />
                  </div>
                  <div className="min-w-0">
                    <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 mb-1">
                      Subscription Activated Successfully
                    </h2>
                    <p className="text-sm text-gray-600 dark:text-gray-400 leading-relaxed">
                      Your Azure Marketplace purchase has been confirmed and your Xtract account is ready.
                      Review your subscription details below, then sign in to start processing documents.
                    </p>
                  </div>
                </div>
              </div>

              {/* Two Column Layout */}
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* ── Left Column: Subscription Details (2/3) ── */}
                <div className="lg:col-span-2 space-y-6">
                  {/* Organization & Plan Card */}
                  <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800">
                    {/* Org Header */}
                    <div className="px-6 py-5 border-b border-gray-100 dark:border-gray-800">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-navy-800 dark:bg-navy-700 rounded-lg flex items-center justify-center text-white font-bold text-sm">
                            {(orgName || 'O').charAt(0).toUpperCase()}
                          </div>
                          <div>
                            <h3 className="text-base font-semibold text-gray-900 dark:text-gray-100">
                              {orgName || 'Your Organization'}
                            </h3>
                            {purchaserEmail && (
                              <p className="text-xs text-gray-500 dark:text-gray-400">{purchaserEmail}</p>
                            )}
                          </div>
                        </div>
                        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-green-50 text-green-700 dark:bg-green-900/30 dark:text-green-400 ring-1 ring-green-200 dark:ring-green-800">
                          <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
                          Active
                        </span>
                      </div>
                    </div>

                    {/* Plan Summary */}
                    <div className="px-6 py-5 border-b border-gray-100 dark:border-gray-800 bg-gray-50/50 dark:bg-gray-800/30">
                      <div className="flex items-center gap-3 mb-2">
                        <Package className="h-5 w-5 text-navy-800 dark:text-navy-400" />
                        <h4 className="text-sm font-semibold text-gray-900 dark:text-gray-100">
                          {planLabels[plan] || plan} Plan
                        </h4>
                      </div>
                      <p className="text-sm text-gray-500 dark:text-gray-400 ml-8">
                        {planDescriptions[plan] || 'Your selected subscription plan'}
                      </p>
                      {plan === 'enterprise' && (
                        <div className="mt-3 ml-8 flex flex-wrap gap-2">
                          <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-navy-50 text-navy-700 dark:bg-navy-900/30 dark:text-navy-400">
                            Metered: Pages Processed
                          </span>
                          <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-navy-50 text-navy-700 dark:bg-navy-900/30 dark:text-navy-400">
                            Metered: Fields Normalised
                          </span>
                        </div>
                      )}
                    </div>

                    {/* Detailed Fields */}
                    <div className="px-6 divide-y divide-gray-100 dark:divide-gray-800">
                      <DetailRow icon={Key} label="Subscription ID" value={subscriptionId} mono copyable />
                      <DetailRow icon={CreditCard} label="Marketplace ID" value={marketplaceSubscriptionId} mono copyable />
                      <DetailRow icon={FileText} label="Offer" value={offerId} />
                      {subscriptionName && (
                        <DetailRow icon={Package} label="Subscription Name" value={subscriptionName} />
                      )}
                      <DetailRow icon={Building2} label="Organization" value={orgName} />
                      <DetailRow icon={Globe} label="Tenant ID" value={tenantId} mono copyable />
                      <DetailRow icon={Mail} label="Purchaser Email" value={purchaserEmail} />
                      <DetailRow icon={Calendar} label="Activated On" value={formattedDate} />
                    </div>

                    {/* Card Footer */}
                    <div className="px-6 py-3 bg-gray-50 dark:bg-gray-800/40 border-t border-gray-100 dark:border-gray-800 rounded-b-xl">
                      <p className="text-xs text-gray-400 dark:text-gray-500 text-center">
                        Save these details for your records · Billing is managed through the Azure Portal
                      </p>
                    </div>
                  </div>

                  {/* What's Included Card */}
                  <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 p-6">
                    <h4 className="text-sm font-semibold text-gray-900 dark:text-gray-100 mb-4 flex items-center gap-2">
                      <Shield className="h-4 w-4 text-navy-800 dark:text-navy-400" />
                      What's Included
                    </h4>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                      {[
                        { icon: Cpu, text: 'AI-powered document extraction' },
                        { icon: FileText, text: 'PDF & document processing' },
                        { icon: BarChart3, text: 'Real-time analytics dashboard' },
                        { icon: Shield, text: 'Enterprise-grade security' },
                        { icon: Mail, text: 'Email ingestion pipeline' },
                        { icon: Globe, text: 'Azure AD SSO integration' },
                      ].map(({ icon: ItemIcon, text }, i) => (
                        <div key={i} className="flex items-center gap-2.5">
                          <div className="w-7 h-7 bg-green-50 dark:bg-green-900/20 rounded-lg flex items-center justify-center shrink-0">
                            <ItemIcon className="h-3.5 w-3.5 text-green-600 dark:text-green-400" />
                          </div>
                          <span className="text-sm text-gray-600 dark:text-gray-400">{text}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                {/* ── Right Column: Actions & Next Steps (1/3) ── */}
                <div className="space-y-6">
                  {/* Sign In CTA */}
                  <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 p-6">
                    <h4 className="text-sm font-semibold text-gray-900 dark:text-gray-100 mb-3">
                      Get Started
                    </h4>
                    <p className="text-sm text-gray-500 dark:text-gray-400 mb-5">
                      Sign in with your Microsoft account to access your Xtract dashboard and start processing documents.
                    </p>
                    <button
                      onClick={() => navigate('/', { replace: true })}
                      className="w-full flex items-center justify-center gap-2.5 px-4 py-3 bg-navy-800 text-white rounded-lg font-medium hover:bg-navy-900 transition-colors"
                    >
                      <svg className="w-5 h-5" viewBox="0 0 21 21" fill="none">
                        <path d="M10 0H0V10H10V0Z" fill="#F25022"/>
                        <path d="M21 0H11V10H21V0Z" fill="#7FBA00"/>
                        <path d="M10 11H0V21H10V11Z" fill="#00A4EF"/>
                        <path d="M21 11H11V21H21V11Z" fill="#FFB900"/>
                      </svg>
                      Sign in with Microsoft
                      <ArrowRight className="h-4 w-4" />
                    </button>
                    <p className="text-xs text-gray-400 dark:text-gray-500 text-center mt-3">
                      Redirecting in {countdown}s...
                    </p>
                  </div>

                  {/* Next Steps */}
                  <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 p-6">
                    <h4 className="text-sm font-semibold text-gray-900 dark:text-gray-100 mb-4 flex items-center gap-2">
                      <Clock className="h-4 w-4 text-navy-800 dark:text-navy-400" />
                      Next Steps
                    </h4>
                    <div className="space-y-4">
                      {[
                        { step: '1', title: 'Sign in to your dashboard', desc: 'Use your Microsoft work account to access Xtract' },
                        { step: '2', title: 'Configure email ingestion', desc: 'Set up your email pipeline to auto-process documents' },
                        { step: '3', title: 'Submit your first document', desc: 'Upload a PDF or process an email attachment' },
                        { step: '4', title: 'Review extracted data', desc: 'View AI-extracted and normalised fields on your dashboard' },
                      ].map(item => (
                        <div key={item.step} className="flex items-start gap-3">
                          <span className="flex items-center justify-center w-6 h-6 rounded-full bg-navy-50 dark:bg-navy-900/30 text-navy-800 dark:text-navy-400 text-xs font-bold shrink-0 mt-0.5">
                            {item.step}
                          </span>
                          <div className="min-w-0">
                            <p className="text-sm font-medium text-gray-900 dark:text-gray-100 leading-tight">
                              {item.title}
                            </p>
                            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
                              {item.desc}
                            </p>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Useful Links */}
                  <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 p-6">
                    <h4 className="text-sm font-semibold text-gray-900 dark:text-gray-100 mb-3">
                      Useful Links
                    </h4>
                    <div className="space-y-2">
                      <a
                        href="https://portal.azure.com/#view/HubsExtension/BrowseResourceBlade/resourceType/Microsoft.SaaS%2Fresources"
                        target="_blank"
                        rel="noopener noreferrer"
                        className="flex items-center gap-2 text-sm text-navy-800 dark:text-navy-400 hover:underline"
                      >
                        <ExternalLink className="h-3.5 w-3.5" />
                        Manage SaaS in Azure Portal
                      </a>
                      <Link
                        to="/privacy"
                        className="flex items-center gap-2 text-sm text-navy-800 dark:text-navy-400 hover:underline"
                      >
                        <Shield className="h-3.5 w-3.5" />
                        Privacy Policy
                      </Link>
                      <a
                        href="mailto:support@synapx.ai"
                        className="flex items-center gap-2 text-sm text-navy-800 dark:text-navy-400 hover:underline"
                      >
                        <LifeBuoy className="h-3.5 w-3.5" />
                        Contact Support
                      </a>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* ══════════ DUPLICATE SUBSCRIPTION STATE ══════════ */}
          {isDuplicate && (
            <div className="max-w-5xl mx-auto space-y-6">
              {/* Duplicate Banner */}
              <div className="rounded-xl bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 p-6">
                <div className="flex items-start gap-4">
                  <div className="w-12 h-12 bg-amber-100 dark:bg-amber-900/40 rounded-xl flex items-center justify-center shrink-0">
                    <Info className="w-6 h-6 text-amber-600 dark:text-amber-400" />
                  </div>
                  <div className="min-w-0">
                    <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 mb-1">
                      Your Organization Already Has an Active Subscription
                    </h2>
                    <p className="text-sm text-gray-600 dark:text-gray-400 leading-relaxed">
                      A subscription for <strong className="text-gray-900 dark:text-gray-100">{dupOrgName || 'your organization'}</strong> is already active.
                      You don't need to purchase again — contact your administrator to request access.
                    </p>
                  </div>
                </div>
              </div>

              {/* Details Card */}
              <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden">
                <div className="px-6 py-5 border-b border-gray-100 dark:border-gray-800">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-navy-800 dark:bg-navy-700 rounded-lg flex items-center justify-center text-white font-bold text-sm">
                      {(dupOrgName || 'O').charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <h3 className="text-base font-semibold text-gray-900 dark:text-gray-100">
                        {dupOrgName || 'Your Organization'}
                      </h3>
                      {dupOrgId && (
                        <p className="text-xs text-gray-500 dark:text-gray-400 font-mono">{dupOrgId}</p>
                      )}
                    </div>
                    <span className="ml-auto inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-green-50 text-green-700 dark:bg-green-900/30 dark:text-green-400 ring-1 ring-green-200 dark:ring-green-800">
                      <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
                      Active
                    </span>
                  </div>
                </div>

                <div className="px-6 py-5">
                  <h4 className="text-sm font-semibold text-gray-900 dark:text-gray-100 mb-4 flex items-center gap-2">
                    <Users className="h-4 w-4 text-navy-800 dark:text-navy-400" />
                    How to Get Access
                  </h4>
                  <div className="space-y-4">
                    {[
                      {
                        step: '1',
                        title: 'Contact your organization admin',
                        desc: dupEmail
                          ? `The subscription was purchased by ${dupEmail}. Reach out to them or your IT administrator.`
                          : 'Reach out to the person who originally purchased the subscription or your IT administrator.',
                      },
                      {
                        step: '2',
                        title: 'Request access via Azure AD',
                        desc: 'Your admin can grant you access by assigning you to the Xtract enterprise application in Azure AD (Entra ID).',
                      },
                      {
                        step: '3',
                        title: 'Sign in directly',
                        desc: 'If your admin has already granted access, you can sign in right away — no separate purchase needed.',
                      },
                    ].map(item => (
                      <div key={item.step} className="flex items-start gap-3">
                        <span className="flex items-center justify-center w-6 h-6 rounded-full bg-amber-50 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 text-xs font-bold shrink-0 mt-0.5">
                          {item.step}
                        </span>
                        <div className="min-w-0">
                          <p className="text-sm font-medium text-gray-900 dark:text-gray-100 leading-tight">
                            {item.title}
                          </p>
                          <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
                            {item.desc}
                          </p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex flex-col sm:flex-row gap-3">
                <button
                  onClick={() => navigate('/', { replace: true })}
                  className="flex-1 inline-flex items-center justify-center gap-2 px-5 py-3 bg-navy-800 text-white font-medium rounded-lg hover:bg-navy-900 transition-colors"
                >
                  <ArrowRight className="h-4 w-4" />
                  Sign In Instead
                </button>
                <a
                  href="https://portal.azure.com/#view/HubsExtension/BrowseResourceBlade/resourceType/Microsoft.SaaS%2Fresources"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex-1 inline-flex items-center justify-center gap-2 px-5 py-3 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 font-medium rounded-lg border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                >
                  <ExternalLink className="h-4 w-4" />
                  Manage in Azure Portal
                </a>
                <a
                  href="mailto:support@synapx.ai"
                  className="flex-1 inline-flex items-center justify-center gap-2 px-5 py-3 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 font-medium rounded-lg border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                >
                  <LifeBuoy className="h-4 w-4" />
                  Contact Support
                </a>
              </div>

              {/* Cancel Purchase Note */}
              <div className="rounded-lg bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 p-4">
                <p className="text-xs text-gray-500 dark:text-gray-400 text-center">
                  <strong>Note:</strong> If you purchased a duplicate subscription, you can cancel it from the
                  {' '}
                  <a
                    href="https://portal.azure.com/#view/HubsExtension/BrowseResourceBlade/resourceType/Microsoft.SaaS%2Fresources"
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-navy-800 dark:text-navy-400 hover:underline"
                  >
                    Azure Portal → SaaS resources
                  </a>
                  {' '}
                  to avoid any charges.
                </p>
              </div>
            </div>
          )}

          {/* ══════════ ERROR STATE ══════════ */}
          {isError && (
            <div className="max-w-5xl mx-auto space-y-6">
              {/* Error Banner */}
              <div className="rounded-xl bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 p-6">
                <div className="flex items-start gap-4">
                  <div className="w-12 h-12 bg-red-100 dark:bg-red-900/40 rounded-xl flex items-center justify-center shrink-0">
                    <AlertCircle className="w-6 h-6 text-red-600 dark:text-red-400" />
                  </div>
                  <div className="min-w-0">
                    <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 mb-1">
                      Subscription Activation Failed
                    </h2>
                    <p className="text-sm text-gray-600 dark:text-gray-400 leading-relaxed">
                      We couldn't complete your Azure Marketplace subscription setup. Don't worry — your purchase is safe with Microsoft.
                    </p>
                  </div>
                </div>
              </div>

              {/* Error Details Card */}
              <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden">
                <div className="px-6 py-4 border-b border-gray-100 dark:border-gray-800 bg-red-50/50 dark:bg-red-900/10">
                  <p className="text-sm font-medium text-gray-700 dark:text-gray-300">Error Details</p>
                  <code className="text-sm text-red-600 dark:text-red-400 mt-1 block">
                    {errorMessages[error] || `Unknown error: ${error}`}
                  </code>
                </div>
                <div className="px-6 py-5">
                  <h4 className="text-sm font-semibold text-gray-900 dark:text-gray-100 mb-3">
                    Troubleshooting Steps
                  </h4>
                  <ol className="space-y-3">
                    {[
                      'Go back to Azure Marketplace and try the "Configure account" button again.',
                      'Make sure you are signed in with the same Microsoft account you used to purchase.',
                      'Clear your browser cache and cookies, then try again.',
                      'If the issue persists, check your SaaS subscription status in the Azure Portal.',
                      'Contact our support team with the error details above.',
                    ].map((step, i) => (
                      <li key={i} className="flex items-start gap-3 text-sm text-gray-600 dark:text-gray-400">
                        <span className="flex items-center justify-center w-5 h-5 rounded-full bg-gray-100 dark:bg-gray-800 text-gray-500 text-xs font-bold shrink-0 mt-0.5">
                          {i + 1}
                        </span>
                        {step}
                      </li>
                    ))}
                  </ol>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex flex-col sm:flex-row gap-3">
                <button
                  onClick={() => window.location.reload()}
                  className="flex-1 inline-flex items-center justify-center gap-2 px-5 py-3 bg-navy-800 text-white font-medium rounded-lg hover:bg-navy-900 transition-colors"
                >
                  <RefreshCw className="h-4 w-4" />
                  Try Again
                </button>
                <a
                  href="https://portal.azure.com/#view/HubsExtension/BrowseResourceBlade/resourceType/Microsoft.SaaS%2Fresources"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex-1 inline-flex items-center justify-center gap-2 px-5 py-3 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 font-medium rounded-lg border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                >
                  <ExternalLink className="h-4 w-4" />
                  Azure Portal
                </a>
                <a
                  href="mailto:support@synapx.ai"
                  className="flex-1 inline-flex items-center justify-center gap-2 px-5 py-3 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 font-medium rounded-lg border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                >
                  <LifeBuoy className="h-4 w-4" />
                  Contact Support
                </a>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* ─── Footer ─── */}
      <footer className="border-t border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900">
        <div className="px-8 lg:px-16 py-4 flex flex-col sm:flex-row items-center justify-between gap-2">
          <p className="text-xs text-gray-400 dark:text-gray-500">
            © {new Date().getFullYear()} Synapx AI Ltd. All rights reserved.
          </p>
          <div className="flex items-center gap-4 text-xs text-gray-400 dark:text-gray-500">
            <Link to="/privacy" className="hover:text-gray-600 dark:hover:text-gray-300">
              Privacy Policy
            </Link>
            <a href="mailto:support@synapx.ai" className="hover:text-gray-600 dark:hover:text-gray-300">
              Support
            </a>
          </div>
        </div>
      </footer>
    </div>
  )
}

export default MarketplaceLanding
