import React, { useState, useEffect, useMemo } from 'react'
import { useSearchParams } from 'react-router-dom'
import { jobsApi } from '../services/api'
import { formatDateTime, parseUTC } from '../utils/dateUtils'
import {
  Search,
  Filter,
  ChevronLeft,
  ChevronRight,
  Clock,
  RefreshCw,
  AlertCircle,
  CheckCircle,
  XCircle,
  PlayCircle,
  PauseCircle,
  Loader2
} from 'lucide-react'

function Jobs() {
  const [searchParams, setSearchParams] = useSearchParams()
  const [jobs, setJobs] = useState([])
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0 })
  const [perPage, setPerPage] = useState(10)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [actionJobId, setActionJobId] = useState(null) // Track which job has an action in progress
  
  const page = parseInt(searchParams.get('page') || '1')
  const status = searchParams.get('status') || ''
  const jobType = searchParams.get('job_type') || ''
  
  const fetchJobs = async () => {
    try {
      setLoading(true)
      const res = await jobsApi.list({
        page,
        per_page: perPage,
        status: status || undefined,
        job_type: jobType || undefined,
      })
      setJobs(res.data.jobs || [])
      setPagination(res.data.pagination || { page: 1, pages: 1, total: 0 })
      setError(null)
    } catch (err) {
      console.error('Error fetching jobs:', err)
      setError('Failed to load jobs')
    } finally {
      setLoading(false)
    }
  }
  
  useEffect(() => {
    fetchJobs()
  }, [page, status, jobType, perPage])
  
  // Auto-refresh for running jobs
  useEffect(() => {
    const hasRunning = jobs.some(j => j.status === 'running' || j.status === 'pending')
    if (hasRunning) {
      const interval = setInterval(fetchJobs, 5000)
      return () => clearInterval(interval)
    }
  }, [jobs])
  
  const handleStatusFilter = (newStatus) => {
    setSearchParams({
      ...Object.fromEntries(searchParams),
      status: newStatus,
      page: '1',
    })
  }
  
  const handlePageChange = (newPage) => {
    setSearchParams({
      ...Object.fromEntries(searchParams),
      page: newPage.toString(),
    })
  }
  
  // Only one retry button per request group (entity_type + entity_id).
  // No retry at all if any job in the group is completed, running, or pending.
  const retryEligibleJobIds = useMemo(() => {
    const groups = {}
    jobs.forEach(job => {
      const key = `${job.entity_type}_${job.entity_id}`
      if (!groups[key]) groups[key] = []
      groups[key].push(job)
    })

    const eligible = new Set()
    Object.values(groups).forEach(groupJobs => {
      // If any job in this request is completed/running/pending, no retry
      const hasNonRetryable = groupJobs.some(j =>
        ['completed', 'running', 'pending'].includes(j.status)
      )
      if (hasNonRetryable) return

      // Pick the latest failed/cancelled job to show the retry button on
      const retryable = groupJobs
        .filter(j => ['failed', 'cancelled'].includes(j.status))
        .sort((a, b) => b.id - a.id)
      if (retryable.length > 0) {
        eligible.add(retryable[0].id)
      }
    })
    return eligible
  }, [jobs])

  const handleCancel = async (jobId) => {
    try {
      setActionJobId(jobId)
      await jobsApi.cancel(jobId)
      fetchJobs()
    } catch (err) {
      console.error('Error cancelling job:', err)
    } finally {
      setActionJobId(null)
    }
  }
  
  const handleRetry = async (jobId) => {
    try {
      setActionJobId(jobId)
      await jobsApi.retry(jobId)
      fetchJobs()
    } catch (err) {
      console.error('Error retrying job:', err)
    } finally {
      setActionJobId(null)
    }
  }
  
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-gray-100">Jobs</h1>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">Monitor extraction and processing tasks</p>
        </div>
        <button onClick={fetchJobs} disabled={loading} className="btn btn-secondary disabled:opacity-50 disabled:cursor-not-allowed">
          <RefreshCw className={`h-4 w-4 mr-1 ${loading ? 'animate-spin' : ''}`} />
          Refresh
        </button>
      </div>
      
      {/* Filters */}
      <div className="card">
        <div className="card-body flex flex-col md:flex-row md:items-center gap-4">
          <div className="flex items-center gap-2 flex-1">
            <Filter className="h-5 w-5 text-gray-400" />
            <select
              value={status}
              onChange={(e) => handleStatusFilter(e.target.value)}
              className="form-select"
            >
              <option value="">All Status</option>
              <option value="pending">Pending</option>
              <option value="running">Running</option>
              <option value="completed">Completed</option>
              <option value="failed">Failed</option>
              <option value="cancelled">Cancelled</option>
            </select>
          </div>
        </div>
      </div>
      
      {/* Error */}
      {error && (
        <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-4 flex items-center">
          <AlertCircle className="h-5 w-5 text-red-500 dark:text-red-400 mr-2" />
          <span className="text-red-700 dark:text-red-300">{error}</span>
        </div>
      )}
      
      {/* Table */}
      <div className="card overflow-hidden">
        {loading ? (
          <div className="overflow-x-auto">
            <table className="table">
              <thead>
                <tr className="sticky top-0 z-10">
                  <th>ID</th>
                  <th>Type</th>
                  <th>Parent</th>
                  <th>Status</th>
                  <th>Progress</th>
                  <th>Duration</th>
                  <th>Started</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {[...Array(5)].map((_, i) => (
                  <tr key={i} className="animate-pulse">
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-12"></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-24"></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-24"></div></td>
                    <td><div className="h-6 bg-gray-200 dark:bg-gray-700 rounded-full w-20"></div></td>
                    <td><div className="h-2 bg-gray-200 dark:bg-gray-700 rounded-full w-20"></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-16"></div></td>
                    <td><div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-32"></div></td>
                    <td><div className="h-7 bg-gray-200 dark:bg-gray-700 rounded w-8"></div></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : jobs.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-gray-500">
            <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
              <Clock className="h-8 w-8 text-gray-400 dark:text-gray-500" />
            </div>
            <p className="font-medium text-gray-900 dark:text-gray-100">No jobs found</p>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">Jobs will appear here when processing starts</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="table">
              <thead>
                <tr className="sticky top-0 z-10">
                  <th>ID</th>
                  <th>Type</th>
                  <th>Parent</th>
                  <th>Status</th>
                  <th>Progress</th>
                  <th>Duration</th>
                  <th>Started</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {jobs.map((job) => (
                  <tr key={job.id}>
                    <td className="font-medium">#{job.id}</td>
                    <td>{job.job_type}</td>
                    <td>
                      <span className="text-gray-600 dark:text-gray-400">
                        {job.entity_type} #{job.entity_id}
                      </span>
                    </td>
                    <td>
                      <JobStatusBadge status={job.status} />
                    </td>
                    <td>
                      {job.status === 'running' ? (
                        <div className="flex items-center gap-2">
                          <div className="w-20 bg-gray-200 dark:bg-gray-700 rounded-full h-2 overflow-hidden relative">
                            <div
                              className="bg-primary-600 h-2 rounded-full transition-all progress-shimmer"
                              style={{ width: `${job.progress_percent || 0}%` }}
                            />
                          </div>
                          <span className="text-xs text-gray-500 dark:text-gray-400">{job.progress_percent || 0}%</span>
                        </div>
                      ) : (
                        <span className="text-gray-400">-</span>
                      )}
                    </td>
                    <td className="text-gray-500 text-sm">
                      {formatDuration(job.started_at, job.completed_at, job.status)}
                    </td>
                    <td className="text-gray-500 text-sm">
                      {job.started_at ? formatDateTime(job.started_at) : '-'}
                    </td>
                    <td className="text-gray-500 text-sm">
                      <div className="flex gap-1">
                        {['pending', 'running'].includes(job.status) && (
                          <button
                            onClick={() => handleCancel(job.id)}
                            disabled={actionJobId !== null}
                            className="btn btn-secondary btn-sm disabled:opacity-50 disabled:cursor-not-allowed"
                            title="Cancel"
                            aria-label="Cancel job"
                          >
                            {actionJobId === job.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <XCircle className="h-4 w-4" />}
                          </button>
                        )}
                        {retryEligibleJobIds.has(job.id) && (
                          <button
                            onClick={() => handleRetry(job.id)}
                            disabled={actionJobId !== null}
                            className="btn btn-secondary btn-sm disabled:opacity-50 disabled:cursor-not-allowed"
                            title="Retry"
                            aria-label="Retry job"
                          >
                            {actionJobId === job.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <RefreshCw className="h-4 w-4" />}
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        
        {/* Pagination */}
        {(() => {
          const totalPages = Math.ceil(pagination.total / perPage)
          return (
            <div className="px-5 py-4 border-t border-gray-100 dark:border-gray-800 flex items-center justify-between">
              <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400">
                <span>
                  {pagination.total === 0
                    ? 'No results'
                    : `Showing ${(page - 1) * perPage + 1}\u2013${Math.min(page * perPage, pagination.total)} of ${pagination.total} result${pagination.total !== 1 ? 's' : ''}`}
                </span>
                <span className="border-l border-gray-200 dark:border-gray-700 h-4" />
                <span className="flex items-center gap-1.5">
                  Rows per page
                  <select
                    value={perPage}
                    onChange={(e) => {
                      setPerPage(Number(e.target.value))
                      handlePageChange(1)
                    }}
                    className="px-2 py-1 border border-gray-200 dark:border-gray-700 rounded text-sm dark:bg-gray-800 dark:text-gray-200"
                  >
                    <option value={10}>10</option>
                    <option value={25}>25</option>
                    <option value={50}>50</option>
                  </select>
                </span>
              </div>
              {totalPages > 1 && (
                <div className="flex items-center gap-1">
                  <button
                    onClick={() => handlePageChange(page - 1)}
                    disabled={page <= 1}
                    className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <ChevronLeft className="h-4 w-4" />
                    Previous
                  </button>
                  {generatePageNumbers(page, totalPages).map((pg, i) => (
                    <React.Fragment key={i}>
                      {pg === '...' ? (
                        <span className="px-2 text-gray-400 dark:text-gray-500">...</span>
                      ) : (
                        <button
                          onClick={() => handlePageChange(pg)}
                          className={`w-8 h-8 rounded text-sm font-medium ${
                            page === pg
                              ? 'bg-navy-800 text-white'
                              : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800'
                          }`}
                        >
                          {pg}
                        </button>
                      )}
                    </React.Fragment>
                  ))}
                  <button
                    onClick={() => handlePageChange(page + 1)}
                    disabled={page >= totalPages}
                    className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    Next
                    <ChevronRight className="h-4 w-4" />
                  </button>
                </div>
              )}
            </div>
          )
        })()}
      </div>
    </div>
  )
}

function JobStatusBadge({ status }) {
  const configs = {
    pending: { icon: Clock, color: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400' },
    running: { icon: PlayCircle, color: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400', animate: true },
    completed: { icon: CheckCircle, color: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' },
    failed: { icon: XCircle, color: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400' },
    cancelled: { icon: PauseCircle, color: 'bg-gray-100 text-gray-700 dark:bg-gray-700 dark:text-gray-300' },
  }
  
  const config = configs[status] || configs.pending
  const Icon = config.icon
  
  return (
    <span className={`status-badge ${config.color} flex items-center gap-1`}>
      <Icon className={`h-3 w-3 ${config.animate ? 'animate-spin' : ''}`} />
      {status}
    </span>
  )
}

function formatDuration(startedAt, completedAt, status) {
  if (!startedAt) return '-'
  const start = parseUTC(startedAt)
  const end = completedAt ? parseUTC(completedAt) : (status === 'running' ? new Date() : null)
  if (!end) return '-'
  const diffMs = end - start
  const seconds = Math.floor(diffMs / 1000)
  if (seconds < 60) return `${seconds}s`
  const minutes = Math.floor(seconds / 60)
  const remainingSeconds = seconds % 60
  if (minutes < 60) return `${minutes}m ${remainingSeconds}s`
  const hours = Math.floor(minutes / 60)
  const remainingMinutes = minutes % 60
  return `${hours}h ${remainingMinutes}m`
}

function generatePageNumbers(current, total) {
  if (total <= 7) {
    return Array.from({ length: total }, (_, i) => i + 1)
  }
  if (current <= 3) {
    return [1, 2, 3, '...', total]
  }
  if (current >= total - 2) {
    return [1, '...', total - 2, total - 1, total]
  }
  return [1, '...', current - 1, current, current + 1, '...', total]
}

export default Jobs
