import React, { useState, useEffect, useRef } from 'react'
import { useParams, useNavigate, useLocation, Link } from 'react-router-dom'
import { requestsApi, documentsApi, jobsApi } from '../services/api'
import { formatTimeAgo as formatTimeAgoUtil, formatDateTime, formatAuditTimestamp, parseUTC } from '../utils/dateUtils'
import { useToast } from '../context/ToastContext'
import PDFViewer from '../components/PDFViewer'
import DocumentViewer from '../components/DocumentViewer'
import CostBreakdown from '../components/CostBreakdown'
import {
  ArrowLeft,
  FileText,
  Check,
  X,
  RefreshCw,
  Download,
  Save,
  AlertCircle,
  Clock,
  Search,
  ZoomIn,
  ZoomOut,
  Maximize2,
  Printer,
  RotateCcw,
  Mail,
  ChevronRight,
  ChevronDown,
  Info,
  Calendar,
  CheckCircle,
  User,
  Bot,
  FileSpreadsheet,
  File,
  RotateCw,
  Layers,
  Eye,
  History,
  Loader2,
  Sparkles,
  Edit,
  XCircle,
  Upload,
  PanelRightClose,
  PanelRightOpen,
  Columns2
} from 'lucide-react'

function RequestDetail() {
  const { id } = useParams()
  const navigate = useNavigate()
  const location = useLocation()
  const toast = useToast()
  const queryParams = new URLSearchParams(location.search)
  const modeFromUrl = queryParams.get('mode') // 'view' or 'edit'
  const [request, setRequest] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [editedFields, setEditedFields] = useState([])
  const [saving, setSaving] = useState(false)
  const [analyzing, setAnalyzing] = useState(false)
  const [documentId, setDocumentId] = useState(null)
  const [activeDocTab, setActiveDocTab] = useState(0)
  const [searchText, setSearchText] = useState('')
  const [replaceText, setReplaceText] = useState('')
  const [searchResults, setSearchResults] = useState([])
  const [currentPage, setCurrentPage] = useState(1)
  const [zoomLevel, setZoomLevel] = useState(100)
  const [highlightedField, setHighlightedField] = useState(null)
  const [isRequestInfoExpanded, setIsRequestInfoExpanded] = useState(false)
  
  // Activity log entries from API
  const [activityLog, setActivityLog] = useState([])
  const [loadingAuditLogs, setLoadingAuditLogs] = useState(false)
  const [editHistory, setEditHistory] = useState([])
  
  // Batch audit history map: { fieldId: true } for fields with audit logs
  const [fieldsAuditMap, setFieldsAuditMap] = useState({})
  
  // Processing state for popup
  const [showProcessingModal, setShowProcessingModal] = useState(false)
  const [processingMinimized, setProcessingMinimized] = useState(false)
  const pollingIntervalRef = useRef(null)
  const processingCardRef = useRef(null)
  
  // Stuck request auto-cancel state
  const processingStartTimeRef = useRef(null)
  const stuckTimerRef = useRef(null)
  const [stuckMinutes, setStuckMinutes] = useState(0)
  const [stuckCancelling, setStuckCancelling] = useState(false)

  // Document upload state
  const [uploading, setUploading] = useState(false)
  const fileInputRef = useRef(null)
  const docTabsRef = useRef(null)
  const pageThumbnailsRef = useRef(null)
  
  // Document processing banner state (for initial docs still being processed)
  const [documentsStillProcessing, setDocumentsStillProcessing] = useState(false)
  const [processingComplete, setProcessingComplete] = useState(false)
  const [processingProgress, setProcessingProgress] = useState({ percent: 0, message: '' })
  const [processingLog, setProcessingLog] = useState([])
  const [showProcessingLog, setShowProcessingLog] = useState(false)
  const processingBannerPollRef = useRef(null)
  const processingJobIdRef = useRef(null)
  const processingLogPollRef = useRef(null)
  const logBottomRef = useRef(null)
  
  // View/Edit mode for published requests
  // If navigated with ?mode=edit, start in edit mode; otherwise view mode
  const [isEditMode, setIsEditMode] = useState(modeFromUrl === 'edit')
  const [originalFields, setOriginalFields] = useState([]) // For discard functionality
  
  // Editable request metadata (title, description, issuer)
  const [editedMetadata, setEditedMetadata] = useState({ title: '', description: '', issuer: '' })
  const [originalMetadata, setOriginalMetadata] = useState({ title: '', description: '', issuer: '' })
  
  // Save reason modal state
  const [showSaveReasonModal, setShowSaveReasonModal] = useState(false)
  const [saveReason, setSaveReason] = useState('')
  
  // Cancel reason modal state
  const [showCancelReasonModal, setShowCancelReasonModal] = useState(false)
  const [cancelReason, setCancelReason] = useState('')
  const [cancelError, setCancelError] = useState('')
  const [cancelling, setCancelling] = useState(false)
  const [publishing, setPublishing] = useState(false)
  
  // Cost breakdown modal
  const [showCostModal, setShowCostModal] = useState(false)

  // PDF Viewer panel visibility toggle
  const [isPdfViewerVisible, setIsPdfViewerVisible] = useState(true)
  
  // Computed: true when request is completed/cancelled
  const isViewOnly = request?.status === 'completed' || request?.status === 'cancelled'
  
  // Computed: true when fields should be disabled (view mode for completed/cancelled/approved/published)
  const isFieldsDisabled = (isViewOnly || request?.status === 'approved' || request?.status === 'published') && !isEditMode
  
  // Fetch audit logs
  const fetchAuditLogs = async () => {
    try {
      setLoadingAuditLogs(true)
      const res = await requestsApi.getAuditLogs(id, { limit: 20 })
      const logs = res.data.audit_logs || []
      
      // Transform audit logs to activity log format
      // Filter out low-value entries (INSERTs from extraction, empty changes, null-only values)
      const formattedLogs = logs
        .filter(log => {
          const changes = log.changes || []
          // Skip if no changes recorded
          if (changes.length === 0) return false
          // Skip INSERT logs from system (extraction) - they don't add value
          if (log.action === 'INSERT' && !log.created_by_name) return false
          // For UPDATE: skip if all changes have both old and new as null/empty
          if (log.action === 'UPDATE') {
            const hasMeaningfulChange = changes.some(c => {
              const oldVal = c.old_value
              const newVal = c.new_value
              // At least one side must have a real non-null, non-empty value
              return (oldVal !== null && oldVal !== undefined && oldVal !== '') ||
                     (newVal !== null && newVal !== undefined && newVal !== '')
            })
            if (!hasMeaningfulChange) return false
          }
          return true
        })
        .map(log => {
          const changes = log.changes || []
          // Filter out individual changes where both old and new are null/empty
          const meaningfulChanges = changes.filter(c => {
            const oldVal = c.old_value
            const newVal = c.new_value
            return (oldVal !== null && oldVal !== undefined && oldVal !== '') ||
                   (newVal !== null && newVal !== undefined && newVal !== '')
          })
          const firstChange = meaningfulChanges[0]
          let action = ''
          let icon = 'user'
          
          const formatValue = (val) => {
            if (val === null || val === undefined || val === '') return '(empty)'
            return String(val)
          }
          
          if (log.action === 'INSERT') {
            action = `${log.created_by_name || 'System'} added ${firstChange?.display_label || 'field'}`
            if (firstChange?.new_value != null && firstChange.new_value !== '') {
              action += `: "${formatValue(firstChange.new_value)}"`
            }
            icon = log.created_by_name ? 'user' : 'system'
          } else if (log.action === 'UPDATE') {
            if (meaningfulChanges.length === 1 && firstChange) {
              // Single field changed - show details
              const fieldLabel = firstChange.display_label || 'field'
              action = `${log.created_by_name || 'User'} edited ${fieldLabel}`
              action += `: "${formatValue(firstChange.old_value)}" → "${formatValue(firstChange.new_value)}"`
            } else if (meaningfulChanges.length > 1) {
              // Multiple fields changed - list them
              const fieldLabels = meaningfulChanges.map(c => c.display_label || c.field).filter(Boolean)
              action = `${log.created_by_name || 'User'} edited ${fieldLabels.join(', ')}`
            } else {
              action = `${log.created_by_name || 'User'} edited ${firstChange?.display_label || 'field'}`
            }
            icon = 'user'
          } else if (log.action === 'DELETE') {
            action = `${log.created_by_name || 'User'} removed ${firstChange?.display_label || 'field'}`
            icon = 'user'
          }
          
          return {
            id: log.id,
            action,
            time: formatTimeAgo(log.created_at),
            icon,
            details: log
          }
        })
      
      setActivityLog(formattedLogs)
      
      // Transform UPDATE logs to edit history format (filter out null/empty changes)
      const historyItems = logs
        .filter(log => log.action === 'UPDATE')
        .flatMap(log => {
          const changes = log.changes || []
          return changes
            .filter(change => {
              // Only include changes with at least one meaningful value
              const oldVal = change.old_value
              const newVal = change.new_value
              return (oldVal !== null && oldVal !== undefined && oldVal !== '') ||
                     (newVal !== null && newVal !== undefined && newVal !== '')
            })
            .map((change, idx) => ({
              id: `${log.id}-${idx}`,
              timestamp: formatAuditTimestamp(log.created_at),
              oldValue: (change.old_value !== null && change.old_value !== undefined && change.old_value !== '') ? String(change.old_value) : '-',
              newValue: (change.new_value !== null && change.new_value !== undefined && change.new_value !== '') ? String(change.new_value) : '-',
              user: log.created_by_name || 'User',
              fieldName: change.display_label || change.field
            }))
        })
        .slice(0, 10) // Limit to 10 most recent edits
      
      setEditHistory(historyItems)
    } catch (err) {
      console.error('Error fetching audit logs:', err)
      // Fallback to demo data if API fails
      setActivityLog([
        { id: 1, action: 'No recent activity', time: '', icon: 'system' }
      ])
      setEditHistory([])
    } finally {
      setLoadingAuditLogs(false)
    }
  }
  
  // Batch fetch audit summary for all fields (single API call)
  const fetchFieldsAuditSummary = async () => {
    try {
      const res = await requestsApi.getFieldsAuditSummary(id)
      setFieldsAuditMap(res.data.fields_with_history || {})
    } catch (err) {
      console.error('Error fetching fields audit summary:', err)
      setFieldsAuditMap({})
    }
  }
  
  // Format time ago helper (UK timezone-aware)
  const formatTimeAgo = formatTimeAgoUtil
  
  const fetchRequest = async () => {
    try {
      setLoading(true)
      const res = await requestsApi.get(id)
      setRequest(res.data)
      setEditedFields(res.data.fields || [])
      // Store original fields for discard functionality
      setOriginalFields(JSON.parse(JSON.stringify(res.data.fields || [])))
      
      // Set editable metadata
      const metadata = {
        title: res.data.title || '',
        description: res.data.description || '',
        issuer: res.data.issuer || ''
      }
      setEditedMetadata(metadata)
      setOriginalMetadata(JSON.parse(JSON.stringify(metadata)))
      
      // Load processing log from last_job if available (persists after job completes)
      if (res.data.last_job?.result_data?.processing_log) {
        setProcessingLog(res.data.last_job.result_data.processing_log)
      }
      
      setError(null)
      
      if (res.data.documents && res.data.documents.length > 0) {
        const pdfDoc = res.data.documents.find(
          doc => doc.content_type === 'application/pdf' || doc.filename?.endsWith('.pdf')
        )
        if (pdfDoc) {
          setDocumentId(pdfDoc.id)
        }
      }
      
    } catch (err) {
      console.error('Error fetching request:', err)
      setError('Failed to load request')
    } finally {
      setLoading(false)
    }
  }
  
  // Silent poll: fetch request data without loading spinner or PDF remount.
  // Merges status + fields only. When status changes from processing → done, does one full refresh.
  const silentPollRequest = async () => {
    try {
      const res = await requestsApi.get(id)
      const fresh = res.data
      
      setRequest(prev => {
        if (!prev) return fresh
        
        // If status changed from processing/pending → something else, let the
        // polling effect handle a full fetchRequest on next cycle
        const statusChanged = prev.status !== fresh.status
        
        // Merge: keep the same object identity for documents (so PDFViewer doesn't remount)
        // but update fields, status, metadata, active_job, last_job
        return {
          ...prev,
          status: fresh.status,
          fields: fresh.fields,
          active_job: fresh.active_job,
          last_job: fresh.last_job,
          title: fresh.title,
          description: fresh.description,
          issuer: fresh.issuer,
          updated_at: fresh.updated_at,
          // Only update documents array if the count changed (new doc uploaded)
          documents: (prev.documents?.length !== fresh.documents?.length) ? fresh.documents : prev.documents,
        }
      })
      
      // Update fields for the form (only if user hasn't made local edits)
      setEditedFields(prev => {
        // If the field values are identical to what we already have, skip
        const freshFields = fresh.fields || []
        if (JSON.stringify(prev) === JSON.stringify(freshFields)) return prev
        return freshFields
      })
      setOriginalFields(JSON.parse(JSON.stringify(fresh.fields || [])))
      
      // Update processing log if available
      if (fresh.last_job?.result_data?.processing_log) {
        setProcessingLog(fresh.last_job.result_data.processing_log)
      }
      
      setError(null)
    } catch (err) {
      // Silently ignore poll errors — don't blank the page
      console.warn('Silent poll error:', err.message)
    }
  }

  useEffect(() => {
    fetchRequest()
    fetchAuditLogs()  // Fetch audit logs on mount
    // Fetch batch audit summary for all fields (single API call instead of N)
    fetchFieldsAuditSummary()
  }, [id])
  
  // Polling effect for processing status
  useEffect(() => {
    // Check if request is in processing status
    const isProcessing = request?.status === 'processing' || request?.status === 'pending'
    setShowProcessingModal(isProcessing)
    
    if (isProcessing) {
      // Track when processing started (use request updated_at or current time)
      if (!processingStartTimeRef.current) {
        const startTime = request?.updated_at ? new Date(request.updated_at) : new Date()
        processingStartTimeRef.current = startTime
      }
      
      setShowProcessingLog(true) // Auto-open the log panel
      // Start silent polling every 15 seconds (no loading spinner, no PDF reload)
      pollingIntervalRef.current = setInterval(() => {
        silentPollRequest()
      }, 15000)

      // Also poll the processing log every 3 seconds for real-time step updates
      const activeJobId = request?.active_job?.id
      if (activeJobId) {
        processingJobIdRef.current = activeJobId
        // Initial fetch immediately
        jobsApi.getProcessingLog(activeJobId).then(res => {
          const data = res.data
          setProcessingLog(data.processing_log || [])
          setProcessingProgress({
            percent: data.progress_percent || 0,
            message: data.progress_message || 'Starting...'
          })
        }).catch(() => {})

        processingLogPollRef.current = setInterval(async () => {
          try {
            const res = await jobsApi.getProcessingLog(activeJobId)
            const data = res.data
            setProcessingLog(data.processing_log || [])
            setProcessingProgress({
              percent: data.progress_percent || 0,
              message: data.progress_message || 'Processing...'
            })
          } catch (err) {
            // Silently ignore — job may have completed
          }
        }, 3000)
      }
      
      // Start stuck timer — update elapsed minutes every 30 seconds
      stuckTimerRef.current = setInterval(() => {
        if (processingStartTimeRef.current) {
          const elapsed = Math.floor((Date.now() - processingStartTimeRef.current.getTime()) / 60000)
          setStuckMinutes(elapsed)
        }
      }, 30000)
      // Also compute immediately
      if (processingStartTimeRef.current) {
        const elapsed = Math.floor((Date.now() - processingStartTimeRef.current.getTime()) / 60000)
        setStuckMinutes(elapsed)
      }
    } else {
      // Clear polling when not processing
      if (pollingIntervalRef.current) {
        clearInterval(pollingIntervalRef.current)
        pollingIntervalRef.current = null
      }
      if (processingLogPollRef.current) {
        clearInterval(processingLogPollRef.current)
        processingLogPollRef.current = null
      }
      // Clear stuck timer
      if (stuckTimerRef.current) {
        clearInterval(stuckTimerRef.current)
        stuckTimerRef.current = null
      }
      processingStartTimeRef.current = null
      setStuckMinutes(0)
    }
    
    // Cleanup on unmount or status change
    return () => {
      if (pollingIntervalRef.current) {
        clearInterval(pollingIntervalRef.current)
      }
      if (processingLogPollRef.current) {
        clearInterval(processingLogPollRef.current)
      }
      if (stuckTimerRef.current) {
        clearInterval(stuckTimerRef.current)
      }
    }
  }, [request?.status, request?.active_job?.id])
  
  // Document processing banner: detect when request is in reviewing/extracted status but still has an active job
  // Uses lightweight job status polling to avoid resetting user edits
  useEffect(() => {
    const activeJob = request?.active_job
    const isReviewingButStillProcessing = 
      activeJob && 
      (activeJob.status === 'pending' || activeJob.status === 'running') &&
      (request?.status === 'reviewing' || request?.status === 'extracted')
    
    if (isReviewingButStillProcessing) {
      setDocumentsStillProcessing(true)
      setProcessingComplete(false)
      setShowProcessingLog(true) // Auto-open log panel
      processingJobIdRef.current = activeJob.id
      setProcessingProgress({
        percent: activeJob.progress_percent || 0,
        message: activeJob.progress_message || 'Processing remaining documents...'
      })
      
      // Poll every 10 seconds using lightweight job status endpoint (no data reset)
      if (!processingBannerPollRef.current && activeJob.id) {
        processingBannerPollRef.current = setInterval(async () => {
          try {
            // Use processing-log endpoint to get both status AND step logs
            const res = await jobsApi.getProcessingLog(processingJobIdRef.current)
            const data = res.data
            if (data.processing_log) {
              setProcessingLog(data.processing_log)
            }
            if (data.status === 'completed' || data.status === 'failed') {
              // Job finished — show completed banner, don't auto-refresh
              clearInterval(processingBannerPollRef.current)
              processingBannerPollRef.current = null
              setDocumentsStillProcessing(false)
              setProcessingComplete(true)
              setProcessingProgress({
                percent: 100,
                message: data.status === 'completed' 
                  ? 'All documents processed successfully!' 
                  : `Processing finished with errors: ${data.error_message || 'Unknown error'}`
              })
              

            } else {
              // Still running — update progress
              setProcessingProgress({
                percent: data.progress_percent || 0,
                message: data.progress_message || 'Processing remaining documents...'
              })
            }
          } catch (err) {
            console.error('Error polling job status:', err)
          }
        }, 5000)
      }
    }
    
    return () => {
      if (processingBannerPollRef.current) {
        clearInterval(processingBannerPollRef.current)
        processingBannerPollRef.current = null
      }
    }
  }, [request?.active_job?.id, request?.status])
  
  // Handler for manual refresh after processing completes
  const handleProcessingRefresh = () => {
    setProcessingComplete(false)
    setDocumentsStillProcessing(false)
    fetchRequest()
    fetchAuditLogs()
    fetchFieldsAuditSummary()
  }
  
  // Warn before leaving with unsaved changes
  useEffect(() => {
    const handleBeforeUnload = (e) => {
      if (hasUnsavedChanges()) {
        e.preventDefault()
        e.returnValue = ''
      }
    }
    window.addEventListener('beforeunload', handleBeforeUnload)
    return () => window.removeEventListener('beforeunload', handleBeforeUnload)
  })
  
  // Ctrl+S / Cmd+S keyboard shortcut to save (Save Changes only, never Publish)
  useEffect(() => {
    const handleKeyDown = (e) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault()
        if (saving || publishing) return
        
        const isPublishedOrApproved = request?.status === 'approved' || request?.status === 'published'
        
        if (isPublishedOrApproved) {
          // Published/approved requests require edit mode + save reason modal
          if (isEditMode && hasUnsavedChanges()) {
            setShowSaveReasonModal(true)
          }
        } else if (!isViewOnly) {
          // Draft/pending requests: direct save
          if (hasUnsavedChanges()) {
            handleSaveChanges()
          }
        }
        // Cancelled/completed (isViewOnly) requests: Ctrl+S does nothing
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  })

  // Field search filter state
  const [fieldSearchQuery, setFieldSearchQuery] = useState('')
  
  const handleSaveChanges = async () => {
    try {
      setSaving(true)
      // Update request metadata if changed
      if (JSON.stringify(editedMetadata) !== JSON.stringify(originalMetadata)) {
        await requestsApi.update(id, {
          title: editedMetadata.title,
          description: editedMetadata.description,
          issuer: editedMetadata.issuer
        })
        setOriginalMetadata(JSON.parse(JSON.stringify(editedMetadata)))
      }
      await requestsApi.updateFields(id, editedFields, 'User saved changes')
      setOriginalFields(JSON.parse(JSON.stringify(editedFields)))
      toast.success('Changes saved successfully')
      fetchRequest()
      fetchAuditLogs()  // Refresh audit logs after save
    } catch (err) {
      console.error('Error saving fields:', err)
      toast.error('Failed to save changes')
      setError('Failed to save fields')
    } finally {
      setSaving(false)
    }
  }
  
  // Handler for saving with reason (for published requests)
  const handleSaveWithReason = async () => {
    if (!saveReason.trim()) return
    try {
      setSaving(true)
      // Update request metadata if changed
      if (JSON.stringify(editedMetadata) !== JSON.stringify(originalMetadata)) {
        await requestsApi.update(id, {
          title: editedMetadata.title,
          description: editedMetadata.description,
          issuer: editedMetadata.issuer
        })
      }
      // Update fields
      await requestsApi.updateFields(id, editedFields, saveReason)
      // Update originals after successful save
      setOriginalFields(JSON.parse(JSON.stringify(editedFields)))
      setOriginalMetadata(JSON.parse(JSON.stringify(editedMetadata)))
      setShowSaveReasonModal(false)
      setSaveReason('')
      setIsEditMode(false) // Exit edit mode after save
      toast.success('Changes saved with reason')
      fetchRequest()
      fetchAuditLogs()
    } catch (err) {
      console.error('Error saving fields:', err)
      toast.error('Failed to save changes')
      setError('Failed to save fields')
    } finally {
      setSaving(false)
    }
  }
  
  // Handler for discarding changes
  const handleDiscardChanges = () => {
    setEditedFields(JSON.parse(JSON.stringify(originalFields)))
    setEditedMetadata(JSON.parse(JSON.stringify(originalMetadata)))
    setIsEditMode(false)
  }
  
  // Handler for entering edit mode
  const handleEnterEditMode = () => {
    // Store current values as original before editing
    setOriginalFields(JSON.parse(JSON.stringify(editedFields)))
    setOriginalMetadata(JSON.parse(JSON.stringify(editedMetadata)))
    setIsEditMode(true)
  }
  
  // Check if fields or metadata have been modified
  const hasUnsavedChanges = () => {
    const fieldsChanged = JSON.stringify(editedFields) !== JSON.stringify(originalFields)
    const metadataChanged = JSON.stringify(editedMetadata) !== JSON.stringify(originalMetadata)
    return fieldsChanged || metadataChanged
  }
  
  const handlePublish = async () => {
    try {
      setPublishing(true)
      // Save metadata if changed
      if (JSON.stringify(editedMetadata) !== JSON.stringify(originalMetadata)) {
        await requestsApi.update(id, {
          title: editedMetadata.title,
          description: editedMetadata.description,
          issuer: editedMetadata.issuer
        })
      }
      // Save changes first with reason
      await requestsApi.updateFields(id, editedFields, 'User published changes')
      await requestsApi.approve(id)
      toast.success('Request published successfully')
      fetchRequest()
      fetchAuditLogs()  // Refresh audit logs after publish
    } catch (err) {
      console.error('Error publishing:', err)
      toast.error('Failed to publish request')
      setError('Failed to publish')
    } finally {
      setPublishing(false)
    }
  }
  
  const handleAlternativeSelect = async (altFieldId, fieldName, altData) => {
    try {
      await requestsApi.setFieldActive(id, altFieldId)
      
      // Update only the affected field locally — preserves other fields' unsaved edits
      const updateField = (f) => {
        if (f.field_name === fieldName) {
          return {
            ...f,
            id: altData.id,
            field_value: altData.field_value || altData.extracted_value || '',
            extracted_value: altData.extracted_value || altData.field_value || '',
            confidence: altData.confidence,
            source_id: altData.source_document_id,
            source_document_id: altData.source_document_id,
            source_document_filename: altData.source_document_filename,
            page_number: altData.page_number,
            bounding_box: altData.bounding_box
          }
        }
        return f
      }
      
      setEditedFields(prev => prev.map(updateField))
      // Also update originalFields so hasUnsavedChanges() stays accurate
      // (alternative selection is persisted server-side immediately)
      setOriginalFields(prev => prev.map(updateField))
      
      fetchAuditLogs()  // Refresh audit logs after alternative selection
      fetchFieldsAuditSummary() // Refresh batch audit summary
    } catch (err) {
      console.error('Error selecting alternative:', err)
      setError('Failed to select alternative value')
    }
  }
  
  const handleCancel = async () => {
    if (!cancelReason.trim()) return
    setCancelError('')
    setCancelling(true)
    try {
      await requestsApi.cancel(id, cancelReason)
      setShowCancelReasonModal(false)
      setCancelReason('')
      setCancelError('')
      navigate(-1)
    } catch (err) {
      console.error('Error cancelling:', err)
      setCancelError(err?.response?.data?.error || 'Failed to cancel request. Please try again.')
    } finally {
      setCancelling(false)
    }
  }
  
  // Auto-cancel stuck request from processing modal
  const handleStuckCancel = async () => {
    setStuckCancelling(true)
    try {
      const reason = `Request stuck in processing for ${stuckMinutes} minute${stuckMinutes !== 1 ? 's' : ''} — auto-cancelled`
      await requestsApi.cancel(id, reason)
      setShowProcessingModal(false)
      navigate(-1)
    } catch (err) {
      console.error('Error cancelling stuck request:', err)
      toast.error('Failed to cancel stuck request. Please try again.')
    } finally {
      setStuckCancelling(false)
    }
  }

  const handleFieldChange = (fieldId, newValue) => {
    setEditedFields(prev => 
      prev.map(f => f.id === fieldId ? { ...f, field_value: newValue } : f)
    )
  }
  
  // Handle document upload to request
  const handleDocumentUpload = async (e) => {
    const file = e.target.files?.[0]
    if (!file) return
    // Reset the input so the same file can be re-selected
    e.target.value = ''
    try {
      setUploading(true)
      const res = await requestsApi.uploadDocument(id, file)
      const newDocId = res.data?.id
      toast.success(`"${file.name}" uploaded successfully`)
      // Refresh request to include the new document in tabs
      const refreshed = await requestsApi.get(id)
      const updatedRequest = refreshed.data
      setRequest(updatedRequest)
      setEditedFields(updatedRequest.fields || [])
      // Switch to the newly uploaded document tab
      const docs = updatedRequest.documents || []
      const newIdx = newDocId ? docs.findIndex(d => d.id === newDocId) : docs.length - 1
      if (newIdx >= 0) {
        setActiveDocTab(newIdx)
        setDocumentId(docs[newIdx].id)
        // Auto-scroll tab bar to make the new tab visible
        setTimeout(() => {
          const tabEl = docTabsRef.current?.querySelector(`[data-doc-tab="${newIdx}"]`)
          if (tabEl) tabEl.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'nearest' })
        }, 100)
      }
    } catch (err) {
      console.error('Error uploading document:', err)
      toast.error(err?.response?.data?.error || 'Failed to upload document')
    } finally {
      setUploading(false)
    }
  }

  // Handle field click - switch to correct document and highlight field
  const handleFieldClick = (field) => {
    const documents = request?.documents || []
    
    // Only highlight if field has an actual extracted value
    const hasExtractedValue = (field.field_value && field.field_value.trim() !== '') || (field.extracted_value && field.extracted_value.trim() !== '')
    
    // If field has source_id (document ID) and has a value, switch to that document
    if (hasExtractedValue && field.source_id && documents.length > 0) {
      const docIndex = documents.findIndex(doc => doc.id === field.source_id)
      if (docIndex !== -1) {
        setActiveDocTab(docIndex)
        setDocumentId(documents[docIndex].id)
      }
    }
    
    // Only set the highlighted field if there's a value to highlight
    if (hasExtractedValue) {
      setHighlightedField(field)
      
      // Auto-scroll the page thumbnails sidebar to the first relevant page
      const firstPage = field.page_number
      if (firstPage && pageThumbnailsRef.current) {
        setTimeout(() => {
          const btn = pageThumbnailsRef.current?.querySelector(`[data-page="${firstPage}"]`)
          if (btn) btn.scrollIntoView({ behavior: 'smooth', block: 'nearest' })
        }, 100)
      }
    } else {
      // Clear any previous highlight for empty fields
      setHighlightedField(null)
    }
  }
  
  // Reset page thumbnails to default state (clear field highlight, keep current page)
  const handleResetPageView = () => {
    setHighlightedField(null)
  }
  
  // Handle viewing a field value in the PDF viewer
  const handleViewInDocument = (docId, pageNumber, boundingBox) => {
    const documents = request?.documents || []
    
    // Switch to the correct document
    if (docId && documents.length > 0) {
      const docIndex = documents.findIndex(doc => doc.id === docId)
      if (docIndex !== -1) {
        setActiveDocTab(docIndex)
        setDocumentId(documents[docIndex].id)
      }
    }
    
    // Set page and highlight
    if (pageNumber) {
      setCurrentPage(pageNumber)
    }
    
    // Set highlight info for bounding box
    if (boundingBox) {
      setHighlightedField({ bounding_box: boundingBox, page_number: pageNumber })
    }
  }
  
  const handleSearch = () => {
    if (!searchText.trim()) {
      setSearchResults([])
      return
    }
    setSearchResults([
      { page: 1, count: 3 },
      { page: 5, count: 1 },
    ])
  }
  
  // Calculate average confidence: sum of all extracted field confidences / number of extracted fields, as 0-100
  const extractedFields = editedFields.filter(f => f.confidence != null && f.confidence > 0)
  const avgConfidence = extractedFields.length > 0 
    ? Math.min(100, Math.max(0, Math.round((extractedFields.reduce((sum, f) => sum + (f.confidence || 0), 0) / extractedFields.length) * 100)))
    : 0
  
  // Required-field gating removed — all fields are optional.
  // Publish is always allowed regardless of empty fields.
  const emptyRequiredFields = []
  const hasEmptyRequiredFields = false
  
  // Group fields dynamically based on template or fallback to static categories
  const getFieldsByCategory = () => {
    // ALWAYS use stored extraction fields as the primary source.
    // Template fields may have changed since extraction — stored data must never disappear.
    if (!editedFields || editedFields.length === 0) return {}

    // Build a lookup from current template fields for supplemental metadata only
    const templateFieldMap = {}
    if (request?.template?.fields_by_category) {
      Object.entries(request.template.fields_by_category).forEach(([category, tFields]) => {
        tFields.forEach(tf => {
          templateFieldMap[tf.field_name] = { ...tf, _category: category }
        })
      })
    }

    const result = {}
    editedFields.forEach(f => {
      // Email-extracted fields go into their own category for clear segregation
      const isEmailField = f.source_type === 'email_body'
      
      // Determine category: email fields → 'email_extracted',
      // otherwise prefer template snapshot, then current template, then 'other'
      const category = isEmailField
        ? 'email_extracted'
        : (f.template_field?.category ||
           templateFieldMap[f.field_name]?._category ||
           'other')

      // Determine display_name: prefer stored template_field, then current template, then derive from field_name
      const tf = templateFieldMap[f.field_name]
      const display_name =
        f.template_field?.display_name ||
        tf?.display_name ||
        f.field_name.replace(/([A-Z])/g, ' $1').replace(/^./, s => s.toUpperCase()).trim()

      if (!result[category]) result[category] = []
      result[category].push({
        ...f,
        display_name,
        field_type: f.template_field?.field_type || tf?.field_type || 'text',
        field_values: f.template_field?.field_values || tf?.field_values || null,
        is_required: false,  // Required-field concept removed — all fields optional
        sort_order: f.template_field?.sort_order ?? tf?.sort_order ?? 999,
        ui_properties: tf?.ui_properties || null,
      })
    })

    // Sort fields within each category by sort_order
    Object.values(result).forEach(arr =>
      arr.sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0))
    )

    return result
  }
  
  const fieldsByCategory = getFieldsByCategory()
  
  // Get category order from template (defines the order categories appear in UI)
  const categoryOrder = request?.template?.category_order || []
  
  // Build category metadata map from category_order (includes display names, icons, colors)
  const categoryMetadata = categoryOrder.reduce((acc, cat) => {
    acc[cat.name] = {
      displayName: cat.display_name,
      description: cat.description,
      icon: cat.icon,
      color: cat.color,
      isVisible: cat.is_visible
    }
    return acc
  }, {})
  
  // Get category display names from template metadata or use fallback defaults
  const getCategoryDisplayName = (categoryName) => {
    if (categoryName === 'email_extracted') return '📧 Email Extracted Fields'
    return categoryMetadata[categoryName]?.displayName || 
           request?.template?.category_display_names?.[categoryName] || 
           categoryName.charAt(0).toUpperCase() + categoryName.slice(1).replace(/_/g, ' ')
  }
  
  // Get category color for styling
  const getCategoryColor = (categoryName) => {
    if (categoryName === 'email_extracted') return '#6366f1'  // Indigo for email fields
    return categoryMetadata[categoryName]?.color || 'gray'
  }
  
  // Get ordered categories based on template category_order, or fallback to Object.keys
  const getOrderedCategories = () => {
    const allCats = Object.keys(fieldsByCategory).filter(cat => fieldsByCategory[cat]?.length > 0)

    let ordered
    if (categoryOrder.length > 0) {
      // Use the order defined in the database, filter by visibility and available fields
      ordered = categoryOrder
        .filter(co => co.is_visible !== false)
        .map(co => co.name)
        .filter(name => fieldsByCategory[name] && fieldsByCategory[name].length > 0)
      // Append any categories from stored fields that aren't in the current template order
      const orderedSet = new Set(ordered)
      allCats.forEach(cat => {
        if (!orderedSet.has(cat)) ordered.push(cat)
      })
    } else {
      ordered = [...allCats]
    }
    
    // Email-extracted fields always appear last for clear visual segregation
    if (ordered.includes('email_extracted')) {
      ordered = ordered.filter(c => c !== 'email_extracted')
      ordered.push('email_extracted')
    }
    
    return ordered
  }
  
  const orderedCategories = getOrderedCategories()
  
  // Get document icon based on file type
  const getDocIcon = (filename) => {
    if (filename?.endsWith('.pdf')) return FileText
    if (filename?.endsWith('.xlsx') || filename?.endsWith('.xls')) return FileSpreadsheet
    return File
  }

  // Check if a document is a PDF (viewable in PDF viewer)
  const isPdfDocument = (doc) => {
    if (!doc) return false
    if (doc.content_type === 'application/pdf') return true
    if (doc.filename?.toLowerCase().endsWith('.pdf')) return true
    return false
  }

  // Get human-readable file type label
  const getFileTypeLabel = (filename) => {
    if (!filename) return 'Document'
    const ext = filename.split('.').pop()?.toLowerCase()
    const labels = {
      xlsx: 'Excel Spreadsheet', xls: 'Excel Spreadsheet',
      doc: 'Word Document', docx: 'Word Document',
      csv: 'CSV File', txt: 'Text File',
      msg: 'Email Message', eml: 'Email Message',
      png: 'Image', jpg: 'Image', jpeg: 'Image',
      gif: 'Image', bmp: 'Image',
    }
    return labels[ext] || `${(ext || '').toUpperCase()} File`
  }
  
  if (loading) {
    return (
      <div className="flex items-center justify-center h-screen bg-gray-50 dark:bg-gray-950">
        <div className="flex flex-col items-center gap-3">
          <div className="animate-spin rounded-full h-10 w-10 border-2 border-navy-800 border-t-transparent"></div>
          <p className="text-sm text-gray-500 dark:text-gray-400">Loading document...</p>
        </div>
      </div>
    )
  }
  
  if (error) {
    return (
      <div className="p-6 bg-gray-50 dark:bg-gray-950 min-h-screen">
        <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200 mb-4">
          <ArrowLeft className="h-4 w-4" />
          Back
        </button>
        <div className="bg-red-50 dark:bg-red-900/30 border border-red-200 dark:border-red-800 rounded-xl p-4 flex items-center">
          <AlertCircle className="h-5 w-5 text-red-500 dark:text-red-400 mr-2" />
          <span className="text-red-700 dark:text-red-300">{error}</span>
        </div>
      </div>
    )
  }
  
  if (!request) return null

  const documents = request.documents || []
  const activeDocument = documents[activeDocTab]

  return (
    <div className="-m-6 flex bg-gray-100 dark:bg-gray-950 overflow-hidden" style={{ height: 'calc(100vh - 4rem)' }}>
      {/* AI Processing Modal — centered on screen, click backdrop to minimize */}
      {showProcessingModal && (
        processingMinimized ? (
          /* Minimized pill - bottom-right corner */
          <button
            onClick={() => setProcessingMinimized(false)}
            className="fixed bottom-6 right-6 z-50 flex items-center gap-2.5 px-4 py-2.5 bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-full shadow-lg hover:shadow-xl transition-all group"
          >
            <div className="relative">
              <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-purple-600 rounded-full flex items-center justify-center">
                <Bot className="h-4 w-4 text-white" />
              </div>
              <div className="absolute inset-0 w-8 h-8">
                <svg className="w-full h-full animate-spin" style={{ animationDuration: '3s' }} viewBox="0 0 100 100">
                  <circle cx="50" cy="50" r="46" fill="none" stroke="url(#gradient-mini)" strokeWidth="4" strokeLinecap="round" strokeDasharray="100 200" />
                  <defs>
                    <linearGradient id="gradient-mini" x1="0%" y1="0%" x2="100%" y2="100%">
                      <stop offset="0%" stopColor="#3b82f6" />
                      <stop offset="100%" stopColor="#8b5cf6" />
                    </linearGradient>
                  </defs>
                </svg>
              </div>
            </div>
            <div className="text-left">
              <p className="text-xs font-semibold text-gray-900 dark:text-gray-100">Processing...</p>
              <p className="text-[10px] text-gray-500 dark:text-gray-400">{processingProgress.percent}% — click to expand</p>
            </div>
            <Maximize2 className="h-3.5 w-3.5 text-gray-400 group-hover:text-gray-600 dark:group-hover:text-gray-300 ml-1" />
          </button>
        ) : (
          /* Full centered modal — click backdrop to minimize to pill */
          <div className="fixed inset-0 z-50 flex items-center justify-center">
            {/* Backdrop — click to minimize */}
            <div 
              className="absolute inset-0 bg-navy-900/60 backdrop-blur-sm"
              onClick={() => setProcessingMinimized(true)}
            />
            
            {/* Modal Content */}
            <div className="relative bg-white dark:bg-gray-900 rounded-2xl shadow-2xl border border-gray-200 dark:border-gray-700 p-8 max-w-lg w-full mx-4 animate-fade-in">
              {/* Decorative gradient border effect */}
              <div className="absolute inset-0 rounded-2xl bg-gradient-to-r from-blue-500 via-purple-500 to-blue-500 opacity-10 animate-pulse"></div>
              
              <div className="relative flex flex-col items-center text-center">
                {/* AI icon */}
                <div className="relative mb-4">
                  <div className="w-16 h-16 bg-gradient-to-br from-blue-500 to-purple-600 rounded-full flex items-center justify-center shadow-lg">
                    <Bot className="h-8 w-8 text-white" />
                  </div>
                  <div className="absolute inset-0 w-16 h-16">
                    <svg className="w-full h-full animate-spin" style={{ animationDuration: '3s' }} viewBox="0 0 100 100">
                      <circle cx="50" cy="50" r="46" fill="none" stroke="url(#gradient)" strokeWidth="3" strokeLinecap="round" strokeDasharray="100 200" />
                      <defs>
                        <linearGradient id="gradient" x1="0%" y1="0%" x2="100%" y2="100%">
                          <stop offset="0%" stopColor="#3b82f6" />
                          <stop offset="50%" stopColor="#8b5cf6" />
                          <stop offset="100%" stopColor="#3b82f6" />
                        </linearGradient>
                      </defs>
                    </svg>
                  </div>
                </div>
                
                {/* Title and progress */}
                <h3 className="text-lg font-bold text-gray-900 dark:text-gray-100 mb-1">
                  AI is Extracting Details
                </h3>
                
                {/* Progress bar */}
                <div className="w-full mb-3">
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-xs text-gray-500 dark:text-gray-400">
                      {processingProgress.message || 'Starting...'}
                    </span>
                    <span className="text-xs font-semibold text-blue-600 dark:text-blue-400">
                      {processingProgress.percent}%
                    </span>
                  </div>
                  <div className="w-full h-2 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-gradient-to-r from-blue-500 to-purple-500 rounded-full transition-all duration-500"
                      style={{ width: `${Math.max(processingProgress.percent, 2)}%` }}
                    ></div>
                  </div>
                </div>
                
                {/* Real-time processing log */}
                <div className="w-full bg-gray-50 dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 max-h-64 overflow-y-auto text-left">
                  {processingLog.length === 0 ? (
                    <div className="p-3 flex items-center gap-2 text-xs text-gray-400">
                      <Loader2 className="h-3 w-3 animate-spin" />
                      <span>Waiting for processing to start...</span>
                    </div>
                  ) : (
                    <div className="divide-y divide-gray-100 dark:divide-gray-700">
                      {processingLog.map((step, idx) => (
                        <div key={idx} className="px-3 py-1.5 flex items-start gap-2">
                          <span className="text-[10px] font-mono text-gray-400 dark:text-gray-500 whitespace-nowrap mt-0.5">
                            {step.elapsed_seconds != null ? `${step.elapsed_seconds}s` : step.timestamp}
                          </span>
                          <span className={`text-xs ${
                            step.message?.includes('\u2705') ? 'text-green-600 dark:text-green-400 font-medium' :
                            step.message?.includes('\u274C') || step.message?.includes('\u26A0\uFE0F') ? 'text-red-600 dark:text-red-400' :
                            step.message?.includes('\u23F3') || step.message?.includes('Polling') || step.message?.includes('waiting') ? 'text-amber-600 dark:text-amber-400' :
                            'text-gray-700 dark:text-gray-300'
                          }`}>
                            {step.message}
                          </span>
                        </div>
                      ))}
                      {/* Auto-scroll anchor */}
                      <div ref={el => el?.scrollIntoView({ behavior: 'smooth', block: 'end' })} />
                    </div>
                  )}
                </div>
                
                {/* Request info + hint */}
                <div className="mt-3 pt-2 border-t border-gray-100 dark:border-gray-700 w-full flex items-center justify-between">
                  <p className="text-[10px] text-gray-400 dark:text-gray-500">
                    Request ID: {request?.id || id}
                  </p>
                  {processingLog.length > 0 && (
                    <p className="text-[10px] text-gray-400 dark:text-gray-500">
                      Elapsed: {processingLog[processingLog.length - 1]?.elapsed_seconds || 0}s
                    </p>
                  )}
                </div>
                <p className="text-[10px] text-gray-400 dark:text-gray-500 mt-2">
                  Click anywhere outside to minimize
                </p>
              </div>
            </div>
          </div>
        )
      )}

      {/* Save Reason Modal */}
      {showSaveReasonModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          {/* Backdrop */}
          <div 
            className="absolute inset-0 bg-navy-900/60 backdrop-blur-sm"
            onClick={() => { if (!saving) { setShowSaveReasonModal(false); } }}
          ></div>
          
          {/* Modal Content */}
          <div className="relative bg-white dark:bg-gray-900 rounded-xl shadow-2xl border border-gray-200 dark:border-gray-700 p-6 max-w-md w-full mx-4">
            <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-100 mb-2">
              Save Changes
            </h3>
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-4">
              Please provide a reason for the changes you are making. This will be recorded in the audit log.
            </p>
            
            <textarea
              value={saveReason}
              onChange={(e) => setSaveReason(e.target.value)}
              placeholder="Enter reason for changes..."
              disabled={saving}
              className={`w-full h-24 px-4 py-3 text-sm border border-gray-200 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent resize-none mb-4 dark:bg-gray-800 dark:text-gray-200 dark:placeholder-gray-500 ${saving ? 'opacity-50 cursor-not-allowed' : ''}`}
              autoFocus
            />
            
            <div className="flex items-center justify-end gap-3">
              <button
                onClick={() => {
                  setShowSaveReasonModal(false)
                  setSaveReason('')
                }}
                disabled={saving}
                className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors ${
                  saving
                    ? 'text-gray-400 dark:text-gray-600 cursor-not-allowed'
                    : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800'
                }`}
              >
                Cancel
              </button>
              <button
                onClick={handleSaveWithReason}
                disabled={!saveReason.trim() || saving}
                className={`px-4 py-2 text-sm font-medium text-white rounded-lg transition-colors flex items-center gap-1.5 ${
                  saveReason.trim() && !saving
                    ? 'bg-blue-500 hover:bg-blue-600'
                    : 'bg-gray-400 cursor-not-allowed'
                }`}
              >
                {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Check className="h-4 w-4" />}
                {saving ? 'Saving...' : 'OK'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Cancel Reason Modal */}
      {showCancelReasonModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          {/* Backdrop */}
          <div 
            className="absolute inset-0 bg-navy-900/60 backdrop-blur-sm"
            onClick={() => { if (!cancelling) { setShowCancelReasonModal(false); setCancelError(''); } }}
          ></div>
          
          {/* Modal Content */}
          <div className="relative bg-white dark:bg-gray-900 rounded-xl shadow-2xl border border-gray-200 dark:border-gray-700 p-6 max-w-md w-full mx-4">
            <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-100 mb-2">
              Cancel Request
            </h3>
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-4">
              Please provide a reason for cancelling this request. This will be recorded in the audit log.
            </p>
            
            {cancelError && (
              <div className="mb-4 p-3 bg-red-50 dark:bg-red-900/30 border border-red-200 dark:border-red-800 rounded-lg flex items-center gap-2">
                <AlertCircle className="h-4 w-4 text-red-500 flex-shrink-0" />
                <span className="text-sm text-red-700 dark:text-red-300">{cancelError}</span>
              </div>
            )}
            
            <textarea
              value={cancelReason}
              onChange={(e) => setCancelReason(e.target.value)}
              placeholder="Enter reason for cancellation..."
              disabled={cancelling}
              className={`w-full h-24 px-4 py-3 text-sm border border-gray-200 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-red-500 focus:border-transparent resize-none mb-4 dark:bg-gray-800 dark:text-gray-200 dark:placeholder-gray-500 ${cancelling ? 'opacity-50 cursor-not-allowed' : ''}`}
              autoFocus
            />
            
            <div className="flex items-center justify-end gap-3">
              <button
                onClick={() => {
                  setShowCancelReasonModal(false)
                  setCancelReason('')
                  setCancelError('')
                }}
                disabled={cancelling}
                className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors ${
                  cancelling
                    ? 'text-gray-400 dark:text-gray-600 cursor-not-allowed'
                    : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800'
                }`}
              >
                Go Back
              </button>
              <button
                onClick={handleCancel}
                disabled={!cancelReason.trim() || cancelling}
                className={`px-4 py-2 text-sm font-medium text-white rounded-lg transition-colors flex items-center gap-1.5 ${
                  cancelReason.trim() && !cancelling
                    ? 'bg-red-500 hover:bg-red-600'
                    : 'bg-gray-400 cursor-not-allowed'
                }`}
              >
                {cancelling ? <Loader2 className="h-4 w-4 animate-spin" /> : <X className="h-4 w-4" />}
                {cancelling ? 'Cancelling...' : 'Confirm Cancel'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Cost Breakdown Modal */}
      {showCostModal && (
        <CostBreakdown requestId={id} onClose={() => setShowCostModal(false)} />
      )}

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Top Action Bar */}
        <div className="bg-white dark:bg-gray-800 px-4 py-2 flex items-center justify-between border-b border-gray-200 dark:border-gray-700">
          <div className="flex items-center gap-2">
            {/* Show different buttons based on request status */}
            {request?.status === 'cancelled' ? (
              // Cancelled request: No edit actions available
              <span className="text-sm text-gray-500 dark:text-gray-400 italic flex items-center gap-1.5">
                <XCircle className="h-4 w-4" />
                Request Cancelled — Read Only
              </span>
            ) : (isViewOnly || request?.status === 'approved' || request?.status === 'published') ? (
              // Completed/Published/Approved request: Show Edit/Save/Discard buttons
              <>
                {!isEditMode ? (
                  // View Mode: Show Edit button and disabled Save button
                  <>
                    <button 
                      onClick={handleEnterEditMode}
                      disabled={saving}
                      className={`px-4 py-1.5 text-white text-sm font-medium rounded-lg flex items-center gap-1.5 transition-colors ${
                        saving
                          ? 'bg-gray-400 cursor-not-allowed opacity-50'
                          : 'bg-blue-500 hover:bg-blue-600'
                      }`}
                    >
                      <Edit className="h-4 w-4" />
                      Edit
                    </button>
                    <button 
                      disabled
                      className="px-4 py-1.5 text-white text-sm font-medium rounded-lg flex items-center gap-1.5 transition-colors bg-gray-400 cursor-not-allowed opacity-50"
                      title="Enter edit mode to make changes"
                    >
                      <Save className="h-4 w-4" />
                      Save
                    </button>
                  </>
                ) : (
                  // Edit Mode: Show Discard Changes and enabled Save button
                  <>
                    <button 
                      onClick={handleDiscardChanges}
                      disabled={saving}
                      className={`px-4 py-1.5 text-white text-sm font-medium rounded-lg flex items-center gap-1.5 transition-colors ${
                        saving
                          ? 'bg-gray-400 cursor-not-allowed opacity-50'
                          : 'bg-red-500 hover:bg-red-600'
                      }`}
                    >
                      <XCircle className="h-4 w-4" />
                      Discard Changes
                    </button>
                    <button 
                      onClick={() => setShowSaveReasonModal(true)}
                      disabled={saving || !hasUnsavedChanges()}
                      className={`px-4 py-1.5 text-white text-sm font-medium rounded-lg flex items-center gap-1.5 transition-colors ${
                        hasUnsavedChanges() && !saving
                          ? 'bg-blue-500 hover:bg-blue-600' 
                          : 'bg-gray-400 cursor-not-allowed opacity-50'
                      }`}
                      title={hasUnsavedChanges() ? "Save changes" : "No changes to save"}
                    >
                      {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                      {saving ? 'Saving...' : 'Save'}
                    </button>
                  </>
                )}
              </>
            ) : (
              // Non-published request: Show original Publish/Cancel/Save buttons
              <>
                <button 
                  onClick={handlePublish}
                  disabled={publishing || saving}
                  className={`px-4 py-1.5 text-white text-sm font-medium rounded-lg flex items-center gap-1.5 transition-colors ${
                    publishing || saving
                      ? 'bg-gray-400 cursor-not-allowed opacity-50' 
                      : 'bg-green-500 hover:bg-green-600'
                  }`}
                  title="Publish changes"
                >
                  {publishing ? <Loader2 className="h-4 w-4 animate-spin" /> : <Check className="h-4 w-4" />}
                  {publishing ? 'Publishing...' : 'Publish'}
                </button>
                <button 
                  onClick={() => setShowCancelReasonModal(true)}
                  disabled={publishing || saving}
                  className={`px-4 py-1.5 text-white text-sm font-medium rounded-lg flex items-center gap-1.5 transition-colors ${
                    publishing || saving
                      ? 'bg-gray-400 cursor-not-allowed opacity-50'
                      : 'bg-red-500 hover:bg-red-600'
                  }`}
                >
                  <X className="h-4 w-4" />
                  Cancel
                </button>
                <button 
                  onClick={handleSaveChanges}
                  disabled={saving || publishing || !hasUnsavedChanges()}
                  className={`px-4 py-1.5 text-white text-sm font-medium rounded-lg flex items-center gap-1.5 transition-colors ${
                    hasUnsavedChanges() && !saving && !publishing
                      ? 'bg-blue-500 hover:bg-blue-600'
                      : 'bg-gray-400 cursor-not-allowed opacity-50'
                  }`}
                  title={hasUnsavedChanges() ? "Save changes" : "No changes to save"}
                >
                  {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                  {saving ? 'Saving...' : 'Save Changes'}
                </button>
                

              </>
            )}
          </div>
          
          <div className="flex items-center gap-6 text-sm text-gray-500 dark:text-gray-400">
            <div className="flex items-center gap-1.5">
              <Clock className="h-4 w-4" />
              <span>Last saved: 2 minutes ago</span>
            </div>
            <div className="flex items-center gap-1.5">
              <span>AI Confidence:</span>
              <span className={`font-semibold ${avgConfidence >= 90 ? 'text-green-600 dark:text-green-400' : avgConfidence >= 70 ? 'text-orange-500 dark:text-orange-400' : 'text-red-500 dark:text-red-400'}`}>
                {avgConfidence}%
              </span>
            </div>
            <button
              onClick={() => setShowCostModal(true)}
              className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg hover:bg-blue-50 dark:hover:bg-blue-950/40 text-blue-600 dark:text-blue-400 transition-colors"
              title="View AI processing operations & costs"
            >
              <Info className="h-4 w-4" />
              <span className="text-xs font-medium">AI Operations</span>
            </button>
          </div>
        </div>
        
        {/* Document Processing Banner - shows when initial docs are still being processed OR just completed */}
        {(documentsStillProcessing || processingComplete) && (
          <div className={`border-b px-4 py-2.5 flex-shrink-0 transition-colors duration-500 ${
            processingComplete
              ? 'bg-gradient-to-r from-green-50 via-emerald-50 to-green-50 dark:from-green-950/40 dark:via-emerald-950/40 dark:to-green-950/40 border-green-200 dark:border-green-800'
              : 'bg-gradient-to-r from-blue-50 via-indigo-50 to-purple-50 dark:from-blue-950/40 dark:via-indigo-950/40 dark:to-purple-950/40 border-blue-200 dark:border-blue-800'
          }`}>
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                {/* Animated icon */}
                <div className="relative">
                  <div className={`w-7 h-7 rounded-full flex items-center justify-center shadow-sm ${
                    processingComplete
                      ? 'bg-gradient-to-br from-green-500 to-emerald-500'
                      : 'bg-gradient-to-br from-blue-500 to-purple-500'
                  }`}>
                    {processingComplete
                      ? <CheckCircle className="h-3.5 w-3.5 text-white" />
                      : <Bot className="h-3.5 w-3.5 text-white" />
                    }
                  </div>
                  {!processingComplete && (
                    <>
                      <span className="absolute -top-0.5 -right-0.5 w-2.5 h-2.5 bg-blue-500 rounded-full animate-ping"></span>
                      <span className="absolute -top-0.5 -right-0.5 w-2.5 h-2.5 bg-blue-500 rounded-full"></span>
                    </>
                  )}
                </div>
                
                {/* Message */}
                <div className="flex flex-col">
                  <span className={`text-sm font-semibold flex items-center gap-1.5 ${
                    processingComplete
                      ? 'text-green-800 dark:text-green-200'
                      : 'text-blue-800 dark:text-blue-200'
                  }`}>
                    {processingComplete
                      ? <><CheckCircle className="h-3.5 w-3.5 text-green-500" /> All documents have been processed</>
                      : <><Sparkles className="h-3.5 w-3.5 text-yellow-500 animate-pulse" /> AI is still processing remaining documents</>
                    }
                  </span>
                  <span className={`text-xs ${
                    processingComplete
                      ? 'text-green-600/80 dark:text-green-300/70'
                      : 'text-blue-600/80 dark:text-blue-300/70'
                  }`}>
                    {processingComplete
                      ? 'New extracted fields are available. Refresh to load the latest data.'
                      : (processingProgress.message || 'Extracting and merging fields from additional documents...')
                    }
                  </span>
                </div>
              </div>
              
              {/* Right side: progress bar OR refresh/dismiss buttons */}
              <div className="flex items-center gap-3">
                {processingComplete ? (
                  <>
                    <button
                      onClick={handleProcessingRefresh}
                      className="px-3 py-1.5 text-xs font-semibold text-white bg-green-500 hover:bg-green-600 rounded-lg flex items-center gap-1.5 transition-colors shadow-sm"
                    >
                      <RefreshCw className="h-3.5 w-3.5" />
                      Refresh Now
                    </button>
                    <button
                      onClick={() => setProcessingComplete(false)}
                      className="p-1 text-green-400 hover:text-green-600 dark:text-green-500 dark:hover:text-green-300 transition-colors"
                      title="Dismiss"
                    >
                      <X className="h-4 w-4" />
                    </button>
                  </>
                ) : (
                  <>
                    {/* Progress bar */}
                    <div className="flex items-center gap-2">
                      <div className="w-32 h-1.5 bg-blue-200 dark:bg-blue-800 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-gradient-to-r from-blue-500 to-purple-500 rounded-full transition-all duration-700 ease-out"
                          style={{ width: `${Math.max(processingProgress.percent, 10)}%` }}
                        ></div>
                      </div>
                      <span className="text-xs font-medium text-blue-700 dark:text-blue-300 tabular-nums">
                        {processingProgress.percent}%
                      </span>
                    </div>
                    {/* Spinning loader */}
                    <Loader2 className="h-4 w-4 animate-spin text-blue-500" />
                  </>
                )}
              </div>
            </div>
          </div>
        )}
        
        {/* Content below action bar */}
        
        <div className="flex-1 flex overflow-hidden bg-white dark:bg-gray-900">
          {/* Center Panel - Document Viewer + Extracted Fields side by side */}
          <div className="flex-1 flex flex-col bg-gray-100 dark:bg-gray-950 overflow-hidden">
            {/* Document Tabs */}
            <div ref={docTabsRef} className="bg-white dark:bg-gray-900 border-b border-gray-200 dark:border-gray-700 px-4 py-2 flex items-center gap-2 flex-shrink-0 overflow-x-auto">
              {documents.map((doc, idx) => {
                const DocIcon = getDocIcon(doc.filename)
                return (
                  <button
                    key={doc.id}
                    data-doc-tab={idx}
                    onClick={() => {
                      setActiveDocTab(idx)
                      setDocumentId(doc.id)
                    }}
                    className={`px-3 py-1.5 text-xs font-medium rounded-lg flex items-center gap-1.5 transition-colors whitespace-nowrap flex-shrink-0 ${
                      activeDocTab === idx
                        ? 'bg-navy-800 text-white ring-2 ring-blue-400 dark:ring-blue-500 shadow-sm'
                        : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700'
                    }`}
                  >
                    <DocIcon className="h-3.5 w-3.5" />
                    {doc.filename?.substring(0, 20) || `Document ${idx + 1}`}
                    {doc.filename?.length > 20 && '...'}
                  </button>
                )
              })}
              {/* Show placeholder tabs if no documents */}
              {documents.length === 0 && (
                <>
                  <button className="px-3 py-1.5 text-xs font-medium rounded-lg flex items-center gap-1.5 bg-navy-800 text-white">
                    <FileText className="h-3.5 w-3.5" />
                    Offering Circular.pdf
                  </button>
                  <button className="px-3 py-1.5 text-xs font-medium rounded-lg flex items-center gap-1.5 bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300">
                    <Mail className="h-3.5 w-3.5" />
                    Email Body
                  </button>
                  <button className="px-3 py-1.5 text-xs font-medium rounded-lg flex items-center gap-1.5 bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300">
                    <FileSpreadsheet className="h-3.5 w-3.5" />
                    Attachment 2.xlsx
                  </button>
                  <button className="px-3 py-1.5 text-xs font-medium rounded-lg flex items-center gap-1.5 bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300">
                    <File className="h-3.5 w-3.5" />
                    Attachment 3.docx
                  </button>
                </>
              )}
              
              {/* Upload button */}
              <button
                onClick={() => fileInputRef.current?.click()}
                disabled={uploading}
                title="Upload document"
                className="px-2 py-1.5 text-xs font-medium rounded-lg flex items-center gap-1 transition-colors border border-dashed border-gray-300 dark:border-gray-600 text-gray-500 dark:text-gray-400 hover:border-navy-500 hover:text-navy-600 dark:hover:border-navy-400 dark:hover:text-navy-400 hover:bg-navy-50 dark:hover:bg-navy-900/20 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {uploading ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Upload className="h-3.5 w-3.5" />}
                <span className="hidden sm:inline">{uploading ? 'Uploading...' : 'Upload'}</span>
              </button>
              <input
                ref={fileInputRef}
                type="file"
                className="hidden"
                accept=".pdf,.xlsx,.xls,.doc,.docx,.ppt,.pptx,.csv,.txt,.msg,.eml,.json,.xml,.png,.jpg,.jpeg,.gif"
                onChange={handleDocumentUpload}
              />

              {/* Toggle PDF Viewer button */}
              <button
                onClick={() => setIsPdfViewerVisible(prev => !prev)}
                className={`ml-2 px-2.5 py-1.5 text-xs font-medium rounded-lg flex items-center gap-1.5 transition-colors border ${
                  isPdfViewerVisible
                    ? 'border-gray-200 dark:border-gray-600 bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700'
                    : 'border-navy-300 dark:border-navy-500 bg-navy-50 dark:bg-navy-900/30 text-navy-700 dark:text-navy-300 hover:bg-navy-100 dark:hover:bg-navy-900/50'
                }`}
                title={isPdfViewerVisible ? 'Hide document viewer' : 'Show document viewer'}
              >
                {isPdfViewerVisible ? <PanelRightClose className="h-3.5 w-3.5" /> : <PanelRightOpen className="h-3.5 w-3.5" />}
                <span className="hidden sm:inline">{isPdfViewerVisible ? 'Hide Viewer' : 'Show Viewer'}</span>
              </button>

              {/* Confidence indicator in tabs bar */}
              <div className="ml-auto flex items-center gap-3 text-xs">
                <div className="flex items-center gap-1">
                  <div className="w-2 h-2 rounded-full bg-green-500"></div>
                  <span className="text-gray-500 dark:text-gray-400">&gt;90%</span>
                </div>
                <div className="flex items-center gap-1">
                  <div className="w-2 h-2 rounded-full bg-orange-500"></div>
                  <span className="text-gray-500 dark:text-gray-400">70-89%</span>
                </div>
                <div className="flex items-center gap-1">
                  <div className="w-2 h-2 rounded-full bg-red-500"></div>
                  <span className="text-gray-500 dark:text-gray-400">&lt;70%</span>
                </div>
              </div>
            </div>
            
            {/* Main content: Extracted Fields left, PDF right */}
            <div className="flex-1 flex overflow-hidden min-w-0">
              {/* Left Panel - Extracted Data Fields */}
              <div className={`${
                isPdfViewerVisible 
                  ? 'w-[520px] flex-shrink-0' 
                  : 'flex-1'
              } bg-white dark:bg-gray-900 border-r border-gray-200 dark:border-gray-700 flex flex-col overflow-hidden transition-all duration-300`}>
                {/* Request Info - Title, Issuer, Description stacked (collapsible) */}
                <div className="border-b border-gray-200 dark:border-gray-700 flex-shrink-0">
                  <button
                    onClick={() => setIsRequestInfoExpanded(prev => !prev)}
                    className="w-full px-4 py-2.5 flex items-center justify-between text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
                  >
                    <span>Request Info</span>
                    <ChevronDown className={`h-4 w-4 transition-transform duration-200 ${isRequestInfoExpanded ? '' : '-rotate-90'}`} />
                  </button>
                  {isRequestInfoExpanded && <div className="px-4 pb-3.5 space-y-3">
                    <div>
                      <label className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1 block">Title</label>
                      <input
                        type="text"
                        value={editedMetadata.title}
                        onChange={(e) => setEditedMetadata(prev => ({ ...prev, title: e.target.value }))}
                        disabled={isFieldsDisabled}
                        className={`w-full px-3 py-2 text-sm font-medium rounded-md border border-gray-200 dark:border-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent dark:text-gray-200 ${
                          isFieldsDisabled
                            ? 'bg-gray-100 dark:bg-gray-800 cursor-not-allowed opacity-75' 
                            : 'bg-white dark:bg-gray-800'
                        }`}
                        placeholder="Title..."
                      />
                    </div>
                    <div>
                      <label className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1 block">Issuer</label>
                      <input
                        type="text"
                        value={editedMetadata.issuer}
                        onChange={(e) => setEditedMetadata(prev => ({ ...prev, issuer: e.target.value }))}
                        disabled={isFieldsDisabled}
                        className={`w-full px-3 py-2 text-sm font-medium rounded-md border border-gray-200 dark:border-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent dark:text-gray-200 ${
                          isFieldsDisabled
                            ? 'bg-gray-100 dark:bg-gray-800 cursor-not-allowed opacity-75' 
                            : 'bg-white dark:bg-gray-800'
                        }`}
                        placeholder="Issuer..."
                      />
                    </div>
                    <div>
                      <label className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1 block">Description</label>
                      <textarea
                        value={editedMetadata.description}
                        onChange={(e) => setEditedMetadata(prev => ({ ...prev, description: e.target.value }))}
                        disabled={isFieldsDisabled}
                        rows={3}
                        className={`w-full px-3 py-2 text-sm font-medium rounded-md border border-gray-200 dark:border-gray-600 focus:ring-2 focus:ring-blue-500 focus:border-transparent resize-none dark:text-gray-200 ${
                          isFieldsDisabled
                            ? 'bg-gray-100 dark:bg-gray-800 cursor-not-allowed opacity-75' 
                            : 'bg-white dark:bg-gray-800'
                        }`}
                        placeholder="Description..."
                        title={editedMetadata.description}
                      />
                    </div>
                  </div>}
                </div>
                
                {/* Extracted Fields Header */}
                <div className="px-4 py-2 border-b border-gray-100 dark:border-gray-700 flex-shrink-0">
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="text-sm font-semibold text-gray-900 dark:text-gray-100">Extracted Data Fields</h3>
                  </div>
                  <div className="relative">
                    <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-gray-400" />
                    <input
                      type="text"
                      value={fieldSearchQuery}
                      onChange={(e) => setFieldSearchQuery(e.target.value)}
                      placeholder="Filter fields..."
                      className="w-full pl-8 pr-8 py-1.5 text-xs rounded-md border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    />
                    {fieldSearchQuery && (
                      <button
                        onClick={() => setFieldSearchQuery('')}
                        className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
                        aria-label="Clear field search"
                      >
                        <X className="h-3.5 w-3.5" />
                      </button>
                    )}
                  </div>
                </div>
                
                {/* Scrollable Fields Content */}
                <div className="flex-1 overflow-y-auto px-4 py-3">
                  <div className="space-y-5">
                    {orderedCategories.map((category) => {
                      let fields = fieldsByCategory[category] || []
                      // Apply field search filter
                      if (fieldSearchQuery.trim()) {
                        const q = fieldSearchQuery.toLowerCase()
                        fields = fields.filter(f => 
                          (f.display_label || f.field_name || '').toLowerCase().includes(q) ||
                          (f.value || '').toString().toLowerCase().includes(q)
                        )
                      }
                      if (fields.length === 0) return null
                      const color = getCategoryColor(category)
                      return (
                        <div key={category}>
                          <div className="flex items-center gap-2 mb-3">
                            {color && color !== 'gray' && (
                              <div 
                                className="w-1 h-4 rounded-full" 
                                style={{ backgroundColor: color }}
                              />
                            )}
                            <h4 className="text-xs font-semibold text-gray-900 dark:text-gray-100">
                              {getCategoryDisplayName(category)}
                            </h4>
                            <span className="text-xs text-gray-400">({fields.length})</span>
                          </div>
                          <div className={`${!isPdfViewerVisible ? 'grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-2' : 'space-y-2'}`}>
                            {fields.map((field) => {
                              // --- ui_properties grid-level overrides ---
                              const uiProps = field.ui_properties || {}
                              const gridStyle = !isPdfViewerVisible ? (() => {
                                const classes = []
                                if (uiProps.fullWidth || uiProps.colSpan === 'full') {
                                  classes.push('col-span-1 lg:col-span-2 xl:col-span-3')
                                } else if (uiProps.colSpan === 2) {
                                  classes.push('col-span-1 lg:col-span-2')
                                }
                                return classes.join(' ')
                              })() : ''
                              const inlineStyle = {}
                              if (uiProps.minWidth) inlineStyle.minWidth = uiProps.minWidth
                              if (uiProps.maxWidth) inlineStyle.maxWidth = uiProps.maxWidth
                              
                              return (
                                <div key={field.id} className={gridStyle} style={inlineStyle}>
                                  <FieldInput 
                                    field={field} 
                                    onChange={handleFieldChange}
                                    onClick={() => handleFieldClick(field)}
                                    isDate={field.field_type === 'date' || category === 'date'}
                                    requestId={id}
                                    onAlternativeSelect={handleAlternativeSelect}
                                    onViewInDocument={handleViewInDocument}
                                    documents={documents}
                                    disabled={isFieldsDisabled}
                                    hasAuditHistoryFromParent={!!fieldsAuditMap[String(field.id)]}
                                  />
                                </div>
                              )
                            })}
                            {fields.length === 0 && (
                              <p className="text-xs text-gray-400 dark:text-gray-500 italic">No fields in this category</p>
                            )}
                          </div>
                        </div>
                      )
                    })}
                    
                    {/* Processing Log — persistent, survives modal disappearing */}
                    {processingLog.length > 0 && (
                      <div className="mb-4">
                        <button
                          onClick={() => setShowProcessingLog(!showProcessingLog)}
                          className="flex items-center justify-between w-full mb-2"
                        >
                          <h4 className="text-xs font-semibold text-gray-900 dark:text-gray-100 flex items-center gap-1.5">
                            <Clock className="w-3 h-3 text-blue-500" />
                            Processing Log
                            <span className="text-[10px] font-normal text-gray-400">({processingLog.length} steps)</span>
                          </h4>
                          <ChevronDown className={`w-3 h-3 text-gray-400 transition-transform ${showProcessingLog ? 'rotate-180' : ''}`} />
                        </button>
                        {showProcessingLog && (
                          <div className="bg-gray-900 dark:bg-black rounded-lg border border-gray-700 max-h-80 overflow-y-auto font-mono text-[11px] select-all">
                            {processingLog.map((step, idx) => (
                              <div key={idx} className="px-3 py-1 border-b border-gray-800 flex gap-2 hover:bg-gray-800">
                                <span className="text-gray-500 whitespace-nowrap min-w-[50px]">
                                  {step.elapsed_seconds != null ? `${step.elapsed_seconds}s` : step.timestamp}
                                </span>
                                <span className={
                                  step.message?.includes('✅') ? 'text-green-400' :
                                  step.message?.includes('❌') ? 'text-red-400' :
                                  step.message?.includes('⚠️') ? 'text-yellow-400' :
                                  step.message?.includes('⏳') ? 'text-blue-400' :
                                  'text-gray-300'
                                }>
                                  {step.message}
                                </span>
                              </div>
                            ))}
                            <div ref={logBottomRef} />
                          </div>
                        )}
                        {!showProcessingLog && (
                          <p className="text-[10px] text-gray-400 dark:text-gray-500">
                            {request?.last_job?.status === 'completed'
                              ? `✅ Completed in ${processingLog[processingLog.length - 1]?.elapsed_seconds || '?'}s`
                              : request?.last_job?.status === 'failed'
                              ? `❌ Failed: ${request?.last_job?.error_message || 'Unknown error'}`
                              : 'Processing...'}
                          </p>
                        )}
                      </div>
                    )}
                    
                    {/* Activity Log */}
                    <div>
                      <div className="flex items-center justify-between mb-3">
                        <h4 className="text-xs font-semibold text-gray-900 dark:text-gray-100">Activity Log</h4>
                        <button 
                          onClick={fetchAuditLogs}
                          className="text-xs text-blue-600 hover:text-blue-800 font-medium flex items-center gap-1"
                        >
                          <RefreshCw className={`w-3 h-3 ${loadingAuditLogs ? 'animate-spin' : ''}`} />
                          Refresh
                        </button>
                      </div>
                      <div className="space-y-2">
                        {loadingAuditLogs ? (
                          <div className="flex items-center justify-center py-3">
                            <RefreshCw className="w-4 h-4 animate-spin text-gray-400" />
                            <span className="ml-2 text-xs text-gray-400">Loading activity...</span>
                          </div>
                        ) : activityLog.length === 0 ? (
                          <p className="text-xs text-gray-400 dark:text-gray-500 italic text-center py-3">No activity recorded yet</p>
                        ) : (
                          activityLog.map((log) => (
                            <div key={log.id} className="flex items-start gap-2 group">
                              <div className={`w-1.5 h-1.5 rounded-full mt-1.5 flex-shrink-0 ${
                                log.icon === 'user' ? 'bg-blue-500' : 
                                log.icon === 'bot' ? 'bg-purple-500' : 'bg-gray-400'
                              }`}></div>
                              <div className="min-w-0 flex-1">
                                <p className="text-xs text-gray-700 dark:text-gray-300 break-words">{log.action}</p>
                                <p className="text-[10px] text-gray-400 dark:text-gray-500">{log.time}</p>
                              </div>
                            </div>
                          ))
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
              
              {/* Right side: Page Thumbnails + PDF + Controls */}
              {isPdfViewerVisible && <div className="flex-1 flex overflow-hidden min-w-0">
                {/* Page Thumbnails / Document Status */}
                <div ref={pageThumbnailsRef} className="w-16 bg-gray-200 dark:bg-gray-800 border-r border-gray-300 dark:border-gray-700 overflow-y-auto p-1.5 space-y-1.5 flex-shrink-0">
                  {(() => {
                    if (!activeDocument) return null

                    const activeDocId = documents[activeDocTab]?.id
                    const fieldsForDoc = editedFields.filter(
                      field => (field.source_document_id === activeDocId || !field.source_document_id) && (field.page_number || (field.page_numbers && field.page_numbers.length > 0))
                    )
                    const hasExtractedFields = fieldsForDoc.length > 0
                    const isPdf = isPdfDocument(activeDocument)

                    // PDF with extracted fields → show page thumbnails with field navigation
                    // Use page_numbers array for multi-page fields (e.g. field spanning pages 13 and 14)
                    if (isPdf && hasExtractedFields) {
                      const pageNumbers = [...new Set(
                        fieldsForDoc.flatMap(field => field.page_numbers || [field.page_number])
                      )].sort((a, b) => a - b)
                      const pagesToShow = pageNumbers.length > 0 ? pageNumbers : [1]

                      // Determine which pages belong to the currently highlighted field
                      const highlightedFieldPages = new Set()
                      if (highlightedField?.field_name) {
                        // A specific field is selected — find all its pages
                        const matchingField = fieldsForDoc.find(f => f.field_name === highlightedField.field_name)
                        if (matchingField) {
                          (matchingField.page_numbers || [matchingField.page_number]).forEach(p => {
                            if (p) highlightedFieldPages.add(p)
                          })
                        }
                      }
                      const hasFieldSelection = highlightedFieldPages.size > 0

                      return (
                        <>
                          {/* Reset button — shown when a field is selected */}
                          {hasFieldSelection && (
                            <button
                              onClick={handleResetPageView}
                              title="Reset — show all pages"
                              className="w-full flex items-center justify-center gap-0.5 py-1 rounded bg-amber-100 dark:bg-amber-900/40 text-amber-700 dark:text-amber-300 text-[7px] font-semibold border border-amber-300 dark:border-amber-700 hover:bg-amber-200 dark:hover:bg-amber-800/50 transition-colors mb-0.5"
                            >
                              <RotateCcw className="h-2.5 w-2.5" />
                              Reset
                            </button>
                          )}
                          {pagesToShow.map((page) => {
                            const fieldsOnPage = fieldsForDoc
                              .filter(field => (field.page_numbers || [field.page_number]).includes(page))
                              .map(field => field.display_label || field.field_name)
                            const tooltipText = fieldsOnPage.length > 0 
                              ? `Page ${page}\n─────────\n${fieldsOnPage.join('\n')}`
                              : `Page ${page}`

                            const fieldsWithBoxes = fieldsForDoc
                              .filter(field => (field.page_numbers || [field.page_number]).includes(page) && field.bounding_box)
                            const boundingBoxesOnPage = fieldsWithBoxes.map(field => field.bounding_box)
                            const fieldLabelsOnPage = fieldsWithBoxes.map(field => field.display_label || field.field_name)

                            // Determine styling: current page, field-relevant page, or default
                            const isCurrentPage = currentPage === page
                            const isFieldPage = highlightedFieldPages.has(page)
                            let borderClass
                            if (isCurrentPage) {
                              borderClass = 'border-blue-500 ring-1 ring-blue-200'
                            } else if (isFieldPage) {
                              borderClass = 'border-amber-400 dark:border-amber-500 ring-1 ring-amber-200 dark:ring-amber-800 bg-amber-50 dark:bg-amber-900/30'
                            } else if (hasFieldSelection) {
                              borderClass = 'border-gray-200 dark:border-gray-700 opacity-40'
                            } else {
                              borderClass = 'border-gray-300 dark:border-gray-600 hover:border-gray-400 dark:hover:border-gray-500'
                            }

                            return (
                              <button
                                key={page}
                                data-page={page}
                                onClick={() => {
                                  setCurrentPage(page)
                                  setHighlightedField(
                                    boundingBoxesOnPage.length > 0
                                      ? { page_number: page, bounding_boxes: boundingBoxesOnPage, field_labels: fieldLabelsOnPage }
                                      : { page_number: page }
                                  )
                                }}
                                title={tooltipText}
                                className={`w-full aspect-[3/4] rounded border-2 flex items-center justify-center text-[8px] font-medium dark:text-gray-300 transition-colors ${borderClass}`}
                              >
                                {page}
                              </button>
                            )
                          })}
                        </>
                      )
                    }

                    // Any document without extraction (PDF or non-PDF) → show view-only status
                    return (
                      <div className="flex flex-col items-center justify-center h-full px-1">
                        <Sparkles className="h-3.5 w-3.5 text-gray-400 dark:text-gray-500 mb-1.5" />
                        <span className="text-[7px] text-gray-400 dark:text-gray-500 text-center leading-tight font-medium">No AI<br/>extraction</span>
                      </div>
                    )
                  })()}
                </div>
                
                {/* Document Content */}
                <div className="flex-1 bg-gray-300 dark:bg-gray-800 overflow-auto p-4 flex items-start justify-center min-w-0">
                  {documentId && isPdfDocument(activeDocument) ? (
                    <PDFViewer 
                      key={documentId}
                      documentId={documentId} 
                      highlightedField={highlightedField}
                      onPageChange={setCurrentPage}
                    />
                  ) : documentId && activeDocument && !isPdfDocument(activeDocument) ? (
                    <DocumentViewer
                      key={documentId}
                      documentId={documentId}
                      document={activeDocument}
                      toast={toast}
                    />
                  ) : (
                    <div className="flex flex-col items-center justify-center h-full text-gray-400 dark:text-gray-500">
                      <FileText className="h-16 w-16 mb-4 opacity-50" />
                      <p className="text-lg font-medium">No document selected</p>
                      <p className="text-sm mt-1">Upload or select a document to view it here</p>
                    </div>
                  )}
                </div>
                
                {/* Document Controls */}
                <div className="w-10 bg-gray-200 dark:bg-gray-800 border-l border-gray-300 dark:border-gray-700 flex flex-col items-center py-3 gap-2 flex-shrink-0">
                  <button
                    onClick={() => {
                      if (documentId) {
                        const currentDocId = documentId
                        setDocumentId(null)
                        setTimeout(() => setDocumentId(currentDocId), 100)
                      }
                    }}
                    className="p-1.5 bg-white dark:bg-gray-700 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-600 transition-colors shadow-sm cursor-pointer"
                    title="Refresh document"
                  >
                    <RotateCw className="h-3.5 w-3.5 text-gray-600 dark:text-gray-300" />
                  </button>
                  <button
                    onClick={async () => {
                      if (documentId) {
                        try {
                          const response = await documentsApi.download(documentId)
                          const blob = new Blob([response.data])
                          const url = window.URL.createObjectURL(blob)
                          const a = document.createElement('a')
                          a.href = url
                          a.download = activeDocument?.filename || 'document.pdf'
                          document.body.appendChild(a)
                          a.click()
                          window.URL.revokeObjectURL(url)
                          document.body.removeChild(a)
                        } catch (err) {
                          console.error('Error downloading document:', err)
                        }
                      }
                    }}
                    className="p-1.5 bg-white dark:bg-gray-700 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-600 transition-colors shadow-sm cursor-pointer"
                    title="Download document"
                  >
                    <Download className="h-3.5 w-3.5 text-gray-600 dark:text-gray-300" />
                  </button>
                  <button
                    onClick={async () => {
                      if (documentId) {
                        try {
                          const response = await documentsApi.download(documentId)
                          const blob = new Blob([response.data], { type: 'application/pdf' })
                          const url = window.URL.createObjectURL(blob)
                          const printWindow = window.open(url, '_blank')
                          if (printWindow) {
                            printWindow.addEventListener('load', () => {
                              printWindow.print()
                            })
                          }
                        } catch (err) {
                          console.error('Error printing document:', err)
                        }
                      }
                    }}
                    className="p-1.5 bg-white dark:bg-gray-700 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-600 transition-colors shadow-sm cursor-pointer"
                    title="Print document"
                  >
                    <Printer className="h-3.5 w-3.5 text-gray-600 dark:text-gray-300" />
                  </button>
                </div>
              </div>}
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

// Sanitize initial value for numeric field types - strip non-numeric chars
function sanitizeNumericValue(val, fieldType) {
  if (!val) return val
  if (fieldType === 'number' || fieldType === 'integer' || fieldType === 'percentage') {
    // Strip everything except digits, minus, dot, and commas
    const cleaned = val.replace(/[^0-9.\-,]/g, '')
    return cleaned
  }
  if (fieldType === 'currency' || fieldType === 'money') {
    // For currency, strip alpha chars from the amount portion only (preserve symbol)
    const parts = val.split(' ')
    if (parts.length > 1) {
      const symbol = parts[0]
      const amount = parts.slice(1).join(' ').replace(/[^0-9.\-,]/g, '')
      return `${symbol} ${amount}`.trim()
    }
    return val
  }
  return val
}

// Shared dropdown utility — auto-detects format and returns flat list + render function
// Supports:
//   1. Comma-separated string:  "Per Occurrence,Aggregate,Umbrella"
//   2. Flat array:              ["opt1", "opt2", "opt3"]
//   3. Grouped array:           [{group: "USA", items: ["NY", "CA"]}, {group: "Europe", items: ["UK", "FR"]}]
function parseDropdownOptions(raw) {
  let options = raw
  // If it's a string, try JSON first, then fall back to comma-split
  if (typeof raw === 'string') {
    try {
      const parsed = JSON.parse(raw)
      if (Array.isArray(parsed)) options = parsed
      else options = raw.split(',').map(v => v.trim()).filter(Boolean)
    } catch {
      options = raw.split(',').map(v => v.trim()).filter(Boolean)
    }
  }
  if (!Array.isArray(options) || options.length === 0) {
    return { flat: [], isGrouped: false, render: () => null }
  }
  const isGrouped = typeof options[0] === 'object' && options[0] !== null && 'group' in options[0]
  const flat = isGrouped
    ? options.flatMap(g => g.items || [])
    : options.map(String)
  const render = () => {
    if (isGrouped) {
      return options.map((group, gi) => (
        <optgroup key={gi} label={group.group}>
          {(group.items || []).map((opt, i) => (
            <option key={i} value={opt}>{opt}</option>
          ))}
        </optgroup>
      ))
    }
    return options.map((opt, i) => <option key={i} value={String(opt)}>{String(opt)}</option>)
  }
  return { flat, isGrouped, render }
}

// Array of Objects Sub-component for table-style editing
function ArrayOfObjectsField({ value, onChange, disabled, schema }) {
  const columns = React.useMemo(() => {
    if (!schema) return []
    if (Array.isArray(schema)) return schema
    try {
      const parsed = JSON.parse(schema)
      if (Array.isArray(parsed)) return parsed
    } catch { /* ignore */ }
    return []
  }, [schema])

  const parseRows = (val) => {
    if (!val) return []
    if (Array.isArray(val)) return val
    try {
      const parsed = JSON.parse(val)
      return Array.isArray(parsed) ? parsed : []
    } catch {
      return []
    }
  }

  const [rows, setRows] = useState(() => parseRows(value))
  const [isExpanded, setIsExpanded] = useState(false)
  const localChangeRef = React.useRef(false)

  React.useEffect(() => {
    if (localChangeRef.current) {
      localChangeRef.current = false
      return
    }
    setRows(parseRows(value))
  }, [value])

  const commitChange = (updatedRows) => {
    localChangeRef.current = true
    setRows(updatedRows)
    onChange(JSON.stringify(updatedRows))
  }

  const handleCellChange = (rowIdx, colKey, newVal) => {
    const updated = rows.map((row, i) =>
      i === rowIdx ? { ...row, [colKey]: newVal } : row
    )
    commitChange(updated)
  }

  const handleAddRow = () => {
    const emptyRow = {}
    columns.forEach(col => {
      const t = (col.type || 'text').toLowerCase()
      if (t !== 'auto' && t !== 'computed' && t !== 'formula') {
        emptyRow[col.key] = ''
      }
    })
    commitChange([...rows, emptyRow])
  }

  const handleRemoveRow = (rowIdx) => {
    commitChange(rows.filter((_, i) => i !== rowIdx))
  }

  const renderCellInput = (col, cellValue, rowIdx) => {
    const val = cellValue != null ? String(cellValue) : ''
    const colType = (col.type || 'text').toLowerCase()
    const baseClasses = `w-full px-2 py-1.5 text-xs rounded border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-900 text-gray-800 dark:text-gray-200 focus:ring-1 focus:ring-blue-500 focus:border-transparent ${disabled ? 'bg-gray-100 dark:bg-gray-800 cursor-not-allowed opacity-75' : ''}`

    switch (colType) {
      case 'number':
      case 'integer':
        return (
          <input type="text" inputMode="decimal" value={val}
            onChange={(e) => { const v = e.target.value; if (v === '' || v === '-' || v === '.' || v === '-.' || /^-?\d*\.?\d*$/.test(v)) handleCellChange(rowIdx, col.key, v) }}
            onKeyDown={(e) => { if (/^[a-zA-Z]$/.test(e.key) && !e.ctrlKey && !e.metaKey) e.preventDefault() }}
            disabled={disabled} className={baseClasses} placeholder={col.label || col.key} />
        )
      case 'currency':
      case 'money': {
        const parts = (val || '').split(' ')
        const symbol = parts[0] || '$'
        const amount = parts.slice(1).join(' ') || ''
        return (
          <div className="flex gap-1">
            <input type="text" value={symbol} onChange={(e) => handleCellChange(rowIdx, col.key, `${e.target.value} ${amount}`.trim())} disabled={disabled} className={`${baseClasses} w-10 text-center`} maxLength="5" />
            <input type="text" inputMode="decimal" value={amount}
              onChange={(e) => { const v = e.target.value; if (v === '' || v === '-' || v === '.' || v === '-.' || /^-?[\d,]*\.?\d*$/.test(v)) handleCellChange(rowIdx, col.key, `${symbol} ${v}`.trim()) }}
              onKeyDown={(e) => { if (/^[a-zA-Z]$/.test(e.key) && !e.ctrlKey && !e.metaKey) e.preventDefault() }}
              disabled={disabled} className={`${baseClasses} flex-1`} placeholder="0.00" />
          </div>
        )
      }
      case 'percentage':
      case 'percent':
        return (
          <div className="relative">
            <input type="text" inputMode="decimal" value={val}
              onChange={(e) => { const v = e.target.value; if (v === '' || v === '.' || /^\d*\.?\d*$/.test(v)) handleCellChange(rowIdx, col.key, v) }}
              onKeyDown={(e) => { if (/^[a-zA-Z]$/.test(e.key) && !e.ctrlKey && !e.metaKey) e.preventDefault() }}
              disabled={disabled} className={`${baseClasses} pr-5`} placeholder={col.label || col.key} />
            <span className="absolute right-1.5 top-1/2 -translate-y-1/2 text-gray-400 text-[10px]">%</span>
          </div>
        )
      case 'date':
        return <input type={/^\d{4}-\d{2}-\d{2}$/.test(val) ? 'date' : 'text'} value={val} onChange={(e) => handleCellChange(rowIdx, col.key, e.target.value)} disabled={disabled} className={baseClasses} placeholder="YYYY-MM-DD" />
      case 'dropdown':
      case 'select':
      case 'enum': {
        const { flat: flatOpts, render: renderOpts } = parseDropdownOptions(col.options || [])
        const valueMatchesOption = !val || flatOpts.some(opt => opt.toLowerCase() === val.toLowerCase())
        return (
          <select value={valueMatchesOption ? val : ''} onChange={(e) => handleCellChange(rowIdx, col.key, e.target.value)} disabled={disabled} className={`${baseClasses} cursor-pointer`}>
            <option value="">Select...</option>
            {renderOpts()}
          </select>
        )
      }
      case 'boolean':
      case 'bool':
        return (
          <select value={val} onChange={(e) => handleCellChange(rowIdx, col.key, e.target.value)} disabled={disabled} className={`${baseClasses} cursor-pointer`}>
            <option value="">Select...</option>
            <option value="true">Yes</option>
            <option value="false">No</option>
          </select>
        )
      case 'auto':
      case 'computed':
      case 'formula': {
        const currentRow = rows[rowIdx] || {}
        const expression = col.expression || ''
        const computed = expression.replace(/\{(\w+)\}/g, (_, key) => { const v = currentRow[key]; return v != null && v !== '' ? String(v) : '' })
        const hasContent = computed.replace(/[^a-zA-Z0-9]/g, '').length > 0
        return (
          <span className="block w-full px-2 py-1.5 text-xs text-gray-700 dark:text-gray-300 bg-gray-50 dark:bg-gray-800 rounded border border-gray-100 dark:border-gray-700 truncate" title={hasContent ? computed : ''}>
            {hasContent ? computed : <span className="italic text-gray-400">—</span>}
          </span>
        )
      }
      case 'text':
      default:
        return <input type="text" value={val} onChange={(e) => handleCellChange(rowIdx, col.key, e.target.value)} disabled={disabled} className={baseClasses} placeholder={col.label || col.key} />
    }
  }

  if (columns.length === 0) {
    return <div className="border border-dashed border-gray-300 dark:border-gray-600 rounded-lg p-3 text-center"><p className="text-xs text-gray-500 dark:text-gray-400 italic">No column schema defined for this field</p></div>
  }

  if (rows.length === 0 && !isExpanded) {
    return (
      <div className="border border-dashed border-gray-300 dark:border-gray-600 rounded-lg p-3 text-center">
        <p className="text-xs text-gray-500 dark:text-gray-400 mb-2 italic">No items</p>
        {!disabled && <button onClick={(e) => { e.stopPropagation(); setIsExpanded(true); handleAddRow(); }} className="text-xs text-blue-600 hover:text-blue-800 font-medium">+ Add item</button>}
      </div>
    )
  }

  return (
    <div className="border border-gray-200 dark:border-gray-600 rounded-lg overflow-hidden" onClick={(e) => e.stopPropagation()}>
      <div className="flex items-center justify-between px-3 py-2 bg-gray-50 dark:bg-gray-800 cursor-pointer select-none" onClick={() => setIsExpanded(!isExpanded)}>
        <span className="text-xs font-medium text-gray-600 dark:text-gray-400">{rows.length} item{rows.length !== 1 ? 's' : ''} · {columns.length} column{columns.length !== 1 ? 's' : ''}</span>
        <ChevronDown className={`h-3.5 w-3.5 text-gray-500 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
      </div>
      {isExpanded && (
        <div className="overflow-x-auto">
          <table className="w-full text-xs">
            <thead>
              <tr className="bg-gray-50 dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700">
                <th className="px-2 py-1.5 text-left text-gray-500 dark:text-gray-400 font-medium w-8">#</th>
                {columns.map(col => <th key={col.key} className="px-2 py-1.5 text-left text-gray-500 dark:text-gray-400 font-medium min-w-[100px]">{col.label || col.key}</th>)}
                {!disabled && <th className="px-2 py-1.5 w-8"></th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
              {rows.map((row, rowIdx) => (
                <tr key={rowIdx} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                  <td className="px-2 py-1.5 text-gray-400 font-mono">{rowIdx + 1}</td>
                  {columns.map(col => <td key={col.key} className="px-1 py-1">{renderCellInput(col, row[col.key], rowIdx)}</td>)}
                  {!disabled && (
                    <td className="px-1 py-1">
                      <button onClick={(e) => { e.stopPropagation(); handleRemoveRow(rowIdx); }} className="p-1 text-red-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 rounded transition-colors" title="Remove row"><X className="h-3 w-3" /></button>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
          {!disabled && (
            <div className="flex items-center px-3 py-2 bg-gray-50 dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700">
              <button onClick={(e) => { e.stopPropagation(); handleAddRow(); }} className="text-xs text-blue-600 hover:text-blue-800 font-medium flex items-center gap-1">+ Add row</button>
            </div>
          )}
        </div>
      )}
    </div>
  )
}

/**
 * FieldInput – Enhanced field input component with ui_properties support.
 */
function FieldInput({ field, onChange, onClick, isDate = false, isDropdown = false, requestId = null, onAlternativeSelect = null, onViewInDocument = null, documents = [], disabled = false, hasAuditHistoryFromParent = false }) {
  // --- UI Properties from template_field (all keys optional) ---
  const uiProps = field.ui_properties || {}
  if (uiProps.hidden) return null
  
  const fieldType = uiProps.inputType || field.field_type || (isDate ? 'date' : isDropdown ? 'dropdown' : 'text')
  const [value, setValue] = useState(() => sanitizeNumericValue(field.field_value || '', fieldType))
  const [showAlternatives, setShowAlternatives] = useState(false)
  const [alternatives, setAlternatives] = useState([])
  const [activeFieldData, setActiveFieldData] = useState(null)
  const [loadingAlternatives, setLoadingAlternatives] = useState(false)
  const [selectedPreview, setSelectedPreview] = useState(null)
  const popupRef = React.useRef(null)
  
  // Audit log state
  const [showAuditLog, setShowAuditLog] = useState(false)
  const [auditLogs, setAuditLogs] = useState([])
  const [loadingAuditLogs, setLoadingAuditLogs] = useState(false)
  const hasAuditHistory = hasAuditHistoryFromParent
  const auditPopupRef = React.useRef(null)
  
  const confidence = field.confidence || 0
  const confidencePercent = Math.round(confidence * 100)
  const alternativeCount = field.alternative_count || 0
  const hasAlternatives = alternativeCount >= 1
  
  const isLowConfidence = confidence < 0.7
  const isMediumConfidence = confidence >= 0.7 && confidence < 0.9
  const isHighConfidence = confidence >= 0.9
  
  const fetchFieldAuditLogs = async () => {
    if (!requestId || !field.id) return
    try {
      setLoadingAuditLogs(true)
      const res = await requestsApi.getFieldAuditLogs(requestId, field.id, { limit: 20 })
      setAuditLogs(res.data.audit_logs || [])
    } catch (err) {
      console.error('Error fetching field audit logs:', err)
      setAuditLogs([])
    } finally {
      setLoadingAuditLogs(false)
    }
  }
  
  React.useEffect(() => {
    const handleClickOutside = (event) => {
      if (popupRef.current && !popupRef.current.contains(event.target)) {
        setShowAlternatives(false)
        setSelectedPreview(null)
      }
      if (auditPopupRef.current && !auditPopupRef.current.contains(event.target)) {
        setShowAuditLog(false)
      }
    }
    if (showAlternatives || showAuditLog) {
      document.addEventListener('mousedown', handleClickOutside)
    }
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [showAlternatives, showAuditLog])
  
  const getDocumentFilename = (fieldData) => {
    if (fieldData?.source_document_filename) return fieldData.source_document_filename
    return 'Unknown Source'
  }
  
  const truncateFilename = (filename, maxLength = 30) => {
    if (!filename || filename.length <= maxLength) return filename
    const ext = filename.split('.').pop()
    const nameWithoutExt = filename.slice(0, filename.lastIndexOf('.'))
    const truncatedName = nameWithoutExt.slice(0, maxLength - ext.length - 4) + '...'
    return `${truncatedName}.${ext}`
  }
  
  const getAllValues = () => {
    const values = []
    const currentValue = activeFieldData || {
      id: field.id, field_value: field.field_value, confidence: field.confidence,
      source_document_id: field.source_document_id, source_document_filename: field.source_document_filename,
      page_number: field.page_number, bounding_box: field.bounding_box
    }
    values.push({ ...currentValue, isActive: true })
    alternatives.forEach(alt => { values.push({ ...alt, isActive: false }) })
    return values
  }
  
  const { flat: dropdownOptions, render: renderDropdownOptions } = parseDropdownOptions(field.field_values || '')
  
  const getConfidenceBadgeColor = () => {
    if (isHighConfidence) return 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400'
    if (isMediumConfidence) return 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400'
    return 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
  }
  
  const getInputBorderColor = () => {
    if (isLowConfidence) return 'border-red-300 bg-red-50 dark:border-red-700 dark:bg-red-900/20'
    if (isMediumConfidence) return 'border-orange-300 bg-orange-50 dark:border-orange-700 dark:bg-orange-900/20'
    return 'border-gray-200 bg-white dark:border-gray-600 dark:bg-gray-800'
  }
  
  const handleChange = (e) => {
    setValue(e.target.value)
    onChange(field.id, e.target.value)
  }
  
  const formatFieldName = (name) => {
    if (field.display_name) return field.display_name
    return name.replace(/([A-Z])/g, ' $1').replace(/_/g, ' ').replace(/^./, str => str.toUpperCase()).trim()
  }
  
  const loadAlternatives = async () => {
    if (!requestId || !field.field_name) return
    setLoadingAlternatives(true)
    try {
      const res = await requestsApi.getFieldAlternatives(requestId, field.field_name)
      setAlternatives(res.data.alternatives || [])
      setActiveFieldData(res.data.active || field)
    } catch (err) {
      console.error('Error loading alternatives:', err)
    } finally {
      setLoadingAlternatives(false)
    }
  }
  
  const handleAlternativesClick = async (e) => {
    e.stopPropagation()
    if (!showAlternatives) {
      setShowAlternatives(true)
      loadAlternatives()
    } else {
      setShowAlternatives(false)
      setSelectedPreview(null)
    }
  }
  
  const handleSelectAlternative = async (alt) => {
    if (onAlternativeSelect) {
      await onAlternativeSelect(alt.id, field.field_name, alt)
    }
    const newValue = alt.field_value || alt.extracted_value || ''
    setValue(sanitizeNumericValue(newValue, fieldType))
    setShowAlternatives(false)
    setSelectedPreview(null)
  }
  
  const isEmpty = (() => {
    const fv = field.field_value
    if (!fv) return true
    if (typeof fv !== 'string') return false
    const trimmed = fv.trim()
    if (trimmed === '') return true
    if (fieldType === 'array_of_objects' || fieldType === 'array') {
      try { const parsed = JSON.parse(trimmed); return Array.isArray(parsed) ? parsed.length === 0 : false } catch { return false }
    }
    return false
  })()
  
  // --- Derived UI overrides from ui_properties ---
  const isReadOnly      = uiProps.readOnly       || disabled
  const customPlaceholder = uiProps.placeholder   || null
  const helpText        = uiProps.helpText        || null
  const customRows      = uiProps.rows            || null
  const prefix          = uiProps.prefix          || null
  const suffix          = uiProps.suffix          || null
  const labelPosition   = uiProps.labelPosition   || 'top'
  const highlightColor  = uiProps.highlight       || null
  const isCompact       = uiProps.compact         || false
  
  const renderInput = () => {
    const sizeClasses = isCompact ? 'px-3 py-1.5 text-sm' : 'px-4 py-3 text-base'
    const baseClasses = `w-full ${sizeClasses} font-medium rounded-lg border ${getInputBorderColor()} focus:ring-2 focus:ring-blue-500 focus:border-transparent dark:text-gray-200 ${isReadOnly ? 'bg-gray-100 dark:bg-gray-800 cursor-not-allowed opacity-75' : ''}`
    
    switch (fieldType) {
      case 'date':
        const isValidDateFormat = /^\d{4}-\d{2}-\d{2}$/.test(value)
        return <input type={isValidDateFormat ? "date" : "text"} value={value} onChange={handleChange} onClick={(e) => e.stopPropagation()} className={baseClasses} placeholder={customPlaceholder || "Enter date..."} disabled={isReadOnly} />
      
      case 'number':
      case 'integer':
        return (
          <input type="text" inputMode="decimal" value={value}
            onChange={(e) => { const v = e.target.value; if (v === '' || v === '-' || v === '.' || v === '-.' || /^-?\d*\.?\d*$/.test(v)) { setValue(v); onChange(field.id, v) } }}
            onKeyDown={(e) => { if (/^[a-zA-Z]$/.test(e.key) && !e.ctrlKey && !e.metaKey) e.preventDefault() }}
            onClick={(e) => e.stopPropagation()} className={baseClasses} placeholder={customPlaceholder || ''} disabled={isReadOnly} />
        )
      
      case 'currency':
      case 'money':
        const parts = (value || '').split(' ')
        const currencySymbol = parts[0] || '$'
        const currencyAmount = parts.slice(1).join(' ') || ''
        return (
          <div className="flex gap-2">
            <input type="text" value={currencySymbol} onChange={(e) => { const nv = `${e.target.value} ${currencyAmount}`.trim(); setValue(nv); onChange(field.id, nv) }} onClick={(e) => e.stopPropagation()} className={`${baseClasses} w-20 text-center`} placeholder={prefix || "$"} maxLength="5" disabled={isReadOnly} />
            <input type="text" inputMode="decimal" value={currencyAmount}
              onChange={(e) => { const na = e.target.value; if (na === '' || na === '-' || na === '.' || na === '-.' || /^-?[\d,]*\.?\d*$/.test(na)) { const nv = `${currencySymbol} ${na}`.trim(); setValue(nv); onChange(field.id, nv) } }}
              onKeyDown={(e) => { if (/^[a-zA-Z]$/.test(e.key) && !e.ctrlKey && !e.metaKey) e.preventDefault() }}
              onClick={(e) => e.stopPropagation()} className={`${baseClasses} flex-1`} placeholder={customPlaceholder || "0.00"} disabled={isReadOnly} />
          </div>
        )
      
      case 'dropdown':
      case 'select':
      case 'enum':
        const valueMatchesOption = !value || dropdownOptions.some(opt => opt.toLowerCase() === (value || '').toLowerCase())
        return (
          <select value={valueMatchesOption ? value : ''} onChange={handleChange} onClick={(e) => e.stopPropagation()} className={`${baseClasses} pr-12 cursor-pointer`} disabled={isReadOnly}>
            <option value="">{customPlaceholder || 'Select...'}</option>
            {renderDropdownOptions()}
          </select>
        )
      
      case 'textarea':
      case 'text_area':
      case 'multiline':
        return <textarea value={value} onChange={handleChange} onClick={(e) => e.stopPropagation()} rows={customRows || 3} className={`${baseClasses} resize-none`} placeholder={customPlaceholder || ''} disabled={isReadOnly} />
      
      case 'percentage':
      case 'percent':
        return (
          <div className="relative">
            <input type="text" inputMode="decimal" value={value}
              onChange={(e) => { const v = e.target.value; if (v === '' || v === '.' || /^\d*\.?\d*$/.test(v)) { setValue(v); onChange(field.id, v) } }}
              onKeyDown={(e) => { if (/^[a-zA-Z]$/.test(e.key) && !e.ctrlKey && !e.metaKey) e.preventDefault() }}
              onClick={(e) => e.stopPropagation()} className={`${baseClasses} pr-8`} placeholder={customPlaceholder || ''} disabled={isReadOnly} />
            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 text-sm">{suffix || '%'}</span>
          </div>
        )
      
      case 'array_of_objects':
      case 'array':
        return <ArrayOfObjectsField value={value} schema={field.field_values} onChange={(newVal) => { setValue(newVal); onChange(field.id, newVal) }} disabled={isReadOnly} />
      
      case 'boolean':
      case 'bool':
        return (
          <select value={value} onChange={handleChange} onClick={(e) => e.stopPropagation()} className={`${baseClasses} pr-12 cursor-pointer`} disabled={isReadOnly}>
            <option value="">{customPlaceholder || 'Select...'}</option>
            <option value="true">Yes</option>
            <option value="false">No</option>
          </select>
        )
      
      case 'text':
      default:
        if (prefix || suffix) {
          return (
            <div className="flex items-center gap-0">
              {prefix && <span className={`${isCompact ? 'px-2 py-1.5 text-sm' : 'px-3 py-3 text-base'} font-medium bg-gray-100 dark:bg-gray-700 text-gray-500 dark:text-gray-400 border border-r-0 border-gray-200 dark:border-gray-600 rounded-l-lg`}>{prefix}</span>}
              <input type="text" value={value} onChange={handleChange} onClick={(e) => e.stopPropagation()} className={`${baseClasses} ${isEmpty ? 'italic' : ''} ${prefix ? 'rounded-l-none' : ''} ${suffix ? 'rounded-r-none' : ''}`} placeholder={customPlaceholder || (isEmpty ? "Enter value..." : "")} disabled={isReadOnly} />
              {suffix && <span className={`${isCompact ? 'px-2 py-1.5 text-sm' : 'px-3 py-3 text-base'} font-medium bg-gray-100 dark:bg-gray-700 text-gray-500 dark:text-gray-400 border border-l-0 border-gray-200 dark:border-gray-600 rounded-r-lg`}>{suffix}</span>}
            </div>
          )
        }
        return <input type="text" value={value} onChange={handleChange} onClick={(e) => e.stopPropagation()} className={`${baseClasses} ${isEmpty ? 'italic' : ''}`} placeholder={customPlaceholder || (isEmpty ? "Enter value..." : "")} disabled={isReadOnly} />
    }
  }
  
  const highlightBorderStyle = highlightColor ? { borderLeft: `3px solid ${highlightColor.startsWith('#') ? highlightColor : `var(--color-${highlightColor}, ${highlightColor})`}` } : {}
  
  return (
    <div onClick={onClick} className={`cursor-pointer relative group ${highlightColor ? 'pl-2' : ''}`} style={highlightBorderStyle}>
      {/* Field Label Row */}
      <div className={`flex items-center justify-between gap-2 ${labelPosition === 'inline' ? 'mb-0' : 'mb-1.5'}`}>
        <div className="flex items-center gap-2">
          <div className={`w-1.5 h-1.5 rounded-full ${isHighConfidence ? 'bg-green-500' : isMediumConfidence ? 'bg-orange-500' : 'bg-red-500'}`}></div>
          <label className={`${isCompact ? 'text-[10px]' : 'text-xs'} font-medium text-gray-600 dark:text-gray-400`}>
            {formatFieldName(field.field_name)}
          </label>
          {!isEmpty && <span className={`text-xs px-1.5 py-0.5 rounded ${getConfidenceBadgeColor()}`}>{confidencePercent}%</span>}
          {!isEmpty && field.source_type === 'llm_fallback' && (
            <span className="text-xs px-1.5 py-0.5 rounded bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400" title="Extracted by AI (LLM fallback)">AI</span>
          )}
          {isEmpty && <span className="text-xs text-gray-500 dark:text-gray-500 italic">Not extracted</span>}
          {!isEmpty && isLowConfidence && !hasAlternatives && <span className="text-xs text-red-500 dark:text-red-400 italic">Low confidence - manual review required</span>}
        </div>
        
        <div className="flex items-center gap-1">
          <button onClick={(e) => { e.stopPropagation(); if (!showAuditLog) fetchFieldAuditLogs(); setShowAuditLog(!showAuditLog) }}
            className={`flex-shrink-0 p-1.5 rounded-md transition-all ${showAuditLog ? 'bg-purple-600 text-white' : hasAuditHistory ? 'text-purple-500 hover:bg-purple-50 hover:text-purple-600' : 'text-gray-400 hover:bg-gray-50 hover:text-gray-500'}`}
            title="View edit history">
            <History className="h-3.5 w-3.5" />
          </button>
          {hasAlternatives && !disabled && (
            <button onClick={handleAlternativesClick}
              className={`flex-shrink-0 flex items-center gap-1.5 px-2.5 py-1 rounded-md text-xs font-medium transition-all border ${showAlternatives ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-blue-600 border-blue-200 hover:bg-blue-50 hover:border-blue-300'}`}
              title={`${alternativeCount} alternative value(s) from different documents`}>
              <Layers className="h-3 w-3" /><span>{alternativeCount + 1}</span>
              <ChevronDown className={`h-2.5 w-2.5 transition-transform ${showAlternatives ? 'rotate-180' : ''}`} />
            </button>
          )}
        </div>
      </div>
      
      {/* Input with field value */}
      <div className={`${labelPosition === 'inline' ? 'flex-1' : ''} relative`}>
        {renderInput()}
        {fieldType === 'date' && (
          <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none flex items-center justify-center w-8 h-8 rounded-md bg-gray-100 dark:bg-gray-700/60">
            <svg className="h-4 w-4 text-gray-500 dark:text-gray-400" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
              <rect x="3" y="4" width="18" height="18" rx="3" stroke="currentColor" strokeWidth="1.8" />
              <path d="M3 9.5h18" stroke="currentColor" strokeWidth="1.8" />
              <path d="M8 2.5v3M16 2.5v3" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" />
              <circle cx="8.5" cy="14" r="1" fill="currentColor" /><circle cx="12" cy="14" r="1" fill="currentColor" /><circle cx="15.5" cy="14" r="1" fill="currentColor" />
              <circle cx="8.5" cy="17.5" r="1" fill="currentColor" /><circle cx="12" cy="17.5" r="1" fill="currentColor" />
            </svg>
          </div>
        )}
        {(fieldType === 'dropdown' || fieldType === 'select' || fieldType === 'enum' || fieldType === 'boolean' || fieldType === 'bool') && (
          <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none flex items-center justify-center w-8 h-8 rounded-md bg-gray-100 dark:bg-gray-700/60">
            <ChevronDown className="h-4 w-4 text-gray-500 dark:text-gray-400" />
          </div>
        )}
      </div>
      
      {/* Help text from ui_properties */}
      {helpText && <p className="mt-1 text-[10px] text-gray-400 dark:text-gray-500 italic">{helpText}</p>}
      
      {/* Alternatives Popup */}
      {showAlternatives && (
        <div ref={popupRef} className="absolute z-50 mt-2 right-0 bg-white dark:bg-gray-900 rounded-lg shadow-xl border border-gray-200 dark:border-gray-700 overflow-hidden" style={{ width: '340px' }} onClick={(e) => e.stopPropagation()}>
          <div className="px-3 py-2.5 bg-gray-50 dark:bg-gray-800 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between">
            <span className="text-xs font-medium text-gray-700 dark:text-gray-300">Select value <span className="text-gray-400">({alternatives.length + 1} found)</span></span>
            <button onClick={(e) => { e.stopPropagation(); setShowAlternatives(false); }} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition-colors"><X className="h-3.5 w-3.5" /></button>
          </div>
          {loadingAlternatives ? (
            <div className="p-6 text-center"><RefreshCw className="h-4 w-4 animate-spin mx-auto text-blue-500" /><span className="text-xs text-gray-500 mt-2 block">Loading...</span></div>
          ) : (
            <div className="overflow-y-auto max-h-64 divide-y divide-gray-100 dark:divide-gray-700">
              {getAllValues().map((item) => (
                <div key={item.id}
                  className={`px-3 py-2.5 transition-all cursor-pointer flex items-center gap-3 ${item.isActive ? 'bg-green-50 dark:bg-green-900/30' : selectedPreview?.id === item.id ? 'bg-blue-50 dark:bg-blue-900/30' : 'hover:bg-gray-50 dark:hover:bg-gray-800'}`}
                  onClick={(e) => { e.stopPropagation(); setSelectedPreview(item); if (onViewInDocument && item.source_document_id) onViewInDocument(item.source_document_id, item.page_number || 1, item.bounding_box) }}>
                  <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center flex-shrink-0 transition-colors ${item.isActive ? 'border-green-500 bg-green-500' : 'border-gray-300 hover:border-blue-500'}`}
                    onClick={(e) => { e.stopPropagation(); if (!item.isActive) handleSelectAlternative(item) }}>
                    {item.isActive && <Check className="h-2.5 w-2.5 text-white" />}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className={`text-sm truncate ${item.isActive ? 'font-medium text-gray-900 dark:text-gray-100' : 'text-gray-700 dark:text-gray-300'}`}>{item.field_value || item.extracted_value || '(empty)'}</p>
                    <p className="text-xs text-gray-400 truncate mt-0.5">{truncateFilename(getDocumentFilename(item), 35)}{item.page_number && <span className="ml-1">• p.{item.page_number}</span>}</p>
                  </div>
                  <span className={`text-xs px-1.5 py-0.5 rounded font-medium flex-shrink-0 ${(item.confidence || 0) >= 0.9 ? 'bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-300' : (item.confidence || 0) >= 0.7 ? 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/40 dark:text-yellow-300' : 'bg-red-100 text-red-700 dark:bg-red-900/40 dark:text-red-300'}`}>
                    {Math.round((item.confidence || 0) * 100)}%
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
      
      {/* Audit History Popup */}
      {showAuditLog && (
        <div ref={auditPopupRef} className="absolute z-50 mt-2 right-0 bg-white dark:bg-gray-900 rounded-lg shadow-xl border border-gray-200 dark:border-gray-700 overflow-hidden" style={{ width: '380px' }} onClick={(e) => e.stopPropagation()}>
          <div className="px-3 py-2.5 bg-purple-50 dark:bg-purple-900/30 border-b border-purple-100 dark:border-purple-800 flex items-center justify-between">
            <span className="text-xs font-medium text-purple-700 flex items-center gap-1.5"><History className="h-3.5 w-3.5" /> Edit History</span>
            <button onClick={(e) => { e.stopPropagation(); setShowAuditLog(false); }} className="text-purple-400 hover:text-purple-600 p-1 hover:bg-purple-100 rounded transition-colors"><X className="h-3.5 w-3.5" /></button>
          </div>
          {loadingAuditLogs ? (
            <div className="p-6 text-center"><RefreshCw className="h-4 w-4 animate-spin mx-auto text-purple-500" /><span className="text-xs text-gray-500 mt-2 block">Loading history...</span></div>
          ) : auditLogs.length === 0 ? (
            <div className="p-6 text-center text-gray-500 dark:text-gray-400 text-sm">No edit history found</div>
          ) : (
            <div className="overflow-y-auto max-h-72 divide-y divide-gray-100 dark:divide-gray-700">
              {auditLogs.map((log, idx) => {
                let oldValue = null, newValue = null
                try {
                  const changes = typeof log.audit_json === 'string' ? JSON.parse(log.audit_json) : log.audit_json
                  Object.keys(changes || {}).forEach(key => { if (changes[key].old !== undefined || changes[key].new !== undefined) { oldValue = changes[key].old; newValue = changes[key].new } })
                } catch (e) { console.error('Error parsing audit_json:', e) }
                return (
                  <div key={log.id || idx} className="px-3 py-2.5">
                    <div className="flex items-center justify-between mb-1.5">
                      <span className="text-xs text-gray-500">{log.created_by_name || log.created_by || 'System'}</span>
                      <span className="text-xs text-gray-400">{log.created_at ? formatDateTime(log.created_at) : ''}</span>
                    </div>
                    <div className="space-y-1">
                      {oldValue !== null && oldValue !== undefined && (
                        <div className="flex items-start gap-2"><span className="text-xs text-red-500 font-medium w-10 flex-shrink-0">From:</span><span className="text-xs text-gray-600 dark:text-gray-300 bg-red-50 dark:bg-red-900/20 px-2 py-0.5 rounded break-all">{String(oldValue) || '(empty)'}</span></div>
                      )}
                      {newValue !== null && newValue !== undefined && (
                        <div className="flex items-start gap-2"><span className="text-xs text-green-600 font-medium w-10 flex-shrink-0">To:</span><span className="text-xs text-gray-600 dark:text-gray-300 bg-green-50 dark:bg-green-900/20 px-2 py-0.5 rounded break-all">{String(newValue) || '(empty)'}</span></div>
                      )}
                    </div>
                    {log.reason && <div className="mt-1.5 text-xs text-gray-500 italic">"{log.reason}"</div>}
                  </div>
                )
              })}
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default RequestDetail
