import React, { createContext, useContext, useState, useEffect, useCallback } from 'react'
import { useAuth } from './AuthContext'
import { brandingApi } from '../services/api'

const BrandingContext = createContext(null)

// Xtract default branding — used for reset and initial state
export const BRANDING_DEFAULTS = {
  app_name: 'Xtract',
  subtitle: 'Synapx AI',
  logo_url: null,
  favicon_url: null,
  primary_color: '#1e2a3b',
  accent_color: '#2563eb',
  login_tagline: null,
  is_default: true,
  apply_to_plugin: false,
}

/**
 * Inject branding colors as CSS custom properties on :root
 * so Tailwind/CSS classes can reference var(--brand-primary) etc.
 */
function applyBrandColors(primary, accent) {
  const root = document.documentElement
  root.style.setProperty('--brand-primary', primary || BRANDING_DEFAULTS.primary_color)
  root.style.setProperty('--brand-accent', accent || BRANDING_DEFAULTS.accent_color)

  // Pre-compute lighter/darker shades for hover states
  root.style.setProperty('--brand-primary-hover', darkenHex(primary || BRANDING_DEFAULTS.primary_color, 15))
  root.style.setProperty('--brand-primary-light', lightenHex(primary || BRANDING_DEFAULTS.primary_color, 90))
}

/** Darken a hex color by a percentage (0-100) */
function darkenHex(hex, percent) {
  const num = parseInt(hex.replace('#', ''), 16)
  const r = Math.max(0, (num >> 16) - Math.round(2.55 * percent))
  const g = Math.max(0, ((num >> 8) & 0x00ff) - Math.round(2.55 * percent))
  const b = Math.max(0, (num & 0x0000ff) - Math.round(2.55 * percent))
  return `#${(0x1000000 + r * 0x10000 + g * 0x100 + b).toString(16).slice(1)}`
}

/** Lighten a hex color by mixing with white */
function lightenHex(hex, percent) {
  const num = parseInt(hex.replace('#', ''), 16)
  const r = Math.min(255, (num >> 16) + Math.round((255 - (num >> 16)) * percent / 100))
  const g = Math.min(255, ((num >> 8) & 0x00ff) + Math.round((255 - ((num >> 8) & 0x00ff)) * percent / 100))
  const b = Math.min(255, (num & 0x0000ff) + Math.round((255 - (num & 0x0000ff)) * percent / 100))
  return `#${(0x1000000 + r * 0x10000 + g * 0x100 + b).toString(16).slice(1)}`
}

/** Update <link rel="icon"> dynamically */
function applyFavicon(url) {
  try {
    const existing = document.querySelector("link[rel~='icon']")
    if (!url) {
      // Remove custom favicon — browser will fall back to /favicon.ico
      if (existing) existing.remove()
      return
    }
    if (existing) {
      existing.href = url
    } else {
      const link = document.createElement('link')
      link.rel = 'icon'
      link.href = url
      document.head.appendChild(link)
    }
  } catch (e) {
    // Ignore DOM errors (e.g. insertBefore race conditions)
  }
}

export function BrandingProvider({ children }) {
  const { isAuthenticated, accessToken } = useAuth()
  const [branding, setBranding] = useState(BRANDING_DEFAULTS)
  const [loading, setLoading] = useState(false)

  // Fetch branding when authenticated
  useEffect(() => {
    if (!isAuthenticated || !accessToken) return

    setLoading(true)
    brandingApi.get()
      .then(res => {
        const data = res.data
        setBranding(data)
        applyBrandColors(data.primary_color, data.accent_color)
        // Don't apply favicon here — only apply when user explicitly saves
        if (data.app_name) {
          document.title = data.app_name
        }
      })
      .catch(err => {
        console.warn('Failed to load branding, using defaults:', err)
        applyBrandColors(BRANDING_DEFAULTS.primary_color, BRANDING_DEFAULTS.accent_color)
      })
      .finally(() => setLoading(false))
  }, [isAuthenticated, accessToken])

  // Apply defaults on mount for unauthenticated pages (login)
  useEffect(() => {
    applyBrandColors(branding.primary_color, branding.accent_color)
  }, [])

  const updateBranding = useCallback(async (updates) => {
    const res = await brandingApi.update(updates)
    const data = res.data
    setBranding(prev => ({ ...prev, ...data, is_default: false }))
    applyBrandColors(data.primary_color || updates.primary_color, data.accent_color || updates.primary_color)
    applyFavicon(data.favicon_url)
    if (data.app_name) document.title = data.app_name
    return data
  }, [])

  const resetBranding = useCallback(async () => {
    const res = await brandingApi.reset()
    const data = res.data
    setBranding({ ...BRANDING_DEFAULTS, ...data, logo_url: null, favicon_url: null })
    applyBrandColors(BRANDING_DEFAULTS.primary_color, BRANDING_DEFAULTS.accent_color)
    applyFavicon(null)
    document.title = BRANDING_DEFAULTS.app_name
  }, [])

  const uploadLogo = useCallback(async (file, type = 'logo') => {
    const res = await brandingApi.uploadLogo(file, type)
    const { url } = res.data
    // Don't update global state here — let Settings page hold it locally
    // until the user clicks Save. The save response will update global state.
    return url
  }, [])

  return (
    <BrandingContext.Provider value={{
      branding,
      loading,
      updateBranding,
      resetBranding,
      uploadLogo,
      BRANDING_DEFAULTS,
    }}>
      {children}
    </BrandingContext.Provider>
  )
}

export function useBranding() {
  const context = useContext(BrandingContext)
  if (!context) {
    throw new Error('useBranding must be used within a BrandingProvider')
  }
  return context
}
