import React from 'react'
import ReactDOM from 'react-dom/client'
import { BrowserRouter } from 'react-router-dom'
import { PublicClientApplication, EventType } from '@azure/msal-browser'
import { MsalProvider } from '@azure/msal-react'
import App from './App'
import { AuthProvider } from './context/AuthContext'
import { ThemeProvider } from './context/ThemeContext'
import { ToastProvider } from './context/ToastContext'
import { BrandingProvider } from './context/BrandingContext'
import { msalConfig, isMsalConfigured } from './config/msalConfig'
import './index.css'

// Error Boundary for debugging
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props)
    this.state = { hasError: false, error: null }
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error }
  }

  componentDidCatch(error, errorInfo) {
    console.error('React Error Boundary caught an error:', error, errorInfo)
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '20px', color: 'red' }}>
          <h1>Something went wrong.</h1>
          <pre>{this.state.error?.toString()}</pre>
        </div>
      )
    }
    return this.props.children
  }
}

// Initialize MSAL instance (only if configured)
let msalInstance = null
if (isMsalConfigured()) {
  msalInstance = new PublicClientApplication(msalConfig)
  
  // Initialize MSAL
  msalInstance.initialize().then(() => {
    // Set active account on login success
    msalInstance.addEventCallback((event) => {
      if (event.eventType === EventType.LOGIN_SUCCESS && event.payload?.account) {
        msalInstance.setActiveAccount(event.payload.account)
      }
    })
  })
}

// MSAL wrapper component
const MsalAppWrapper = () => {
  return (
    <ThemeProvider>
      <ToastProvider>
        <MsalProvider instance={msalInstance}>
          <AuthProvider>
            <BrandingProvider>
              <App />
            </BrandingProvider>
          </AuthProvider>
        </MsalProvider>
      </ToastProvider>
    </ThemeProvider>
  )
}

// Dev mode wrapper - no MSAL
const DevAppWrapper = () => {
  return (
    <ThemeProvider>
      <ToastProvider>
        <AuthProvider>
          <BrandingProvider>
            <App />
          </BrandingProvider>
        </AuthProvider>
      </ToastProvider>
    </ThemeProvider>
  )
}

ReactDOM.createRoot(document.getElementById('root')).render(
  <ErrorBoundary>
    <BrowserRouter>
      {isMsalConfigured() ? (
        <MsalAppWrapper />
      ) : (
        <DevAppWrapper />
      )}
    </BrowserRouter>
  </ErrorBoundary>
)
