import React, { useState, useEffect, useRef, useCallback } from 'react';
import * as pdfjsLib from 'pdfjs-dist';
import { ChevronLeft, ChevronRight, ZoomIn, ZoomOut, Loader, X, Maximize2, CornerDownLeft } from 'lucide-react';
import { documentsApi } from '../services/api';

// Set up PDF.js worker - use CDN for reliable production loading
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://unpkg.com/pdfjs-dist@${pdfjsLib.version}/build/pdf.worker.min.mjs`;

/**
 * PDFViewer component with field highlighting support
 * Based on the Xtract document-extraction EmailDetail implementation
 * 
 * @param {Object} props
 * @param {string} props.documentId - ID of the document to load
 * @param {Object|null} props.highlightedField - Field to highlight (with bounding_box and page_number)
 * @param {function} props.onClose - Callback when viewer is closed
 */
function PDFViewer({ documentId, highlightedField, onClose }) {
  const canvasRef = useRef(null);
  const overlayCanvasRef = useRef(null);
  const containerRef = useRef(null);
  
  const [pdfDoc, setPdfDoc] = useState(null);
  const [currentPage, setCurrentPage] = useState(1);
  const [pageInput, setPageInput] = useState('1');
  const [totalPages, setTotalPages] = useState(0);
  const [scale, setScale] = useState(null); // Start with null to prevent premature rendering
  const [fitToWidth, setFitToWidth] = useState(true); // Auto-fit enabled by default
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [rendering, setRendering] = useState(false);
  const [baseViewport, setBaseViewport] = useState(null); // Store base viewport for fit calculations
  const [initialFitDone, setInitialFitDone] = useState(false); // Track if initial fit is done
  const [loadingProgress, setLoadingProgress] = useState(''); // Loading progress text
  const [retryCount, setRetryCount] = useState(0); // Retry counter to re-trigger load
  const [highlightRegions, setHighlightRegions] = useState([]); // Computed highlight regions for hover tooltips
  
  // Sync pageInput when currentPage changes (from arrows, highlights, etc.)
  useEffect(() => {
    setPageInput(String(currentPage));
  }, [currentPage]);
  
  // Load PDF document
  useEffect(() => {
    if (!documentId) {
      setError('No document ID provided');
      setLoading(false);
      return;
    }
    
    let cancelled = false;
    
    // Reset state when document changes
    setFitToWidth(true); // Re-enable fit-to-width for new document
    setScale(null); // Reset to null to wait for fit calculation
    setCurrentPage(1);
    setPdfDoc(null);
    setInitialFitDone(false);
    setLoadingProgress('');
    
    const loadPDF = async () => {
      try {
        setLoading(true);
        setError(null);
        
        let loadingTask;
        
        // ── Strategy 1: SAS URL (direct from Azure Storage, bypasses backend) ──
        try {
          setLoadingProgress('Getting document URL...');
          const sasResponse = await documentsApi.getSasUrl(documentId, 1); // 1-hour expiry
          const sasUrl = sasResponse.data?.url;
          
          if (sasUrl && !cancelled) {
            setLoadingProgress('Loading PDF from storage...');
            loadingTask = pdfjsLib.getDocument({
              url: sasUrl,
              disableStream: false,
              disableAutoFetch: false,
              withCredentials: false, // SAS URL doesn't need credentials
            });
            
            loadingTask.onProgress = (progress) => {
              if (cancelled) return;
              if (progress.total > 0) {
                const pct = Math.round((progress.loaded / progress.total) * 100);
                setLoadingProgress(`Loading PDF... ${pct}%`);
              }
            };
            
            const pdf = await loadingTask.promise;
            
            if (cancelled) return;
            
            console.log('PDFViewer: Loaded via SAS URL');
            setPdfDoc(pdf);
            setTotalPages(pdf.numPages);
            setCurrentPage(1);
            setLoadingProgress('');
            setLoading(false);
            return; // Success — done
          }
        } catch (sasErr) {
          // SAS URL approach failed (CORS not configured, network issue, etc.)
          // Fall through to backend proxy approach
          console.warn('PDFViewer: SAS URL approach failed, falling back to backend proxy:', sasErr.message);
        }
        
        if (cancelled) return;
        
        // ── Strategy 2: Backend proxy (fallback) ──
        setLoadingProgress('Downloading document via server...');
        
        const response = await documentsApi.getPdfBlob(documentId);
        
        if (cancelled) return;
        
        const dataSize = response.data?.byteLength || 0;
        
        if (!response.data || dataSize === 0) {
          throw new Error('Empty PDF content received');
        }
        
        const sizeMB = (dataSize / (1024 * 1024)).toFixed(1);
        setLoadingProgress(`Parsing PDF (${sizeMB} MB)...`);
        
        loadingTask = pdfjsLib.getDocument({ 
          data: response.data,
          // Improve performance for large documents
          disableAutoFetch: dataSize > 5 * 1024 * 1024, // disable auto-fetch for files > 5MB
          disableStream: false,
        });
        
        loadingTask.onProgress = (progress) => {
          if (cancelled) return;
          if (progress.total > 0) {
            const pct = Math.round((progress.loaded / progress.total) * 100);
            setLoadingProgress(`Parsing PDF... ${pct}%`);
          }
        };
        
        const pdf = await loadingTask.promise;
        
        if (cancelled) return;
        
        console.log('PDFViewer: Loaded via backend proxy');
        setPdfDoc(pdf);
        setTotalPages(pdf.numPages);
        setCurrentPage(1);
        setLoadingProgress('');
      } catch (err) {
        if (cancelled) return;
        console.error('PDFViewer: Error loading PDF:', err);
        const errorMessage = err.message || 'Unknown error';
        setError(`Failed to load PDF: ${errorMessage}`);
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    };
    
    loadPDF();
    
    return () => {
      cancelled = true;
    };
  }, [documentId, retryCount]);
  
  // Navigate to highlighted field page
  useEffect(() => {
    if (highlightedField?.page_number && pdfDoc) {
      const targetPage = highlightedField.page_number;
      if (targetPage >= 1 && targetPage <= totalPages && targetPage !== currentPage) {
        setCurrentPage(targetPage);
      }
    }
  }, [highlightedField?.page_number, highlightedField?.field_name, pdfDoc, totalPages]);
  
  // Calculate fit-to-width scale
  const calculateFitScale = useCallback(async (pageNum) => {
    if (!pdfDoc || !containerRef.current) return 1.0;
    
    try {
      const page = await pdfDoc.getPage(pageNum);
      const viewport = page.getViewport({ scale: 1.0 });
      
      // Store base viewport for reference
      setBaseViewport(viewport);
      
      // Get container width - be conservative with padding/margins
      // Account for: container padding (32px), scrollbar (~17px), and some buffer (10px)
      const containerWidth = containerRef.current.clientWidth - 60;
      
      // Calculate scale to fit width
      const fitScale = containerWidth / viewport.width;
      
      // Clamp between reasonable min/max values - allow smaller scales for very wide docs
      return Math.max(0.1, Math.min(fitScale, 3.0));
    } catch (err) {
      console.error('Error calculating fit scale:', err);
      return 1.0;
    }
  }, [pdfDoc]);
  
  // Auto-fit when PDF loads or page changes
  useEffect(() => {
    if (pdfDoc && fitToWidth && containerRef.current) {
      // Use requestAnimationFrame to ensure layout is complete before measuring
      const rafId = requestAnimationFrame(() => {
        setTimeout(() => {
          calculateFitScale(currentPage).then(fitScale => {
            setScale(fitScale);
            setInitialFitDone(true);
          });
        }, 50);
      });
      return () => cancelAnimationFrame(rafId);
    } else if (pdfDoc && !fitToWidth && scale === null) {
      // If fit-to-width is disabled but we don't have a scale, use default 1.0
      setScale(1.0);
      setInitialFitDone(true);
    }
  }, [pdfDoc, currentPage, fitToWidth, calculateFitScale]);
  
  // Handle window resize for fit-to-width
  useEffect(() => {
    if (!fitToWidth || !initialFitDone) return;
    
    const handleResize = () => {
      if (pdfDoc) {
        calculateFitScale(currentPage).then(fitScale => {
          setScale(fitScale);
        });
      }
    };
    
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [pdfDoc, currentPage, fitToWidth, calculateFitScale, initialFitDone]);
  
  // Render page when page number, scale, or PDF changes - only if scale is set
  useEffect(() => {
    if (pdfDoc && scale !== null) {
      renderPage(currentPage);
    }
  }, [pdfDoc, currentPage, scale, highlightedField]);
  
  // Parse D(pageNum, x1,y1, x2,y2, x3,y3, x4,y4) format
  // Handles semicolon-separated multiple D() entries: "D(13,...);D(14,...)"
  const parseBoundingBoxes = (location, pageWidthInches, pageHeightInches) => {
    if (!location || typeof location !== 'string') return [];
    
    const regions = [];
    const pattern = /D\((\d+),([\d.]+),([\d.]+),([\d.]+),([\d.]+),([\d.]+),([\d.]+),([\d.]+),([\d.]+)\)/g;
    let match;
    while ((match = pattern.exec(location)) !== null) {
      const pageNumber = parseInt(match[1]);
      const points = [
        parseFloat(match[2]), parseFloat(match[3]),  // x1, y1
        parseFloat(match[4]), parseFloat(match[5]),  // x2, y2
        parseFloat(match[6]), parseFloat(match[7]),  // x3, y3
        parseFloat(match[8]), parseFloat(match[9])   // x4, y4
      ];
      
      // Convert from inches to normalized coordinates (0-1)
      const normalizedPolygon = [];
      for (let i = 0; i < points.length; i += 2) {
        normalizedPolygon.push(points[i] / pageWidthInches);
        normalizedPolygon.push(points[i + 1] / pageHeightInches);
      }
      
      regions.push({ pageNumber, polygon: normalizedPolygon });
    }
    
    return regions;
  };
  
  // Render a page
  const renderPage = async (pageNum) => {
    if (!pdfDoc || rendering) return;
    
    try {
      setRendering(true);
      
      const page = await pdfDoc.getPage(pageNum);
      const viewport = page.getViewport({ scale });
      
      // Set up main canvas
      const canvas = canvasRef.current;
      if (!canvas) return;
      
      const context = canvas.getContext('2d');
      canvas.height = viewport.height;
      canvas.width = viewport.width;
      
      // Render PDF page
      await page.render({
        canvasContext: context,
        viewport: viewport
      }).promise;
      
      // Set up overlay canvas for highlights
      const overlayCanvas = overlayCanvasRef.current;
      if (overlayCanvas) {
        overlayCanvas.height = viewport.height;
        overlayCanvas.width = viewport.width;
        
        const overlayContext = overlayCanvas.getContext('2d');
        overlayContext.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);
        
        // Draw highlight if field is selected
        const computedRegions = [];
        if (highlightedField?.bounding_box || highlightedField?.bounding_boxes) {
          // Get page dimensions in inches (72 points per inch)
          const pageView = page.view;
          const pageWidthPt = pageView[2] - pageView[0];
          const pageHeightPt = pageView[3] - pageView[1];
          const pageWidthInches = pageWidthPt / 72;
          const pageHeightInches = pageHeightPt / 72;
          
          // Collect all bounding boxes to draw
          const boxes = highlightedField.bounding_boxes
            ? highlightedField.bounding_boxes
            : [highlightedField.bounding_box];
          
          // Field labels array (parallel to bounding_boxes)
          const fieldLabels = highlightedField.field_labels || [];
          
          boxes.forEach((box, idx) => {
            // Each box string may contain multiple D() entries separated by ;
            // e.g. "D(13,...);D(14,...)" for multi-page/multi-box fields
            const regions = parseBoundingBoxes(
              box,
              pageWidthInches,
              pageHeightInches
            );
            const label = fieldLabels[idx] || highlightedField.field_name || '';
            
            regions.forEach((region) => {
              if (region.pageNumber === pageNum) {
                drawHighlight(overlayContext, region.polygon, viewport);
                
                // Compute bounding rect from polygon for hover overlay
                const poly = region.polygon;
                let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
                for (let i = 0; i < poly.length; i += 2) {
                  const px = poly[i] * viewport.width;
                  const py = poly[i + 1] * viewport.height;
                  minX = Math.min(minX, px);
                  minY = Math.min(minY, py);
                  maxX = Math.max(maxX, px);
                  maxY = Math.max(maxY, py);
                }
                
                if (label) {
                  // Round to 1 decimal to group overlapping boxes
                  const key = `${Math.round(minX)}_${Math.round(minY)}_${Math.round(maxX)}_${Math.round(maxY)}`;
                  const existing = computedRegions.find(r => r._key === key);
                  if (existing) {
                    // Append label if not already present
                    if (!existing.label.split(', ').includes(label)) {
                      existing.label += `, ${label}`;
                    }
                  } else {
                    computedRegions.push({
                      _key: key,
                      left: minX,
                      top: minY,
                      width: maxX - minX,
                      height: maxY - minY,
                      label
                    });
                  }
                }
              }
            });
          });
        }
        setHighlightRegions(computedRegions);
      }
    } catch (err) {
      console.error('Error rendering page:', err);
    } finally {
      setRendering(false);
    }
  };
  
  // Draw a highlight polygon
  const drawHighlight = (context, polygon, viewport) => {
    if (!polygon || polygon.length < 6) return;
    
    context.beginPath();
    context.strokeStyle = '#3b82f6';  // Blue stroke
    context.fillStyle = 'rgba(59, 130, 246, 0.25)';  // Semi-transparent blue fill
    context.lineWidth = 3;
    
    // Draw polygon from normalized coordinates
    for (let i = 0; i < polygon.length; i += 2) {
      const x = polygon[i] * viewport.width;
      const y = polygon[i + 1] * viewport.height;
      if (i === 0) {
        context.moveTo(x, y);
      } else {
        context.lineTo(x, y);
      }
    }
    
    context.closePath();
    context.fill();
    context.stroke();
  };
  
  // Navigation handlers
  const goToPrevPage = () => {
    if (currentPage > 1) {
      setCurrentPage(currentPage - 1);
    }
  };
  
  const goToNextPage = () => {
    if (currentPage < totalPages) {
      setCurrentPage(currentPage + 1);
    }
  };
  
  const zoomIn = () => {
    setFitToWidth(false); // Disable fit-to-width when manually zooming
    setScale(Math.min((scale || 1.0) + 0.2, 3));
  };
  
  const zoomOut = () => {
    setFitToWidth(false); // Disable fit-to-width when manually zooming
    setScale(Math.max((scale || 1.0) - 0.2, 0.3));
  };
  
  const toggleFitToWidth = () => {
    setFitToWidth(!fitToWidth);
    if (!fitToWidth && pdfDoc) {
      // Re-calculate fit scale when enabling
      calculateFitScale(currentPage).then(fitScale => {
        setScale(fitScale);
      });
    }
  };
  
  // Show loading while PDF is loading
  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-64 bg-gray-100 dark:bg-gray-800 rounded-lg w-full">
        <div className="flex items-center">
          <Loader className="h-8 w-8 animate-spin text-blue-500" />
          <span className="ml-2 text-gray-600 dark:text-gray-300">Loading PDF...</span>
        </div>
        {loadingProgress && (
          <span className="mt-2 text-sm text-gray-500 dark:text-gray-400">{loadingProgress}</span>
        )}
      </div>
    );
  }
  
  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-64 bg-red-50 dark:bg-red-900/20 rounded-lg border border-red-200 dark:border-red-800 p-4">
        <span className="text-red-600 dark:text-red-400 text-center">{error}</span>
        <div className="mt-4 flex gap-2">
          <button 
            onClick={() => setRetryCount(c => c + 1)}
            className="px-4 py-2 bg-blue-100 text-blue-700 rounded hover:bg-blue-200"
          >
            Retry
          </button>
          {onClose && (
            <button 
              onClick={onClose}
              className="px-4 py-2 bg-red-100 text-red-700 rounded hover:bg-red-200"
            >
              Close
            </button>
          )}
        </div>
      </div>
    );
  }
  
  return (
    <div className="flex flex-col bg-gray-100 dark:bg-gray-800 rounded-lg overflow-hidden w-full h-full min-w-0">
      {/* Toolbar */}
      <div className="flex items-center justify-between px-4 py-2 bg-white dark:bg-gray-900 border-b dark:border-gray-700 flex-shrink-0">
        <div className="flex items-center gap-2">
          <button
            onClick={goToPrevPage}
            disabled={currentPage <= 1}
            className="p-1 rounded hover:bg-gray-100 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed dark:text-gray-300"
          >
            <ChevronLeft className="h-5 w-5" />
          </button>
          <span className="text-sm text-gray-600 dark:text-gray-300 flex items-center gap-1">
            Page
            <input
              type="number"
              min={1}
              max={totalPages || 1}
              value={pageInput}
              onChange={(e) => setPageInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  const val = parseInt(pageInput, 10);
                  if (!isNaN(val) && val >= 1 && val <= totalPages) {
                    setCurrentPage(val);
                  } else {
                    setPageInput(String(currentPage));
                  }
                  e.target.blur();
                }
              }}
              onBlur={() => {
                const val = parseInt(pageInput, 10);
                if (!isNaN(val) && val >= 1 && val <= totalPages) {
                  setCurrentPage(val);
                } else {
                  setPageInput(String(currentPage));
                }
              }}
              className="w-12 text-center text-sm border border-gray-300 dark:border-gray-600 rounded px-1 py-0.5 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-200 focus:outline-none focus:ring-1 focus:ring-blue-500 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
            />
            <button
              onClick={() => {
                const val = parseInt(pageInput, 10);
                if (!isNaN(val) && val >= 1 && val <= totalPages) {
                  setCurrentPage(val);
                } else {
                  setPageInput(String(currentPage));
                }
              }}
              className="p-0.5 rounded hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
              title="Go to page (Enter)"
            >
              <CornerDownLeft className="h-3.5 w-3.5" />
            </button>
            of {totalPages}
          </span>
          <button
            onClick={goToNextPage}
            disabled={currentPage >= totalPages}
            className="p-1 rounded hover:bg-gray-100 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed dark:text-gray-300"
          >
            <ChevronRight className="h-5 w-5" />
          </button>
        </div>
        
        <div className="flex items-center gap-2">
          <button
            onClick={zoomOut}
            className="p-1 rounded hover:bg-gray-100 dark:hover:bg-gray-700 dark:text-gray-300"
            title="Zoom out"
          >
            <ZoomOut className="h-5 w-5" />
          </button>
          <span className="text-sm text-gray-600 dark:text-gray-300 min-w-[45px] text-center">
            {scale !== null ? `${Math.round(scale * 100)}%` : '...'}
          </span>
          <button
            onClick={zoomIn}
            className="p-1 rounded hover:bg-gray-100 dark:hover:bg-gray-700 dark:text-gray-300"
            title="Zoom in"
          >
            <ZoomIn className="h-5 w-5" />
          </button>
          <button
            onClick={toggleFitToWidth}
            className={`p-1 rounded hover:bg-gray-100 dark:hover:bg-gray-700 ${fitToWidth ? 'bg-blue-100 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400' : 'dark:text-gray-300'}`}
            title={fitToWidth ? "Fit to width (enabled)" : "Fit to width"}
          >
            <Maximize2 className="h-5 w-5" />
          </button>
          {onClose && (
            <button
              onClick={onClose}
              className="ml-2 p-1 rounded hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400"
              title="Close"
            >
              <X className="h-5 w-5" />
            </button>
          )}
        </div>
      </div>
      
      {/* PDF Canvas Container - use min-w-0 to prevent flex expansion */}
      <div 
        ref={containerRef}
        className="flex-1 overflow-auto p-4 min-w-0"
        style={{ backgroundColor: '#525659' }}
      >
        {scale === null ? (
          <div className="flex items-center justify-center h-64">
            <Loader className="h-8 w-8 animate-spin text-blue-400" />
            <span className="ml-2 text-gray-300 dark:text-gray-400">Calculating fit...</span>
          </div>
        ) : (
          <div className="flex justify-center">
            <div className="relative inline-block bg-white shadow-lg">
              <canvas ref={canvasRef} />
              <canvas 
                ref={overlayCanvasRef} 
                className="absolute top-0 left-0 pointer-events-none"
              />
              {/* Hover tooltip overlays for highlighted fields */}
              {highlightRegions.map((region, idx) => (
                <div
                  key={idx}
                  className="absolute group cursor-pointer"
                  style={{
                    left: region.left,
                    top: region.top,
                    width: region.width,
                    height: region.height,
                  }}
                >
                  <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-1 px-2 py-1 bg-gray-900 text-white text-xs rounded shadow-lg whitespace-nowrap max-w-xs truncate opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50">
                    {region.label}
                    <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-900" />
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
      
      {/* Highlighted field info */}
      {highlightedField && (
        <div className="px-4 py-2 bg-blue-50 dark:bg-blue-900/30 border-t border-blue-200 dark:border-blue-800">
          <p className="text-sm text-blue-700 dark:text-blue-300">
            <strong>Highlighted:</strong> {highlightedField.field_name}
            {highlightedField.page_number && ` (Page ${highlightedField.page_number})`}
            {highlightedField.extracted_value && (
              <span className="ml-2 text-gray-600">= "{highlightedField.extracted_value}"</span>
            )}
          </p>
        </div>
      )}
    </div>
  );
}

export default PDFViewer;
