import axios from 'axios'

const API_BASE_URL = import.meta.env.VITE_API_URL || '/api'

// Create axios instance
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
})

// Token storage
let accessToken = null
let tokenExpiresAt = 0  // epoch ms — parsed from the JWT 'exp' claim

// Token refresh callback — set by AuthContext so the interceptor can silently
// acquire a new token from MSAL without dispatching session-expired.
let tokenRefreshCallback = null

export const setAccessToken = (token) => {
  accessToken = token
  if (token) {
    try {
      const payload = JSON.parse(atob(token.split('.')[1]))
      tokenExpiresAt = (payload.exp || 0) * 1000
    } catch {
      tokenExpiresAt = 0
    }
  } else {
    tokenExpiresAt = 0
  }
}

export const setTokenRefreshCallback = (cb) => {
  tokenRefreshCallback = cb
}

// Guard against multiple concurrent refresh attempts
let isRefreshing = false
let refreshSubscribers = []

const onTokenRefreshed = (newToken) => {
  refreshSubscribers.forEach(cb => cb(newToken))
  refreshSubscribers = []
}

const addRefreshSubscriber = (cb) => {
  refreshSubscribers.push(cb)
}

// Proactively refresh the token before it expires so API calls never go
// out with a stale token.  MSAL's acquireTokenSilent returns from cache
// instantly when the token is still valid — no extra network call in the
// common case.  We refresh 5 minutes before expiry.
const TOKEN_REFRESH_BUFFER_MS = 5 * 60 * 1000

api.interceptors.request.use(
  async (config) => {
    if (
      tokenRefreshCallback &&
      tokenExpiresAt > 0 &&
      Date.now() >= tokenExpiresAt - TOKEN_REFRESH_BUFFER_MS
    ) {
      try {
        const freshToken = await tokenRefreshCallback()
        if (freshToken) {
          setAccessToken(freshToken)
        }
      } catch (err) {
        console.warn('Proactive token refresh failed:', err)
      }
    }

    if (accessToken) {
      config.headers.Authorization = `Bearer ${accessToken}`
    }
    return config
  },
  (error) => {
    return Promise.reject(error)
  }
)

// Response interceptor — on 401, attempt a silent MSAL token refresh once
// before giving up and dispatching session-expired.
api.interceptors.response.use(
  (response) => response,
  async (error) => {
    const originalRequest = error.config

    if (error.response?.status === 401 && !originalRequest._retry) {
      // First 401 for this request — try to silently refresh the token
      if (tokenRefreshCallback) {
        if (isRefreshing) {
          // Another request is already refreshing — wait for it
          return new Promise((resolve) => {
            addRefreshSubscriber((newToken) => {
              originalRequest.headers.Authorization = `Bearer ${newToken}`
              originalRequest._retry = true
              resolve(api(originalRequest))
            })
          })
        }

        isRefreshing = true
        try {
          const newToken = await tokenRefreshCallback()
          if (newToken) {
            accessToken = newToken
            isRefreshing = false
            onTokenRefreshed(newToken)
            // Retry the original request with the fresh token
            originalRequest.headers.Authorization = `Bearer ${newToken}`
            originalRequest._retry = true
            return api(originalRequest)
          }
        } catch (refreshError) {
          console.error('Token refresh failed:', refreshError)
        } finally {
          isRefreshing = false
        }
      }

      // Refresh failed or no callback — truly expired, dispatch session-expired
      console.error('Unauthorized request — token refresh failed, session expired')
      window.dispatchEvent(new CustomEvent('session-expired', {
        detail: { message: 'Your session has expired. Please sign in again.' }
      }))
    }
    if (error.response?.status === 403 && error.response?.data?.error === 'Subscription inactive') {
      // Subscription is suspended/cancelled — dispatch custom event for UI to handle
      window.dispatchEvent(new CustomEvent('subscription-inactive', {
        detail: {
          status: error.response.data.subscription_status,
          message: error.response.data.message,
        }
      }))
    }
    return Promise.reject(error)
  }
)

// =====================
// Requests API
// =====================

export const requestsApi = {
  list: (params = {}) => api.get('/requests', { params }),
  get: (id) => api.get(`/requests/${id}`),
  create: (data) => api.post('/requests', data),
  update: (id, data) => api.put(`/requests/${id}`, data),
  updateStatus: (id, status) => api.put(`/requests/${id}/status`, { status }),
  delete: (id) => api.delete(`/requests/${id}`),
  
  // Documents
  getDocuments: (id) => api.get(`/requests/${id}/documents`),
  addDocument: (id, documentId, role = 'primary') => 
    api.post(`/requests/${id}/documents`, { document_id: documentId, role }),
  removeDocument: (id, documentId) => 
    api.delete(`/requests/${id}/documents/${documentId}`),
  
  // Versions and Fields
  getVersions: (id) => api.get(`/requests/${id}/versions`),
  createVersion: (id, data) => api.post(`/requests/${id}/versions`, data),
  getFields: (id) => api.get(`/requests/${id}/fields`),
  updateFields: (id, fields, reason = null) => 
    api.put(`/requests/${id}/fields`, { fields, reason }),
  
  // Field Alternatives
  getFieldAlternatives: (requestId, fieldName, versionId = null) => {
    const params = versionId ? { version_id: versionId } : {}
    return api.get(`/requests/${requestId}/fields/${encodeURIComponent(fieldName)}/alternatives`, { params })
  },
  setFieldActive: (requestId, fieldId) => 
    api.post(`/requests/${requestId}/fields/${fieldId}/set-active`),
  
  // Actions
  analyze: (id) => api.post(`/requests/${id}/analyze`),
  normalise: (id, fieldIds = null) => 
    api.post(`/requests/${id}/normalise`, fieldIds ? { field_ids: fieldIds } : {}),
  approve: (id) => api.post(`/requests/${id}/approve`),
  cancel: (id, reason) => api.post(`/requests/${id}/cancel`, { reason }),
  
  // Upload document to request
  uploadDocument: (id, file) => {
    const formData = new FormData()
    formData.append('file', file)
    return api.post(`/requests/${id}/upload`, formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
    })
  },

  // Audit Logs
  getAuditLogs: (id, params = {}) => api.get(`/requests/${id}/audit-logs`, { params }),
  getFieldAuditLogs: (requestId, fieldId, params = {}) => 
    api.get(`/requests/${requestId}/fields/${fieldId}/audit-logs`, { params }),
  getFieldsAuditSummary: (requestId) =>
    api.get(`/requests/${requestId}/fields-audit-summary`),

  // Cost Details
  getCostDetails: (id) => api.get(`/requests/${id}/cost-details`),
}

