// =====================
// Documents API
// =====================

export const documentsApi = {
  list: (params = {}) => api.get('/documents', { params }),
  get: (id) => api.get(`/documents/${id}`),
  upload: (file, source = 'direct_upload', requestId = null) => {
    const formData = new FormData()
    formData.append('file', file)
    formData.append('source', source)
    if (requestId) {
      formData.append('request_id', requestId)
    }
    return api.post('/documents/upload', formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
    })
  },
  download: (id) => api.get(`/documents/${id}/download`, { responseType: 'blob' }),
  getSasUrl: (id, expiryHours = 24) => 
    api.get(`/documents/${id}/sas-url`, { params: { expiry_hours: expiryHours } }),
  // Get PDF via backend proxy - uses fetch with auth token to avoid CORS and axios binary issues
  // Falls back to /download endpoint if /pdf endpoint not available
  getPdfUrl: (id) => `${API_BASE_URL}/documents/${id}/pdf`,
  getPdfBlob: async (id) => {
    // Use native fetch for binary data to avoid axios issues
    const token = accessToken
    
    // Try the /pdf endpoint first, then fall back to /download?inline=true
    const endpoints = [
      `${API_BASE_URL}/documents/${id}/pdf`,
      `${API_BASE_URL}/documents/${id}/download?inline=true`
    ]
    
    // Retry config for 503 (backend cold-start / restart)
    const MAX_RETRIES = 3
    const RETRY_DELAY_MS = 2000 // 2s, 4s, 8s backoff
    
    let lastError = null
    for (const url of endpoints) {
      for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
          // Use AbortController for timeout (120s for large PDFs)
          const controller = new AbortController()
          const timeoutId = setTimeout(() => controller.abort(), 120000)
          
          const response = await fetch(url, {
            method: 'GET',
            headers: token ? { 'Authorization': `Bearer ${token}` } : {},
            signal: controller.signal,
          })
          
          clearTimeout(timeoutId)
          
          if (response.ok) {
            const arrayBuffer = await response.arrayBuffer()
            return { data: arrayBuffer }
          }
          
          // Retry on 503 Service Unavailable (backend cold-starting)
          if (response.status === 503 && attempt < MAX_RETRIES) {
            const delay = RETRY_DELAY_MS * Math.pow(2, attempt)
            console.warn(`getPdfBlob: 503 on ${url}, retrying in ${delay}ms (attempt ${attempt + 1}/${MAX_RETRIES})`)
            await new Promise(r => setTimeout(r, delay))
            continue
          }
          
          // If not OK, store error and try next endpoint
          const errorText = await response.text()
          lastError = new Error(`HTTP ${response.status}: ${errorText}`)
          break // non-retryable status, move to next endpoint
        } catch (err) {
          if (err.name === 'AbortError') {
            lastError = new Error('PDF download timed out. The file may be too large.')
            break
          }
          // Network errors (including CORS blocks from 503) are retryable
          if (attempt < MAX_RETRIES) {
            const delay = RETRY_DELAY_MS * Math.pow(2, attempt)
            console.warn(`getPdfBlob: network error on ${url}, retrying in ${delay}ms (attempt ${attempt + 1}/${MAX_RETRIES})`, err.message)
            await new Promise(r => setTimeout(r, delay))
            continue
          }
          lastError = err
        }
      }
    }
    
    throw lastError || new Error('Failed to fetch PDF from all endpoints')
  },
  getAnalysis: (id) => api.get(`/documents/${id}/analysis`),
  analyze: (id) => api.post(`/documents/${id}/analyze`),
  getRequests: (id) => api.get(`/documents/${id}/requests`),
  update: (id, data) => api.put(`/documents/${id}`, data),
  delete: (id) => api.delete(`/documents/${id}`),
  reprocess: (id) => api.post(`/documents/${id}/reprocess`),
}

