// =====================
// Templates API
// =====================

export const templatesApi = {
  list: (params = {}) => api.get('/templates', { params }),
  get: (id) => api.get(`/templates/${id}`),
  create: (data) => api.post('/templates', data),
  update: (id, data) => api.put(`/templates/${id}`, data),
  delete: (id) => api.delete(`/templates/${id}`),
  getCategories: () => api.get('/templates/categories'),
  buildAnalyzer: (templateId, data = {}) => api.post(`/templates/${templateId}/build-analyzer`, data),
  
  // AI-powered field suggestion (multi-file)
  suggestFields: (files, prompt = '') => {
    const formData = new FormData()
    const fileList = Array.isArray(files) ? files : [files]
    fileList.forEach(f => formData.append('files', f))
    if (prompt) formData.append('prompt', prompt)
    return api.post('/templates/suggest-fields', formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
      timeout: 300000, // 5 min — prebuilt-layout CU + two GPT passes
    })
  },

  // Template Fields
  getFields: (templateId, params = {}) => 
    api.get(`/templates/${templateId}/fields`, { params }),
  addField: (templateId, data) => 
    api.post(`/templates/${templateId}/fields`, data),
  updateField: (templateId, fieldId, data) => 
    api.put(`/templates/${templateId}/fields/${fieldId}`, data),
  deleteField: (templateId, fieldId) => 
    api.delete(`/templates/${templateId}/fields/${fieldId}`),
  deleteAllFields: (templateId) =>
    api.delete(`/templates/${templateId}/fields`),
  importFields: (templateId, data) =>
    api.post(`/templates/${templateId}/import-fields`, data),
  restoreDefaultAnalyzer: () =>
    api.post('/templates/restore-default-analyzer'),
}

