import React, { useState, useEffect, useCallback, useRef } from 'react'
import { Link, useSearchParams, useNavigate } from 'react-router-dom'
import { requestsApi } from '../services/api'
import { formatDate, formatTime, parseUTC } from '../utils/dateUtils'
import IngestEmailModal from '../components/IngestEmailModal'
import {
  Plus,
  Filter,
  ChevronLeft,
  ChevronRight,
  FileText,
  RefreshCw,
  AlertCircle,
  Clock,
  Eye,
  Edit3,
  Check,
  ChevronDown,
  X
} from 'lucide-react'

const STATUS_OPTIONS = [
  { value: 'pending', label: 'Pending', dot: 'bg-yellow-500' },
  { value: 'processing', label: 'Processing', dot: 'bg-blue-500' },
  { value: 'extracted', label: 'Extracted', dot: 'bg-indigo-500' },
  { value: 'reviewing', label: 'Reviewing', dot: 'bg-orange-500' },
  { value: 'approved', label: 'Approved', dot: 'bg-green-500' },
  { value: 'rejected', label: 'Rejected', dot: 'bg-red-500' },
  { value: 'failed', label: 'Failed', dot: 'bg-red-500' },
  { value: 'completed', label: 'Completed', dot: 'bg-green-500' },
  { value: 'cancelled', label: 'Cancelled', dot: 'bg-gray-500' },
]

// Reusable multi-select dropdown component
function MultiSelectDropdown({ options, selected, onChange, label, placeholder = 'Select...' }) {
  const [open, setOpen] = useState(false)
  const ref = useRef(null)

  useEffect(() => {
    const handleClick = (e) => {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false)
    }
    document.addEventListener('mousedown', handleClick)
    return () => document.removeEventListener('mousedown', handleClick)
  }, [])

  const toggleOption = (value) => {
    if (selected.includes(value)) {
      onChange(selected.filter(v => v !== value))
    } else {
      onChange([...selected, value])
    }
  }

  const clearAll = (e) => {
    e.stopPropagation()
    onChange([])
  }

  const selectedLabels = options.filter(o => selected.includes(o.value)).map(o => o.label)

  return (
    <div ref={ref} className="relative">
      {label && <label className="block text-sm text-gray-500 dark:text-gray-400 mb-1.5">{label}</label>}
      <button
        type="button"
        onClick={() => setOpen(!open)}
        className="flex items-center justify-between gap-2 px-3 py-2 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-navy-500/20 focus:border-navy-500 min-w-[180px] dark:bg-gray-800 dark:text-gray-200 bg-white text-left w-full"
      >
        <span className="truncate flex-1">
          {selected.length === 0
            ? placeholder
            : selected.length <= 2
              ? selectedLabels.join(', ')
              : `${selected.length} selected`}
        </span>
        <span className="flex items-center gap-1 flex-shrink-0">
          {selected.length > 0 && (
            <span
              onClick={clearAll}
              className="p-0.5 hover:bg-gray-200 dark:hover:bg-gray-600 rounded transition-colors cursor-pointer"
            >
              <X className="h-3 w-3 text-gray-400" />
            </span>
          )}
          <ChevronDown className={`h-3.5 w-3.5 text-gray-400 transition-transform ${open ? 'rotate-180' : ''}`} />
        </span>
      </button>

      {open && (
        <div className="absolute z-50 mt-1 w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg shadow-lg max-h-60 overflow-y-auto">
          {/* Select All / Clear All */}
          <div className="px-3 py-2 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between">
            <button
              type="button"
              onClick={() => onChange(options.map(o => o.value))}
              className="text-xs text-navy-600 dark:text-navy-400 hover:underline font-medium"
            >
              Select All
            </button>
            <button
              type="button"
              onClick={() => onChange([])}
              className="text-xs text-gray-500 dark:text-gray-400 hover:underline"
            >
              Clear All
            </button>
          </div>
          {options.map((option) => {
            const isSelected = selected.includes(option.value)
            return (
              <button
                key={option.value}
                type="button"
                onClick={() => toggleOption(option.value)}
                className="flex items-center gap-2.5 w-full px-3 py-2 text-sm text-left hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
              >
                <span className={`flex items-center justify-center w-4 h-4 rounded border transition-colors ${
                  isSelected
                    ? 'bg-navy-800 border-navy-800 text-white'
                    : 'border-gray-300 dark:border-gray-600'
                }`}>
                  {isSelected && <Check className="h-3 w-3" />}
                </span>
                {option.dot && <span className={`w-2 h-2 rounded-full ${option.dot}`} />}
                <span className="text-gray-700 dark:text-gray-200">{option.label}</span>
              </button>
            )
          })}
        </div>
      )}
    </div>
  )
}

function Requests() {
  const [searchParams, setSearchParams] = useSearchParams()
  const [requests, setRequests] = useState([])
  const [totalResults, setTotalResults] = useState(0)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [showIngestModal, setShowIngestModal] = useState(false)

  // "Applied" filters — these are what the API is currently filtered by
  const [appliedFilters, setAppliedFilters] = useState({
    search: '',
    statuses: [],
    issuer: '',
    dateFrom: '',
    dateTo: '',
  })

  // "Draft" filters — local input state, committed on Apply
  const [draftSearch, setDraftSearch] = useState('')
  const [draftStatuses, setDraftStatuses] = useState([])
  const [draftIssuer, setDraftIssuer] = useState('')
  const [draftDateFrom, setDraftDateFrom] = useState('')
  const [draftDateTo, setDraftDateTo] = useState('')

  // Pagination
  const [currentPage, setCurrentPage] = useState(parseInt(searchParams.get('page') || '1'))
  const [perPage, setPerPage] = useState(10)

  // Sorting
  const [sortField, setSortField] = useState(null)
  const [sortDirection, setSortDirection] = useState('asc')

  const handleSort = (field) => {
    if (sortField === field) {
      setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc')
    } else {
      setSortField(field)
      setSortDirection('asc')
    }
  }

  // Track whether drafts differ from applied
  const hasUnappliedChanges =
    draftSearch !== appliedFilters.search ||
    JSON.stringify(draftStatuses) !== JSON.stringify(appliedFilters.statuses) ||
    draftIssuer !== appliedFilters.issuer ||
    draftDateFrom !== appliedFilters.dateFrom ||
    draftDateTo !== appliedFilters.dateTo

  const hasActiveFilters =
    appliedFilters.search ||
    appliedFilters.statuses.length > 0 ||
    appliedFilters.issuer ||
    appliedFilters.dateFrom ||
    appliedFilters.dateTo

  const fetchRequests = useCallback(async (filters, page, pageSize) => {
    try {
      setLoading(true)
      const res = await requestsApi.list({
        page,
        per_page: pageSize,
        status: filters.statuses.length > 0 ? filters.statuses.join(',') : undefined,
        search: filters.search || undefined,
        issuer: filters.issuer || undefined,
        date_from: filters.dateFrom || undefined,
        date_to: filters.dateTo || undefined,
      })
      setRequests(res.data.requests || [])
      setTotalResults(res.data.pagination?.total || 0)
      setError(null)
    } catch (err) {
      console.error('Error fetching requests:', err)
      setError('Failed to load requests')
    } finally {
      setLoading(false)
    }
  }, [])

  // Initial load + when page/perPage changes
  useEffect(() => {
    fetchRequests(appliedFilters, currentPage, perPage)
  }, [currentPage, perPage])

  // Sync page to URL
  useEffect(() => {
    setSearchParams({ page: currentPage.toString() }, { replace: true })
  }, [currentPage])

  const handleApplyFilters = () => {
    const newFilters = {
      search: draftSearch,
      statuses: [...draftStatuses],
      issuer: draftIssuer,
      dateFrom: draftDateFrom,
      dateTo: draftDateTo,
    }
    setAppliedFilters(newFilters)
    setCurrentPage(1)
    fetchRequests(newFilters, 1, perPage)
  }

  const handleResetFilters = () => {
    setDraftSearch('')
    setDraftStatuses([])
    setDraftIssuer('')
    setDraftDateFrom('')
    setDraftDateTo('')
    const emptyFilters = { search: '', statuses: [], issuer: '', dateFrom: '', dateTo: '' }
    setAppliedFilters(emptyFilters)
    setCurrentPage(1)
    fetchRequests(emptyFilters, 1, perPage)
  }

  const totalPages = Math.ceil(totalResults / perPage)

  if (loading && requests.length === 0) {
    return (
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <div className="skeleton h-7 w-32 mb-2"></div>
            <div className="skeleton h-4 w-64"></div>
          </div>
          <div className="skeleton h-10 w-32 rounded-lg"></div>
        </div>
        <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden">
          <div className="px-5 py-4 border-b border-gray-100 dark:border-gray-800">
            <div className="skeleton h-5 w-28 mb-2"></div>
            <div className="skeleton h-4 w-40"></div>
          </div>
          <div className="divide-y divide-gray-100 dark:divide-gray-800">
            {[...Array(5)].map((_, i) => (
              <div key={i} className="px-4 py-3 flex items-center gap-4">
                <div className="skeleton w-10 h-10 rounded-lg"></div>
                <div className="flex-1 space-y-2">
                  <div className="skeleton h-4 w-48"></div>
                  <div className="skeleton h-3 w-32"></div>
                </div>
                <div className="skeleton h-4 w-24"></div>
                <div className="skeleton h-6 w-20 rounded-full"></div>
                <div className="skeleton h-4 w-16"></div>
                <div className="skeleton w-8 h-8 rounded-full"></div>
              </div>
            ))}
          </div>
        </div>
      </div>
    )
  }

  if (error && requests.length === 0) {
    return (
      <div className="max-w-md mx-auto mt-12">
        <div className="bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-800 rounded-xl p-6">
          <div className="flex items-start gap-4">
            <div className="p-3 bg-red-100 dark:bg-red-900/40 rounded-full">
              <AlertCircle className="h-6 w-6 text-red-600 dark:text-red-400" />
            </div>
            <div className="flex-1">
              <h3 className="font-semibold text-red-800 dark:text-red-300">Failed to load requests</h3>
              <p className="text-sm text-red-600 dark:text-red-400 mt-1">{error}</p>
              <button
                onClick={() => fetchRequests(appliedFilters, currentPage, perPage)}
                disabled={loading}
                className="mt-4 inline-flex items-center gap-2 px-4 py-2 bg-red-600 text-white text-sm font-medium rounded-lg hover:bg-red-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
                Try again
              </button>
            </div>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-semibold text-gray-900 dark:text-gray-100">Requests</h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1">Manage and track all document processing requests</p>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setShowIngestModal(true)} className="inline-flex items-center gap-2 px-4 py-2.5 bg-navy-800 text-white text-sm font-medium rounded-lg hover:bg-navy-900 transition-colors">
            <Plus className="h-4 w-4" />
            New Request
          </button>
        </div>
      </div>

      {/* Requests Table with Filters */}
      <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden">
        {/* Filter Header */}
        <div className="px-5 py-4 border-b border-gray-100 dark:border-gray-800">
          <div className="mb-4">
            <h2 className="text-base font-semibold text-gray-900 dark:text-gray-100">All Requests</h2>
            <p className="text-sm text-gray-500 dark:text-gray-400">{totalResults} request{totalResults !== 1 ? 's' : ''} found</p>
          </div>

          {/* Filters Row */}
          <div className="flex flex-wrap items-end gap-4">
            <div>
              <label className="block text-sm text-gray-500 dark:text-gray-400 mb-1.5">Search</label>
              <input
                type="text"
                value={draftSearch}
                onChange={(e) => setDraftSearch(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleApplyFilters()}
                placeholder="Title, description, documents..."
                className="px-3 py-2 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-navy-500/20 focus:border-navy-500 min-w-[220px] dark:bg-gray-800 dark:text-gray-200"
              />
            </div>
            <div>
              <label className="block text-sm text-gray-500 dark:text-gray-400 mb-1.5">Date Range</label>
              <div className="flex items-center gap-2">
                <input
                  type="date"
                  value={draftDateFrom}
                  onChange={(e) => setDraftDateFrom(e.target.value)}
                  className="px-3 py-2 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-navy-500/20 focus:border-navy-500 dark:bg-gray-800 dark:text-gray-200"
                />
                <input
                  type="date"
                  value={draftDateTo}
                  onChange={(e) => setDraftDateTo(e.target.value)}
                  className="px-3 py-2 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-navy-500/20 focus:border-navy-500 dark:bg-gray-800 dark:text-gray-200"
                />
              </div>
            </div>
            <MultiSelectDropdown
              label="Status"
              options={STATUS_OPTIONS}
              selected={draftStatuses}
              onChange={setDraftStatuses}
              placeholder="All Status"
            />
            <div>
              <label className="block text-sm text-gray-500 dark:text-gray-400 mb-1.5">Issuer</label>
              <input
                type="text"
                value={draftIssuer}
                onChange={(e) => setDraftIssuer(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleApplyFilters()}
                placeholder="Search issuer..."
                className="px-3 py-2 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-navy-500/20 focus:border-navy-500 min-w-[200px] dark:bg-gray-800 dark:text-gray-200"
              />
            </div>
            <button
              onClick={handleApplyFilters}
              disabled={loading}
              className={`inline-flex items-center gap-2 px-6 py-2 text-sm font-medium rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed ${
                hasUnappliedChanges
                  ? 'bg-navy-800 text-white hover:bg-navy-900 ring-2 ring-navy-400 ring-offset-1'
                  : 'bg-navy-800 text-white hover:bg-navy-900'
              }`}
            >
              <Filter className="h-4 w-4" />
              Apply
              {hasUnappliedChanges && <span className="w-1.5 h-1.5 rounded-full bg-white animate-pulse" />}
            </button>
            {hasActiveFilters && (
              <button
                onClick={handleResetFilters}
                disabled={loading}
                className="inline-flex items-center gap-1.5 px-3 py-2 border border-gray-200 dark:border-gray-700 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors text-sm text-gray-500 dark:text-gray-400 disabled:opacity-50 disabled:cursor-not-allowed"
                title="Reset all filters"
              >
                <RefreshCw className="h-3.5 w-3.5" />
                Reset
              </button>
            )}
          </div>

          {/* Active filter tags */}
          {hasActiveFilters && (
            <div className="flex flex-wrap items-center gap-2 mt-3 pt-3 border-t border-gray-100 dark:border-gray-800">
              <span className="text-xs text-gray-500 dark:text-gray-400">Active filters:</span>
              {appliedFilters.search && (
                <span className="inline-flex items-center gap-1 px-2 py-0.5 bg-navy-50 dark:bg-navy-900/20 text-navy-700 dark:text-navy-300 rounded text-xs">
                  Search: "{appliedFilters.search}"
                </span>
              )}
              {appliedFilters.statuses.length > 0 && (
                <span className="inline-flex items-center gap-1 px-2 py-0.5 bg-navy-50 dark:bg-navy-900/20 text-navy-700 dark:text-navy-300 rounded text-xs">
                  Status: {appliedFilters.statuses.length <= 3
                    ? appliedFilters.statuses.map(s => s.charAt(0).toUpperCase() + s.slice(1)).join(', ')
                    : `${appliedFilters.statuses.length} selected`}
                </span>
              )}
              {appliedFilters.issuer && (
                <span className="inline-flex items-center gap-1 px-2 py-0.5 bg-navy-50 dark:bg-navy-900/20 text-navy-700 dark:text-navy-300 rounded text-xs">
                  Issuer: "{appliedFilters.issuer}"
                </span>
              )}
              {(appliedFilters.dateFrom || appliedFilters.dateTo) && (
                <span className="inline-flex items-center gap-1 px-2 py-0.5 bg-navy-50 dark:bg-navy-900/20 text-navy-700 dark:text-navy-300 rounded text-xs">
                  Date: {appliedFilters.dateFrom || '...'} → {appliedFilters.dateTo || '...'}
                </span>
              )}
            </div>
          )}
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="bg-gray-50 dark:bg-gray-800/50 border-b border-gray-100 dark:border-gray-800 sticky top-0 z-10">
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                  <button onClick={() => handleSort('name')} className="flex items-center gap-1 hover:text-gray-700 dark:hover:text-gray-200 transition-colors">
                    Request Name
                    <SortIcon active={sortField === 'name'} direction={sortField === 'name' ? sortDirection : null} />
                  </button>
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                  <button onClick={() => handleSort('issuer')} className="flex items-center gap-1 hover:text-gray-700 dark:hover:text-gray-200 transition-colors">
                    Issuer
                    <SortIcon active={sortField === 'issuer'} direction={sortField === 'issuer' ? sortDirection : null} />
                  </button>
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                  <button onClick={() => handleSort('created')} className="flex items-center gap-1 hover:text-gray-700 dark:hover:text-gray-200 transition-colors">
                    Created Date
                    <SortIcon active={sortField === 'created'} direction={sortField === 'created' ? sortDirection : null} />
                  </button>
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                  <button onClick={() => handleSort('status')} className="flex items-center gap-1 hover:text-gray-700 dark:hover:text-gray-200 transition-colors">
                    Status
                    <SortIcon active={sortField === 'status'} direction={sortField === 'status' ? sortDirection : null} />
                  </button>
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                  <button onClick={() => handleSort('confidence')} className="flex items-center gap-1 hover:text-gray-700 dark:hover:text-gray-200 transition-colors">
                    AI Confidence
                    <SortIcon active={sortField === 'confidence'} direction={sortField === 'confidence' ? sortDirection : null} />
                  </button>
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                  Created By
                </th>
                <th className="px-4 py-3"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {requests.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-4 py-12 text-center">
                    <div className="flex flex-col items-center">
                      <FileText className="h-12 w-12 text-gray-300 dark:text-gray-600 mb-3" />
                      <p className="text-gray-500 dark:text-gray-400 font-medium">No requests found</p>
                      <p className="text-sm text-gray-400 dark:text-gray-500 mt-1">Try adjusting your filters or create a new request</p>
                    </div>
                  </td>
                </tr>
              ) : (
                [...requests].sort((a, b) => {
                  if (!sortField) return 0
                  let aVal, bVal
                  switch (sortField) {
                    case 'name':
                      aVal = (a.title || a.name || '').toLowerCase()
                      bVal = (b.title || b.name || '').toLowerCase()
                      break
                    case 'issuer':
                      aVal = (a.issuer || a.email?.sender || a.email_sender || '').toLowerCase()
                      bVal = (b.issuer || b.email?.sender || b.email_sender || '').toLowerCase()
                      break
                    case 'created':
                      aVal = (parseUTC(a.created_at) || new Date(0)).getTime()
                      bVal = (parseUTC(b.created_at) || new Date(0)).getTime()
                      break
                    case 'status':
                      aVal = (a.status || '').toLowerCase()
                      bVal = (b.status || '').toLowerCase()
                      break
                    case 'confidence':
                      aVal = a.ai_confidence || 0
                      bVal = b.ai_confidence || 0
                      break
                    default:
                      return 0
                  }
                  if (aVal < bVal) return sortDirection === 'asc' ? -1 : 1
                  if (aVal > bVal) return sortDirection === 'asc' ? 1 : -1
                  return 0
                }).map((req, index) => (
                  <RequestRow key={req.id} request={req} index={index} />
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        <div className="px-5 py-4 border-t border-gray-100 dark:border-gray-800 flex items-center justify-between">
          <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400">
            <span>
              {totalResults === 0
                ? 'No results'
                : `Showing ${(currentPage - 1) * perPage + 1}\u2013${Math.min(currentPage * perPage, totalResults)} of ${totalResults} result${totalResults !== 1 ? 's' : ''}`}
            </span>
            <span className="border-l border-gray-200 dark:border-gray-700 h-4" />
            <span className="flex items-center gap-1.5">
              Rows per page
              <select
                value={perPage}
                onChange={(e) => {
                  setPerPage(Number(e.target.value))
                  setCurrentPage(1)
                }}
                className="px-2 py-1 border border-gray-200 dark:border-gray-700 rounded text-sm dark:bg-gray-800 dark:text-gray-200"
              >
                <option value={10}>10</option>
                <option value={25}>25</option>
                <option value={50}>50</option>
              </select>
            </span>
          </div>
          <div className="flex items-center gap-1">
            <button
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
              className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <ChevronLeft className="h-4 w-4" />
              Previous
            </button>
            {generatePageNumbers(currentPage, totalPages).map((pg, i) => (
              <React.Fragment key={i}>
                {pg === '...' ? (
                  <span className="px-2 text-gray-400 dark:text-gray-500">...</span>
                ) : (
                  <button
                    onClick={() => setCurrentPage(pg)}
                    className={`w-8 h-8 rounded text-sm font-medium ${
                      currentPage === pg
                        ? 'bg-navy-800 text-white'
                        : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800'
                    }`}
                  >
                    {pg}
                  </button>
                )}
              </React.Fragment>
            ))}
            <button
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages || totalPages === 0}
              className="flex items-center gap-1 px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Next
              <ChevronRight className="h-4 w-4" />
            </button>
          </div>
        </div>
      </div>

      {/* Ingest Email Modal */}
      {showIngestModal && (
        <IngestEmailModal
          onClose={() => setShowIngestModal(false)}
          onSuccess={() => {
            setShowIngestModal(false)
            fetchRequests(appliedFilters, currentPage, perPage)
          }}
        />
      )}
    </div>
  )
}

// Sort Icon Component
function SortIcon({ active, direction }) {
  return (
    <svg className={`h-3 w-3 transition-colors ${active ? 'text-navy-600 dark:text-navy-400' : 'text-gray-400'}`} viewBox="0 0 10 14" fill="currentColor">
      <path d="M5 0L9.33 5H0.67L5 0Z" className={active && direction === 'asc' ? 'opacity-100' : 'opacity-30'} />
      <path d="M5 14L0.67 9H9.33L5 14Z" className={active && direction === 'desc' ? 'opacity-100' : 'opacity-30'} />
    </svg>
  )
}

// Request Row Component — matches Dashboard InstrumentRow style
function RequestRow({ request, index }) {
  const navigate = useNavigate()
  // AI Confidence - same formula as Dashboard InstrumentRow
  const confidence = request.ai_confidence != null ? Math.min(100, Math.max(0, request.ai_confidence)) : 0

  // Get created by info
  const createdByName = request.created_by_name || 'Unknown'
  const createdByInitials = createdByName.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || 'UN'

  // Get issuer
  const issuer = request.issuer || request.email?.sender || request.email_sender || 'Unknown Issuer'

  // Get documents info
  const documents = request.documents || []
  const documentCount = documents.length || request.document_count || 0
  const documentNames = documents.length > 0
    ? documents.map(d => d.filename || d.name || 'Unknown').join('\n')
    : (request.document_names || []).join('\n')

  // Truncate description
  const description = request.description || ''
  const maxDescLength = 50
  const truncatedDesc = description.length > maxDescLength
    ? description.substring(0, maxDescLength) + '...'
    : description
  const showTooltip = description.length > maxDescLength

  const getStatusBadge = (status) => {
    const config = {
      pending: { bg: 'bg-yellow-50 dark:bg-yellow-900/20', text: 'text-yellow-700 dark:text-yellow-300', dot: 'bg-yellow-500', label: 'Pending' },
      processing: { bg: 'bg-blue-50 dark:bg-blue-900/20', text: 'text-blue-600 dark:text-blue-300', dot: 'bg-blue-500', label: 'Processing' },
      extracted: { bg: 'bg-indigo-50 dark:bg-indigo-900/20', text: 'text-indigo-600 dark:text-indigo-300', dot: 'bg-indigo-500', label: 'Extracted' },
      reviewing: { bg: 'bg-orange-50 dark:bg-orange-900/20', text: 'text-orange-600 dark:text-orange-300', dot: 'bg-orange-500', label: 'Reviewing' },
      approved: { bg: 'bg-green-50 dark:bg-green-900/20', text: 'text-green-600 dark:text-green-300', dot: 'bg-green-500', label: 'Approved' },
      rejected: { bg: 'bg-red-50 dark:bg-red-900/20', text: 'text-red-600 dark:text-red-300', dot: 'bg-red-500', label: 'Rejected' },
      failed: { bg: 'bg-red-50 dark:bg-red-900/20', text: 'text-red-600 dark:text-red-300', dot: 'bg-red-500', label: 'Failed' },
      completed: { bg: 'bg-green-50 dark:bg-green-900/20', text: 'text-green-600 dark:text-green-300', dot: 'bg-green-500', label: 'Completed' },
      cancelled: { bg: 'bg-gray-50 dark:bg-gray-700', text: 'text-gray-600 dark:text-gray-300', dot: 'bg-gray-500', label: 'Cancelled' },
    }
    return config[status] || config.pending
  }

  const statusConfig = getStatusBadge(request.status)

  const getIconByStatus = (status) => {
    const colors = {
      pending: 'text-yellow-600 bg-yellow-50 dark:text-yellow-400 dark:bg-yellow-900/20',
      processing: 'text-blue-600 bg-blue-50 dark:text-blue-400 dark:bg-blue-900/20',
      extracted: 'text-indigo-600 bg-indigo-50 dark:text-indigo-400 dark:bg-indigo-900/20',
      reviewing: 'text-orange-600 bg-orange-50 dark:text-orange-400 dark:bg-orange-900/20',
      approved: 'text-green-600 bg-green-50 dark:text-green-400 dark:bg-green-900/20',
      rejected: 'text-red-600 bg-red-50 dark:text-red-400 dark:bg-red-900/20',
      failed: 'text-red-600 bg-red-50 dark:text-red-400 dark:bg-red-900/20',
      completed: 'text-green-600 bg-green-50 dark:text-green-400 dark:bg-green-900/20',
      cancelled: 'text-gray-600 bg-gray-50 dark:text-gray-400 dark:bg-gray-700',
    }
    return colors[status] || 'text-gray-600 bg-gray-50 dark:text-gray-400 dark:bg-gray-700'
  }

  const handleRowClick = (e) => {
    // Don't navigate if clicking a link or button
    if (e.target.closest('a') || e.target.closest('button')) return
    const mode = (request.status === 'completed' || request.status === 'cancelled') ? 'view' : 'edit'
    navigate(`/requests/${request.id}?mode=${mode}`)
  }

  return (
    <tr className="clickable-row hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors cursor-pointer" onClick={handleRowClick}>
      <td className="px-4 py-3">
        <div className="flex items-center gap-3">
          <div
            className={`w-10 h-10 rounded-lg flex items-center justify-center relative cursor-default ${getIconByStatus(request.status)}`}
            title={documentCount > 0 ? documentNames : 'No documents'}
          >
            <FileText className="h-5 w-5" />
            <span className="absolute -top-1 -right-1 bg-navy-600 text-white text-[10px] font-medium rounded-full min-w-[18px] h-[18px] flex items-center justify-center px-1">
              {documentCount}
            </span>
          </div>
          <div className="max-w-xs">
            <Link to={`/requests/${request.id}`} className="font-medium text-gray-900 dark:text-gray-100 hover:text-navy-600 dark:hover:text-navy-400">
              {request.title || request.email_subject || `Request #${String(request.id).substring(0, 8)}`}
            </Link>
            {description && (
              <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5" title={showTooltip ? description : undefined}>
                {truncatedDesc || 'No description'}
              </p>
            )}
          </div>
        </div>
      </td>
      <td className="px-4 py-3">
        <span className="text-sm text-gray-600 dark:text-gray-400">
          {issuer}
        </span>
      </td>
      <td className="px-4 py-3">
        <div>
          <p className="text-sm text-gray-900 dark:text-gray-100">{formatDate(request.created_at)}</p>
          <p className="text-xs text-gray-500 dark:text-gray-400">{formatTime(request.created_at)}</p>
        </div>
      </td>
      <td className="px-4 py-3">
        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${statusConfig.bg} ${statusConfig.text}`}>
          <span className={`w-1.5 h-1.5 rounded-full ${statusConfig.dot}`}></span>
          {statusConfig.label}
        </span>
      </td>
      <td className="px-4 py-3">
        <div className="flex items-center gap-2">
          <div className="w-16 h-1.5 bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden">
            <div className={`h-full rounded-full ${confidence >= 90 ? 'bg-green-500' : confidence >= 70 ? 'bg-yellow-500' : 'bg-red-500'}`} style={{ width: `${confidence}%` }} />
          </div>
          <span className="text-sm text-gray-600 dark:text-gray-400">{confidence}%</span>
        </div>
      </td>
      <td className="px-4 py-3">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-gray-200 dark:bg-gray-700 flex items-center justify-center text-xs font-medium text-gray-600 dark:text-gray-300">
            {createdByInitials}
          </div>
          <span className="text-sm text-gray-600 dark:text-gray-400">{createdByName}</span>
        </div>
      </td>
      <td className="px-4 py-3">
        <div className="flex items-center gap-1">
          {request.status === 'completed' || request.status === 'cancelled' ? (
            <Link
              to={`/requests/${request.id}?mode=view`}
              className="p-1.5 rounded-lg text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
              title="View request"
            >
              <Eye className="h-4 w-4" />
            </Link>
          ) : (
            <Link
              to={`/requests/${request.id}?mode=edit`}
              className="p-1.5 rounded-lg text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
              title="Edit request"
            >
              <Edit3 className="h-4 w-4" />
            </Link>
          )}
        </div>
      </td>
    </tr>
  )
}

// Utility Functions (formatDate & formatTime imported from ../utils/dateUtils)

function generatePageNumbers(current, total) {
  if (total <= 7) {
    return Array.from({ length: total }, (_, i) => i + 1)
  }
  if (current <= 3) {
    return [1, 2, 3, '...', total]
  }
  if (current >= total - 2) {
    return [1, '...', total - 2, total - 1, total]
  }
  return [1, '...', current - 1, current, current + 1, '...', total]
}

export default Requests
